TZ_MADRID = ZoneInfo("Europe/Madrid")


def today_local() -> date:
    """Fecha de hoy en Madrid."""
    return datetime.now(TZ_MADRID).date()

def get_day(param: str = "d") -> date:
    """
    Lee ?d=YYYY-MM-DD de la query y devuelve date.
    Si no llega / es inválido, devuelve 'hoy' Madrid.
    """
    raw = request.args.get(param)
    if raw:
        try:
            return datetime.strptime(raw, "%Y-%m-%d").date()
        except ValueError:
            pass
    return today_local()
# ---------- helpers ----------
def db():
    return SessionLocal()


@contextmanager
def get_db():
    """Context manager para sesiones de base de datos (SessionLocal).

    Evita duplicar try/finally de close().
    """
    session_db = db()
    try:
        yield session_db
    finally:
        try:
            session_db.close()
        except Exception:
            pass


def monday_of(d: date) -> date:
    return d - timedelta(days=d.weekday())

def ensure_week(session, week_start: date):
    session.execute(
        text("insert into weeks (week_start) values (:w) on conflict (week_start) do nothing"),
        {"w": week_start}
    )
    session.flush()

def parse_date(value: str) -> date:
    return datetime.strptime(value, "%Y-%m-%d").date()


def parse_optional_date(value: str | None):
    raw = (value or "").strip()
    if not raw:
        return None
    return parse_date(raw)


def parse_concert_sale_start_date(value: str | None, sale_type: str) -> date | None:
    raw = (value or "").strip()
    if raw:
        return parse_date(raw)
    if (sale_type or "").strip().upper() == "GRATUITO":
        return None
    raise ValueError("La fecha de salida a la venta es obligatoria salvo en conciertos gratuitos.")


def parse_timecode_to_seconds(value: str | None) -> int | None:
    """Convierte un timecode tipo "mm:ss" o "ss" a segundos.

    Acepta también "hh:mm:ss".
    """
    raw = (value or "").strip()
    if not raw:
        return None
    try:
        if ":" not in raw:
            n = int(raw)
            return n if n >= 0 else None
        parts = [p.strip() for p in raw.split(":")]
        if len(parts) == 2:
            mm = int(parts[0] or 0)
            ss = int(parts[1] or 0)
            if mm < 0 or ss < 0:
                return None
            return mm * 60 + ss
        if len(parts) == 3:
            hh = int(parts[0] or 0)
            mm = int(parts[1] or 0)
            ss = int(parts[2] or 0)
            if hh < 0 or mm < 0 or ss < 0:
                return None
            return hh * 3600 + mm * 60 + ss
    except Exception:
        return None
    return None

def to_uuid(val):
    if val is None or val == "":
        return None
    if isinstance(val, UUID):
        return val
    return _uuid.UUID(str(val))


def safe_next_or(default_url: str) -> str:
    """Devuelve el parámetro next (form/args) si parece seguro (ruta relativa),
    si no, devuelve default_url.

    Evita open-redirects (no permitimos http(s):// ni //).
    """
    nxt = (request.form.get("next") or request.args.get("next") or "").strip()
    if nxt.startswith("/") and ("://" not in nxt) and (not nxt.startswith("//")):
        return nxt
    return default_url

def admin_required(view):
    @wraps(view)
    def wrapper(*args, **kwargs):
        if not session.get("user_id"):
            nxt = request.full_path if request.query_string else request.path
            return redirect(url_for("admin_login", next=nxt))
        return view(*args, **kwargs)
    return wrapper


# ---------- Requerir login en toda la app (sin "vista general") ----------
# Antes existían rutas públicas para consulta. Ahora el acceso es por roles,
# así que forzamos inicio de sesión en cualquier pantalla salvo landing/login.
@app.before_request
def require_login():
    # Endpoints estáticos (CSS/JS/IMG)
    if request.endpoint == "static":
        return

    # Si ya hay sesión, OK
    if session.get("user_id"):
        return

    # Rutas públicas permitidas
    allowed = {"landing", "admin_login", "concert_contract_public_form", "concert_artwork_public_upload", "public_royalty_liquidation_pdf", "public_song_lyrics_view", "public_song_lyrics_pdf", "public_song_material_bundle_download", "public_song_material_download", "public_song_label_copy_view", "public_song_label_copy_pdf", "public_album_label_copy_view", "public_album_label_copy_pdf", "public_song_production_contract_download", "public_album_production_contract_download", "public_bag_expense_document_upload", "public_registros_repertoire", "public_song_master_delivery", "public_song_delivery_authors", "public_song_delivery_publishers", "public_song_delivery_create_author", "public_song_delivery_create_publisher"}
    if request.endpoint in allowed:
        return

    # Evitar errores raros en endpoints desconocidos
    if not request.endpoint:
        return

    nxt = request.full_path if request.query_string else request.path
    return redirect(url_for("admin_login", next=nxt))



