# -------------------------------
# Discográfica > Ingresos helpers
# -------------------------------

SPANISH_MONTH_ABBR = [
    "Ene", "Feb", "Mar", "Abr", "May", "Jun",
    "Jul", "Ago", "Sep", "Oct", "Nov", "Dic",
]


def _month_start(d: date) -> date:
    return date(d.year, d.month, 1)


def _add_months(d: date, delta_months: int) -> date:
    """Return first day of month shifted by delta_months."""
    y = d.year + (d.month - 1 + delta_months) // 12
    m = (d.month - 1 + delta_months) % 12 + 1
    return date(y, m, 1)


def _month_end(d: date) -> date:
    """Last day of the month containing d."""
    start = _month_start(d)
    nxt = _add_months(start, 1)
    return nxt - timedelta(days=1)


def _month_key(d: date) -> str:
    return f"{d.year:04d}-{d.month:02d}"


def _parse_month_key(key: str) -> date | None:
    try:
        y_s, m_s = (key or "").split("-")
        y, m = int(y_s), int(m_s)
        if not (1 <= m <= 12):
            return None
        return date(y, m, 1)
    except Exception:
        return None


def _month_label(d: date) -> str:
    return f"{SPANISH_MONTH_ABBR[d.month - 1]} {d.year}"


def _semester_key(year: int, half: int) -> str:
    return f"{year:04d}-S{half}"


def _parse_semester_key(key: str) -> tuple[int, int] | None:
    try:
        y_s, h_s = (key or "").split("-")
        year = int(y_s)
        if not h_s.upper().startswith("S"):
            return None
        half = int(h_s[1:])
        if half not in (1, 2):
            return None
        return year, half
    except Exception:
        return None


def _semester_range(year: int, half: int) -> tuple[date, date]:
    if half == 1:
        return date(year, 1, 1), date(year, 6, 30)
    return date(year, 7, 1), date(year, 12, 31)


def _add_semesters(year: int, half: int, delta: int) -> tuple[int, int]:
    # Represent semester index as year*2 + (half-1)
    idx = year * 2 + (half - 1) + delta
    new_year = idx // 2
    new_half = (idx % 2) + 1
    return new_year, new_half


def _semester_label(year: int, half: int) -> str:
    if half == 1:
        return f"S1 {year} (Ene-Jun)"
    return f"S2 {year} (Jul-Dic)"


def _royalty_available_semesters(session_db, selected_sem_start: date | None = None) -> list[tuple[int, int]]:
    available: set[tuple[int, int]] = set()

    def _add_from_period(period_type, period_start):
        if not period_start:
            return
        year = int(period_start.year)
        month = int(period_start.month)
        half = 1 if month <= 6 else 2
        available.add((year, half))

    for period_type, period_start in (
        session_db.query(SongRevenueEntry.period_type, SongRevenueEntry.period_start)
        .filter(SongRevenueEntry.period_start.isnot(None))
        .distinct()
        .all()
    ):
        _add_from_period(period_type, period_start)

    for period_type, period_start in (
        session_db.query(AlbumRevenueEntry.period_type, AlbumRevenueEntry.period_start)
        .filter(AlbumRevenueEntry.period_start.isnot(None))
        .distinct()
        .all()
    ):
        _add_from_period(period_type, period_start)

    today = today_local()
    if today.month <= 6:
        available.add((today.year - 1, 2))
    else:
        available.add((today.year, 1))

    if selected_sem_start:
        available.add((selected_sem_start.year, 1 if selected_sem_start.month <= 6 else 2))

    return sorted(available, key=lambda value: (value[0], value[1]), reverse=True)


def _isrc_key(val: str | None) -> str:
    if not val:
        return ""
    s = str(val).strip().upper()
    return "".join(ch for ch in s if ch.isalnum())


def _norm_isrc(val: str | None) -> str:
    raw = _isrc_key(val)
    if not raw:
        return ""
    if len(raw) == 12:
        return f"{raw[:2]}-{raw[2:5]}-{raw[5:7]}-{raw[7:]}"
    return raw


def _norm_isrc_list(values) -> list[str]:
    seen = set()
    out = []
    for value in values or []:
        code = _norm_isrc(value)
        if not code or code in seen:
            continue
        seen.add(code)
        out.append(code)
    return out


def _song_type_key(song: Song | None) -> str:
    if not song:
        return "DISCOGRAFICA"
    if bool(getattr(song, "is_distribution", False)):
        return "DISTRIBUCION"
    if bool(getattr(song, "is_catalog", False)):
        return "CATALOGO"
    return "DISCOGRAFICA"


def _song_type_label(song: Song | None) -> str:
    key = _song_type_key(song)
    if key == "DISTRIBUCION":
        return "Distribución"
    if key == "CATALOGO":
        return "Catálogo"
    return "Discográfica"


def _song_type_badge_class(song: Song | None) -> str:
    key = _song_type_key(song)
    if key == "DISTRIBUCION":
        return "text-bg-info"
    if key == "CATALOGO":
        return "text-bg-secondary"
    return "text-bg-dark"


def _norm_person_name_key(value: str | None) -> str:
    return re.sub(r"\s+", " ", (value or "").strip()).casefold()


def _song_artist_name_list(song: Song | None = None, artists=None) -> list[str]:
    rows = artists if artists is not None else (getattr(song, "artists", None) or [])
    out: list[str] = []
    seen: set[str] = set()
    for row in rows or []:
        raw = row if isinstance(row, str) else getattr(row, "name", None)
        name = re.sub(r"\s+", " ", (raw or "").strip())
        if not name:
            continue
        key = _norm_person_name_key(name)
        if key in seen:
            continue
        seen.add(key)
        out.append(name)
    return out


def _song_collaborator_from_names(artist_names: list[str] | None, interpreter_names: list[str] | None) -> str | None:
    artist_keys = {_norm_person_name_key(name) for name in (artist_names or []) if _norm_person_name_key(name)}
    out: list[str] = []
    seen: set[str] = set()
    for raw in interpreter_names or []:
        name = re.sub(r"\s+", " ", (raw or "").strip())
        if not name:
            continue
        key = _norm_person_name_key(name)
        if not key or key in artist_keys or key in seen:
            continue
        seen.add(key)
        out.append(name)
    return ", ".join(out) or None


def _song_interpreter_rows_map(session_db, song_ids: list[UUID] | list[str] | None) -> dict[str, list[SongInterpreter]]:
    result: dict[str, list[SongInterpreter]] = {}
    normalized_ids = [to_uuid(sid) for sid in (song_ids or []) if to_uuid(sid)]
    if not normalized_ids:
        return result
    rows = (
        session_db.query(SongInterpreter)
        .filter(SongInterpreter.song_id.in_(normalized_ids))
        .order_by(SongInterpreter.song_id.asc(), SongInterpreter.is_main.desc(), SongInterpreter.created_at.asc())
        .all()
    )
    for row in rows:
        sid = str(getattr(row, "song_id", "") or "")
        if not sid:
            continue
        result.setdefault(sid, []).append(row)
    return result


def _song_display_parts(song: Song | None, interpreter_rows: list[SongInterpreter] | None = None) -> dict:
    artist_names = _song_artist_name_list(song=song)
    interpreters: list[str] = []
    seen_interpreters: set[str] = set()
    for row in interpreter_rows or []:
        name = re.sub(r"\s+", " ", ((getattr(row, "name", None) or "") if not isinstance(row, str) else row).strip())
        if not name:
            continue
        key = _norm_person_name_key(name)
        if key in seen_interpreters:
            continue
        seen_interpreters.add(key)
        interpreters.append(name)
    if not interpreters:
        interpreters = list(artist_names)
    collaborator = _song_collaborator_from_names(artist_names, interpreters)
    return {
        "artist_names": artist_names,
        "interpreters": interpreters,
        "interpreters_str": ", ".join(interpreters) or ", ".join(artist_names) or "",
        "collaborator": collaborator or "",
    }


def _annotate_song_display_fields(session_db, songs, *, persist: bool = False) -> dict[str, dict]:
    songs = list(songs or [])
    if not songs:
        return {}
    interp_map = _song_interpreter_rows_map(session_db, [getattr(song, "id", None) for song in songs])
    out: dict[str, dict] = {}
    changed = False
    for song in songs:
        sid = str(getattr(song, "id", "") or "")
        parts = _song_display_parts(song, interp_map.get(sid, []))
        setattr(song, "display_interpreters", parts.get("interpreters") or [])
        setattr(song, "display_interpreters_str", parts.get("interpreters_str") or "")
        setattr(song, "display_collaborator", parts.get("collaborator") or "")
        out[sid] = parts
        if persist:
            new_value = parts.get("collaborator") or None
            if (getattr(song, "collaborator", None) or None) != new_value:
                song.collaborator = new_value
                changed = True
    if persist and changed:
        session_db.flush()
    return out


def _seconds_to_timecode(total_seconds: int | None) -> str:
    if total_seconds in (None, ""):
        return "—"
    try:
        total = int(total_seconds)
    except Exception:
        return "—"
    if total < 0:
        return "—"
    hours, rem = divmod(total, 3600)
    minutes, seconds = divmod(rem, 60)
    if hours:
        return f"{hours}:{str(minutes).zfill(2)}:{str(seconds).zfill(2)}"
    return f"{minutes}:{str(seconds).zfill(2)}"


def _album_kind_label(album: Album | None) -> str:
    raw = (getattr(album, "album_type", None) or "ALBUM").strip().upper()
    return "EP" if raw == "EP" else "Disco"


def _album_ownership_key(album: Album | None) -> str:
    if not album:
        return "DISCOGRAFICA"
    if bool(getattr(album, "is_distribution", False)):
        return "DISTRIBUCION"
    if bool(getattr(album, "is_catalog", False)):
        return "CATALOGO"
    return "DISCOGRAFICA"


def _album_ownership_label(album: Album | None) -> str:
    key = _album_ownership_key(album)
    if key == "DISTRIBUCION":
        return "Distribución"
    if key == "CATALOGO":
        return "Catálogo"
    return "Propio"


def _album_ownership_badge_class(album: Album | None) -> str:
    key = _album_ownership_key(album)
    if key == "DISTRIBUCION":
        return "text-bg-info"
    if key == "CATALOGO":
        return "text-bg-secondary"
    return "text-bg-dark"


def _album_physical_labels(album: Album | None) -> list[str]:
    if not album:
        return []
    out = []
    if bool(getattr(album, "physical_cd", False)):
        out.append("CD")
    if bool(getattr(album, "physical_vinyl", False)):
        out.append("Vinilo")
    return out


