def _resolve_or_create_promoter_for_contract(session_db, nick: str, tax_id: str = '', contact_email: str = '', contact_phone: str = '') -> Promoter:
    nickname = (nick or '').strip()
    promoter = None
    if nickname:
        promoter = (
            session_db.query(Promoter)
            .filter(func.lower(Promoter.nick) == nickname.lower())
            .first()
        )
    if not promoter:
        promoter = Promoter(nick=nickname or 'Beneficiario')
        session_db.add(promoter)
        session_db.flush()
    if nickname:
        promoter.nick = nickname
    if tax_id:
        promoter.tax_id = tax_id
    if contact_email:
        promoter.contact_email = contact_email
    if contact_phone:
        promoter.contact_phone = contact_phone
    session_db.add(promoter)
    return promoter


def _save_contract_royalty_rows(session_db, media_kind: str, item_id, rows_payload: list[dict]):
    media_kind = (media_kind or 'SONG').strip().upper()
    created = []
    for row in rows_payload or []:
        nick = (row.get('nick') or '').strip()
        if not nick:
            continue
        promoter = _resolve_or_create_promoter_for_contract(
            session_db,
            nick=nick,
            tax_id=(row.get('tax_id') or '').strip(),
            contact_email=(row.get('contact_email') or '').strip(),
            contact_phone=(row.get('contact_phone') or '').strip(),
        )
        pct = _parse_pct(row.get('pct'))
        base = _norm_contract_base(row.get('base'))
        profit_scope = _norm_profit_scope(row.get('profit_scope')) if base == 'PROFIT' else None
        if media_kind == 'ALBUM':
            rec = (
                session_db.query(AlbumRoyaltyBeneficiary)
                .filter(AlbumRoyaltyBeneficiary.album_id == item_id)
                .filter(AlbumRoyaltyBeneficiary.promoter_id == promoter.id)
                .first()
            )
            if not rec:
                rec = AlbumRoyaltyBeneficiary(album_id=item_id, promoter_id=promoter.id)
                session_db.add(rec)
        else:
            rec = (
                session_db.query(SongRoyaltyBeneficiary)
                .filter(SongRoyaltyBeneficiary.song_id == item_id)
                .filter(SongRoyaltyBeneficiary.promoter_id == promoter.id)
                .first()
            )
            if not rec:
                rec = SongRoyaltyBeneficiary(song_id=item_id, promoter_id=promoter.id)
                session_db.add(rec)
        rec.promoter_id = promoter.id
        rec.pct = pct
        rec.base = base
        rec.profit_scope = profit_scope
        rec.updated_at = datetime.now(TZ_MADRID)
        session_db.add(rec)
        created.append(rec)
    return created

def _song_material_slot_label(category: str | None, slot_key: str | None, display_name: str | None = None) -> str:
    cat = (category or "").strip().upper()
    slot = (slot_key or "DEFAULT").strip().upper()
    if cat == "COVER":
        if slot == "COVER_PROVISIONAL":
            return "Portada provisional"
        return "Portada"
    if cat == "MASTER":
        if slot == "MASTER_48":
            return "Master 48 bits"
        if slot == "MASTER_24":
            return "Master 24 bits"
        if slot == "MASTER_16":
            return "Master 16 bits"
        return (display_name or "").strip() or "Subproducto"
    if cat == "INSTRUMENTAL":
        if slot == "DEFAULT":
            return "Instrumental"
        return (display_name or "").strip() or "Subproducto"
    if cat == "TV_TRACK":
        if slot == "DEFAULT":
            return "TV Track"
        return (display_name or "").strip() or "Subproducto"
    if cat == "STEMS":
        return (display_name or "").strip() or "Stems"
    return (display_name or "").strip() or "Archivo"


def _download_remote_content(file_url: str, timeout: int = 30) -> tuple[bytes, str | None]:
    target_url = (file_url or "").strip()
    if not target_url:
        raise ValueError("No hay URL de archivo.")
    req = Request(target_url, headers={"User-Agent": "Mozilla/5.0"})
    with urlopen(req, timeout=timeout) as resp:
        data = resp.read()
        guessed = getattr(resp, "headers", {}).get_content_type() if getattr(resp, "headers", None) else None
    return data, guessed


def _safe_zip_member_name(name: str | None, existing: set[str], fallback: str) -> str:
    raw = (name or "").replace("\\", "/").lstrip("/")
    parts = [part for part in raw.split("/") if part not in ("", ".", "..")]
    candidate = "/".join(parts).strip() or fallback
    if candidate not in existing:
        existing.add(candidate)
        return candidate
    stem = Path(candidate).stem or Path(fallback).stem or "archivo"
    suffix = Path(candidate).suffix
    idx = 2
    while True:
        alt = f"{stem}_{idx}{suffix}"
        if alt not in existing:
            existing.add(alt)
            return alt
        idx += 1


def _convert_image_content(data: bytes, target_format: str) -> tuple[bytes, str, str]:
    fmt = (target_format or "").strip().lower()
    if fmt not in {"jpg", "jpeg", "png"}:
        raise ValueError("Formato de imagen no válido.")
    if not PILLOW_AVAILABLE:
        raise RuntimeError("Pillow no está disponible para convertir imágenes.")
    with PILImage.open(BytesIO(data)) as img:
        out = BytesIO()
        if fmt == "png":
            img.save(out, format="PNG")
            return out.getvalue(), "image/png", ".png"
        if img.mode not in ("RGB", "L"):
            if "A" in img.getbands():
                bg = PILImage.new("RGB", img.size, (255, 255, 255))
                bg.paste(img, mask=img.getchannel("A"))
                img = bg
            else:
                img = img.convert("RGB")
        elif img.mode == "L":
            img = img.convert("RGB")
        img.save(out, format="JPEG", quality=95)
        return out.getvalue(), "image/jpeg", ".jpg"


def _convert_audio_content_to_mp3(data: bytes, source_ext: str | None = None) -> tuple[bytes, str, str]:
    if not PYDUB_AVAILABLE:
        raise RuntimeError("pydub no está disponible para convertir audio.")
    fmt = (source_ext or "").lower().lstrip(".") or None
    seg = AudioSegment.from_file(BytesIO(data), format=fmt or None)
    out = BytesIO()
    seg.export(out, format="mp3", bitrate="320k")
    return out.getvalue(), "audio/mpeg", ".mp3"


def _song_material_completion_meta(song: Song, material_rows: list[SongMaterial]) -> dict:
    # Audios obligatorios para considerar la canción "completa":
    #  - MASTER: basta con UNO cualquiera de los formatos (48/24/16); los demás son opcionales.
    #  - INSTRUMENTAL, TV_TRACK y STEMS: obligatorios.
    # (La portada se controla aparte, en cover_principal.)
    basics = {
        "MASTER": False,
        "INSTRUMENTAL": False,
        "TV_TRACK": False,
        "STEMS": False,
    }
    any_non_cover = False
    has_pending = False   # algún material recibido por entrega aún sin validar
    last_cover_at = None
    last_material_at = None
    cover_principal = False   # portada PRINCIPAL (slot COVER); la provisional NO pone el icono en verde
    any_cover_material = False

    for row in material_rows or []:
        category = (getattr(row, "category", None) or "").strip().upper()
        slot = (getattr(row, "slot_key", None) or "DEFAULT").strip().upper()
        dt = getattr(row, "updated_at", None) or getattr(row, "created_at", None)
        if category == "COVER":
            any_cover_material = True
            if slot != "COVER_PROVISIONAL":
                cover_principal = True
            if dt and (last_cover_at is None or dt > last_cover_at):
                last_cover_at = dt
            continue
        any_non_cover = True
        if dt and (last_material_at is None or dt > last_material_at):
            last_material_at = dt
        vstatus = (getattr(row, "validation_status", None) or "VALIDATED").strip().upper()
        if vstatus == "PENDING":
            has_pending = True
            continue
        if category == "MASTER" and slot in ("MASTER_48", "MASTER_24", "MASTER_16"):
            basics["MASTER"] = True
        elif category == "INSTRUMENTAL" and slot == "DEFAULT":
            basics["INSTRUMENTAL"] = True
        elif category == "TV_TRACK" and slot == "DEFAULT":
            basics["TV_TRACK"] = True
        elif category == "STEMS":
            basics["STEMS"] = True

    # Legacy: cover_url sin material COVER asociado → se considera portada principal.
    if not any_cover_material and bool(getattr(song, "cover_url", None)):
        cover_principal = True

    completed_basics = sum(1 for value in basics.values() if value)
    # Mientras haya algún material pendiente de validar, el estado NO puede ser "completo" (queda amarillo).
    if completed_basics == len(basics) and not has_pending:
        state = "complete"
    elif completed_basics > 0 or any_non_cover or has_pending:
        state = "partial"
    else:
        state = "none"

    return {
        "cover_done": cover_principal,
        "last_cover_at": last_cover_at,
        "last_material_at": last_material_at,
        "completed_basics": completed_basics,
        "total_basics": len(basics),
        "state": state,
        "text_class": "text-success" if state == "complete" else ("text-warning" if state == "partial" else "text-danger"),
        "badge_class": "text-bg-success" if state == "complete" else ("text-bg-warning text-dark" if state == "partial" else "text-bg-danger"),
    }


def _ensure_song_cover_material_row(session_db, song: Song | None) -> None:
    if not song or not getattr(song, "id", None):
        return
    cover_url = (getattr(song, "cover_url", None) or "").strip()
    if not cover_url:
        return
    exists = (
        session_db.query(SongMaterial)
        .filter(SongMaterial.song_id == song.id)
        .filter(func.upper(SongMaterial.category) == "COVER")
        .first()
    )
    if exists:
        return
    mime_type = mimetypes.guess_type(cover_url.split("?", 1)[0])[0] or None
    session_db.add(
        SongMaterial(
            song_id=song.id,
            category="COVER",
            slot_key="COVER",
            display_name="Portada",
            file_name="portada",
            file_url=cover_url,
            mime_type=mime_type,
        )
    )
    session_db.flush()


def _resolve_song_cover_url(session_db, song: Song, material_rows: list[SongMaterial] | None = None) -> None:
    """Recalcula Song.cover_url: portada principal (slot COVER) si existe; si no, la provisional."""
    if not song or not getattr(song, "id", None):
        return
    if material_rows is None:
        material_rows = (
            session_db.query(SongMaterial)
            .filter(SongMaterial.song_id == song.id)
            .filter(func.upper(SongMaterial.category) == "COVER")
            .all()
        )
    principal = None
    provisional = None
    for row in material_rows or []:
        if (getattr(row, "category", None) or "").strip().upper() != "COVER":
            continue
        slot = (getattr(row, "slot_key", None) or "COVER").strip().upper()
        if slot == "COVER_PROVISIONAL":
            if provisional is None:
                provisional = row
        elif principal is None:
            principal = row
    chosen = principal or provisional
    if chosen is not None:
        song.cover_url = (getattr(chosen, "file_url", None) or "").strip() or None
    else:
        song.cover_url = None
    session_db.add(song)


def _refresh_song_material_status(session_db, song_or_id, material_rows: list[SongMaterial] | None = None, status_obj: SongStatus | None = None) -> dict:
    song = song_or_id if isinstance(song_or_id, Song) else session_db.get(Song, to_uuid(song_or_id))
    if not song:
        return {"state": "none", "text_class": "text-danger", "badge_class": "text-bg-danger"}
    if material_rows is None:
        material_rows = (
            session_db.query(SongMaterial)
            .filter(SongMaterial.song_id == song.id)
            .order_by(SongMaterial.created_at.asc())
            .all()
        )
    meta = _song_material_completion_meta(song, material_rows)
    st = status_obj or _ensure_song_status_row(session_db, song.id)
    now_dt = datetime.now(TZ_MADRID)
    st.cover_done = bool(meta["cover_done"])
    st.cover_updated_at = meta["last_cover_at"] or (st.cover_updated_at if meta["cover_done"] else None)
    st.materials_done = meta["state"] == "complete"
    st.materials_updated_at = meta["last_material_at"]
    st.updated_at = now_dt
    session_db.add(st)
    return meta


def _album_material_completion_meta(album: Album, material_rows: list[AlbumMaterial]) -> dict:
    required = {
        "DDP": False,
        "BODEGON": False,
    }
    if bool(getattr(album, "physical_cd", False)) or bool(getattr(album, "physical_vinyl", False)):
        required["PHYSICAL_DESIGN"] = False

    any_non_cover = False
    last_cover_at = None
    last_material_at = None
    cover_exists = bool((getattr(album, "cover_url", None) or "").strip())

    for row in material_rows or []:
        category = (getattr(row, "category", None) or "").strip().upper()
        dt = getattr(row, "created_at", None)
        if category == "COVER":
            cover_exists = True
            if dt and (last_cover_at is None or dt > last_cover_at):
                last_cover_at = dt
            continue
        any_non_cover = True
        if dt and (last_material_at is None or dt > last_material_at):
            last_material_at = dt
        if category in required:
            required[category] = True

    completed_required = sum(1 for value in required.values() if value)
    total_required = len(required)
    if total_required and completed_required == total_required:
        state = "complete"
    elif completed_required > 0 or any_non_cover:
        state = "partial"
    else:
        state = "none"

    return {
        "cover_done": cover_exists,
        "last_cover_at": last_cover_at,
        "last_material_at": last_material_at,
        "completed_required": completed_required,
        "total_required": total_required,
        "state": state,
        "text_class": "text-success" if state == "complete" else ("text-warning" if state == "partial" else "text-danger"),
        "badge_class": "text-bg-success" if state == "complete" else ("text-bg-warning text-dark" if state == "partial" else "text-bg-danger"),
    }


def _ensure_album_status_row(session_db, album_or_id) -> AlbumStatus:
    if isinstance(album_or_id, Album):
        album = album_or_id
        aid = album.id
    else:
        aid = album_or_id
        album = session_db.get(Album, aid) if aid else None

    st = session_db.get(AlbumStatus, aid) if aid else None
    if not st and aid:
        st = AlbumStatus(album_id=aid)
        if album is not None:
            st.cover_done = bool((getattr(album, "cover_url", None) or "").strip())
            if st.cover_done:
                st.cover_updated_at = datetime.now(TZ_MADRID)
        session_db.add(st)
        session_db.flush()
    return st


def _refresh_album_material_status(session_db, album_or_id, material_rows: list[AlbumMaterial] | None = None, status_obj: AlbumStatus | None = None) -> dict:
    album = album_or_id if isinstance(album_or_id, Album) else session_db.get(Album, to_uuid(album_or_id))
    if not album:
        return {"state": "none", "text_class": "text-danger", "badge_class": "text-bg-danger"}
    if material_rows is None:
        material_rows = (
            session_db.query(AlbumMaterial)
            .filter(AlbumMaterial.album_id == album.id)
            .order_by(AlbumMaterial.created_at.asc())
            .all()
        )
    meta = _album_material_completion_meta(album, material_rows)
    st = status_obj or _ensure_album_status_row(session_db, album.id)
    now_dt = datetime.now(TZ_MADRID)
    st.cover_done = bool(meta["cover_done"])
    st.cover_updated_at = meta["last_cover_at"] or (st.cover_updated_at if meta["cover_done"] else None)
    st.materials_done = meta["state"] == "complete"
    st.materials_updated_at = meta["last_material_at"]
    st.updated_at = now_dt
    session_db.add(st)
    return meta


