@app.route("/recintos", methods=["GET", "POST"])
@admin_required
def venues_view():
    session = db()
    query_text = (request.args.get("q") or "").strip()

    if request.method == "POST":
        name = request.form.get("name","").strip()
        covered = (request.form.get("covered") == "on")
        allows_bars = (request.form.get("allows_bars") == "on")
        address = request.form.get("address","").strip()
        municipality = request.form.get("municipality","").strip()
        province = request.form.get("province","").strip()
        try:
            photo = request.files.get("photo")
            photo_url = upload_image(photo, "venues") if photo and getattr(photo, "filename", "") else None
            v = Venue(name=name, covered=covered, allows_bars=allows_bars, address=address,
                      municipality=municipality, province=province, photo_url=photo_url)
            session.add(v)
            session.commit()
            flash("Recinto creado.", "success")
            return redirect(url_for("venue_detail_view", vid=v.id))
        except Exception as e:
            session.rollback()
            flash(f"Error creando recinto: {e}", "danger")
            return redirect(url_for("venues_view"))
        finally:
            session.close()

    venues = session.query(Venue).order_by(Venue.name.asc()).all()
    if query_text:
        qn = _norm_text_key(query_text)
        def _venue_match(v):
            haystack = " ".join([
                v.name or "",
                v.address or "",
                v.municipality or "",
                v.province or "",
                "cubierto" if getattr(v, "covered", False) else "descubierto",
            ])
            return qn in _norm_text_key(haystack)
        venues = [v for v in venues if _venue_match(v)]
    session.close()
    return render_template("venues.html", venues=venues, query_text=query_text)

