        ("administracion", "fa-briefcase"),
        ("contabilidad", "fa-file-invoice-dollar"),
        ("personal", "fa-users-cog"),
        ("integraciones", "fa-plug"),
        ("databases.media", "fa-newspaper"),
        ("databases.bags", "fa-folder-open"),
