@app.route("/personal", methods=["GET", "POST"], endpoint="personnel_view")
@admin_required
def personnel_view():
    session_db = db()
    try:
        if request.method == "POST":
            email = (request.form.get("email") or "").strip().lower()
            nick = (request.form.get("nick") or "").strip()
            if not email or not nick:
                flash("Nick y email son obligatorios.", "danger")
                return redirect(url_for("personnel_view"))
            if session_db.query(User).filter(func.lower(User.email) == email).first():
                flash("Ya existe un usuario con ese email.", "danger")
                return redirect(url_for("personnel_view"))
            photo = request.files.get("photo")
            photo_url = upload_image(photo, "users") if (photo and getattr(photo, "filename", "")) else None
            temp_password = _generate_temporary_password()
            user = User(email=email, password_hash=generate_password_hash(temp_password), role=1)
            session_db.add(user)
            session_db.flush()
            profile = _ensure_user_profile(
                session_db,
                user,
                legacy_full_seed=False,
                nick=nick,
                photo_url=photo_url,
                first_name=(request.form.get("first_name") or "").strip() or None,
                last_name=(request.form.get("last_name") or "").strip() or None,
                dni=(request.form.get("dni") or "").strip() or None,
                birth_date=parse_optional_date(request.form.get("birth_date")),
                mobile_phones=_parse_phone_rows_from_form(request.form),
                departments=_normalize_departments(request.form.getlist("departments")),
                assigned_artist_ids=_normalize_assigned_artist_ids(request.form.getlist("assigned_artist_ids")),
            )
            _ensure_user_security(session_db, user)
            _sync_user_access_grants(session_db, user, profile)
            token = _make_password_token(user.id, purpose="welcome")
            ok, err = _send_optional_email(
                user.email,
                "Bienvenido al Back Office",
                _welcome_email_html(user, profile, token),
                text_body="Te hemos dado de alta en el Back Office. Revisa el enlace para crear tu contraseña.",
            )
            session_db.commit()
            if ok:
                flash("Usuario creado y correo de bienvenida enviado.", "success")
            else:
                flash(f"Usuario creado. No se pudo enviar el correo de bienvenida: {err}", "warning")
            return redirect(url_for("personnel_view"))

        users = (
            session_db.query(User, UserProfile, UserSecurity)
            .outerjoin(UserProfile, UserProfile.user_id == User.id)
            .outerjoin(UserSecurity, UserSecurity.user_id == User.id)
            .filter(or_(UserSecurity.is_deleted == False, UserSecurity.is_deleted.is_(None)))  # noqa: E712
            .order_by(func.lower(func.coalesce(UserProfile.nick, User.email)).asc())
            .all()
        )
        access_rows = _build_personnel_access_rows()
        artists = session_db.query(Artist).order_by(Artist.name.asc()).all()
        assigned_artist_map = {}
        for _user, profile, _security in users:
            ids = list(getattr(profile, "assigned_artist_ids", None) or []) if profile else []
            assigned_artist_map[str(_user.id)] = [str(x) for x in ids]
        return render_template("personnel.html", users=users, access_rows=access_rows, artists=artists, assigned_artist_map=assigned_artist_map)
    finally:
        session_db.close()


@app.route("/personal/<user_id>", methods=["GET", "POST"], endpoint="personnel_detail_view")
@admin_required
def personnel_detail_view(user_id):
    session_db = db()
    try:
        user = session_db.get(User, to_uuid(user_id))
        if not user:
            flash("Usuario no encontrado.", "warning")
            return redirect(url_for("personnel_view"))
        profile = _ensure_user_profile(session_db, user, legacy_full_seed=False)
        security = _ensure_user_security(session_db, user)
        _sync_user_access_grants(session_db, user, profile)
        tab = (request.args.get("tab") or "accesos").strip().lower()
        if tab not in {"accesos", "datos"}:
            tab = "accesos"

        if request.method == "POST":
            mode = (request.form.get("mode") or "").strip().lower()
            if mode == "datos":
                photo = request.files.get("photo")
                if photo and getattr(photo, "filename", ""):
                    profile.photo_url = upload_image(photo, "users")
                profile.nick = (request.form.get("nick") or profile.nick or "").strip() or profile.nick
                profile.first_name = (request.form.get("first_name") or "").strip() or None
                profile.last_name = (request.form.get("last_name") or "").strip() or None
                profile.dni = (request.form.get("dni") or "").strip() or None
                profile.birth_date = parse_optional_date(request.form.get("birth_date"))
                profile.mobile_phones = _parse_phone_rows_from_form(request.form)
                profile.departments = _normalize_departments(request.form.getlist("departments"))
                _prod_ids = _normalize_assigned_artist_ids(request.form.getlist("assigned_artist_ids_produccion"))
                _sello_ids = _normalize_assigned_artist_ids(request.form.getlist("assigned_artist_ids_sello"))
                _union_ids = []
                for _aid in _prod_ids + _sello_ids:
                    if _aid not in _union_ids:
                        _union_ids.append(_aid)
                profile.assigned_artist_ids_produccion = _prod_ids
                profile.assigned_artist_ids_sello = _sello_ids
                profile.assigned_artist_ids = _union_ids
                user.email = (request.form.get("email") or user.email or "").strip().lower() or user.email
                session_db.commit()
                flash("Usuario actualizado.", "success")
                return redirect(url_for("personnel_detail_view", user_id=user.id, tab="datos"))
            if mode == "accesos":
                if not is_master():
                    return forbid("Solo dirección puede modificar los accesos del personal.")
                grants = {g.resource_key: g for g in session_db.query(UserAccessGrant).filter(UserAccessGrant.user_id == user.id).all()}
                resources = session_db.query(UserAccessResource).order_by(UserAccessResource.sort_order.asc(), UserAccessResource.label.asc()).all()
                for resource in resources:
                    grant = grants.get(resource.key)
                    if not grant:
                        grant = UserAccessGrant(user_id=user.id, resource_key=resource.key)
                        session_db.add(grant)
                    grant.can_view_basic, grant.can_view_econ, grant.can_edit = _coherent_grant_values(
                        resource,
                        view=request.form.get(f"perm__{resource.key}__view") == "1",
                        econ=request.form.get(f"perm__{resource.key}__econ") == "1",
                        edit=request.form.get(f"perm__{resource.key}__edit") == "1",
                    )
                session_db.commit()
                flash("Accesos actualizados.", "success")
                return redirect(url_for("personnel_detail_view", user_id=user.id, tab="accesos"))

        grants = {g.resource_key: g for g in session_db.query(UserAccessGrant).filter(UserAccessGrant.user_id == user.id).all()}
        access_rows = _build_personnel_access_rows()
        artists = session_db.query(Artist).order_by(Artist.name.asc()).all()
        assigned_artist_ids = [str(x) for x in (getattr(profile, "assigned_artist_ids", None) or [])]
        assigned_prod_ids = [str(x) for x in (getattr(profile, "assigned_artist_ids_produccion", None) or [])]
        assigned_sello_ids = [str(x) for x in (getattr(profile, "assigned_artist_ids_sello", None) or [])]
        # Migración suave (en memoria, sin escribir BD): los usuarios antiguos solo tienen la lista
        # única; la repartimos por departamento para prerrellenar las facetas en el formulario.
        if not assigned_prod_ids and not assigned_sello_ids and assigned_artist_ids:
            _depts = list(getattr(profile, "departments", None) or [])
            if "Sello" in _depts and "Producción" not in _depts:
                assigned_sello_ids = list(assigned_artist_ids)
            else:
                assigned_prod_ids = list(assigned_artist_ids)
        return render_template(
            "personnel_detail.html",
            user=user,
            profile=profile,
            security=security,
            tab=tab,
            access_rows=access_rows,
            grants=grants,
            artists=artists,
            assigned_artist_ids=assigned_artist_ids,
            assigned_prod_ids=assigned_prod_ids,
            assigned_sello_ids=assigned_sello_ids,
            container_keys=set(_ACCESS_CHILDREN.keys()),
            target_is_master=(int(getattr(user, "role", 0) or 0) == 10),
        )
    finally:
        session_db.close()


@app.post("/personal/<user_id>/ver-como", endpoint="impersonate_start")
@admin_required
def impersonate_start(user_id):
    """Activa el modo «Ver como»: dirección usa la app con la identidad y permisos de otro usuario."""
    if not is_master():
        return forbid("Solo dirección puede usar el modo «Ver como».")
    if session.get("impersonator_id"):
        flash("Ya estás en modo visión. Sal primero para cambiar de usuario.", "warning")
        return redirect(url_for("personnel_detail_view", user_id=user_id))
    session_db = db()
    try:
        target = session_db.get(User, to_uuid(user_id))
        if not target:
            flash("Usuario no encontrado.", "warning")
            return redirect(url_for("personnel_view"))
        if str(target.id) == str(session.get("user_id")):
            flash("No puedes verte como tú mismo.", "warning")
            return redirect(url_for("personnel_detail_view", user_id=user_id))
        security = _ensure_user_security(session_db, target)
        if getattr(security, "is_deleted", False) or getattr(security, "is_blocked", False):
            flash("No puedes ver como un usuario bloqueado o eliminado.", "warning")
            return redirect(url_for("personnel_detail_view", user_id=user_id))
        profile = _ensure_user_profile(session_db, target, legacy_full_seed=False)
        session_db.commit()
        nick = (getattr(profile, "nick", None) or _email_to_nick(target.email or "")).strip()
        # Intercambiamos la identidad de sesión: a partir de aquí toda la app (permisos, menú,
        # economía, módulos de inicio) refleja al usuario impersonado. La identidad real se
        # guarda para poder volver y para autorizar la salida.
        session["impersonator_id"] = str(session.get("user_id"))
        session["impersonator_role"] = int(session.get("role") or 10)
        session["user_id"] = str(target.id)
        session["role"] = int(getattr(target, "role", 10) or 10)
        flash(f"Estás viendo la app como {nick}.", "info")
        return redirect(url_for("home"))
    finally:
        session_db.close()


@app.get("/salir-modo-vision", endpoint="impersonate_stop")
def impersonate_stop():
    """Sale del modo «Ver como» y restaura la sesión real de dirección."""
    imp = session.get("impersonator_id")
    if not imp:
        return redirect(url_for("home"))
    viewed_id = session.get("user_id")
    session["user_id"] = str(imp)
    session["role"] = int(session.get("impersonator_role") or 10)
    session.pop("impersonator_id", None)
    session.pop("impersonator_role", None)
    flash("Has salido del modo visión.", "success")
    try:
        return redirect(url_for("personnel_detail_view", user_id=viewed_id, tab="datos"))
    except Exception:
        return redirect(url_for("home"))


BULK_ACCESS_OPERATIONS = {
    "view": (True, False, False),
    "view_edit": (True, False, True),
    "view_econ": (True, True, False),
    "full": (True, True, True),
    "remove": (False, False, False),
}


@app.route("/personal/accesos-bloque", methods=["GET", "POST"], endpoint="personnel_bulk_access")
@admin_required
def personnel_bulk_access():
    # Solo dirección (rol master) puede configurar accesos en bloque.
    if not is_master():
        return forbid("Solo dirección puede configurar accesos del personal.")
    session_db = db()
    try:
        if request.method == "POST":
            user_ids = [to_uuid(x) for x in request.form.getlist("user_ids") if (x or "").strip()]
            section_keys = [x for x in request.form.getlist("section_keys") if (x or "").strip()]
            operation = (request.form.get("operation") or "").strip().lower()
            if not user_ids or not section_keys or operation not in BULK_ACCESS_OPERATIONS:
                flash("Selecciona al menos un trabajador, una sección y una operación.", "warning")
                return redirect(url_for("personnel_bulk_access"))
            # Hojas afectadas (pestañas/funcionalidades reales) de las secciones elegidas.
            leaf_keys = []
            for sk in section_keys:
                leaf_keys.extend(_leaf_keys_under(sk))
            leaf_keys = list(dict.fromkeys(leaf_keys))
            res_map = {r.key: r for r in session_db.query(UserAccessResource).filter(UserAccessResource.key.in_(leaf_keys)).all()}
            target_view, target_econ, target_edit = BULK_ACCESS_OPERATIONS[operation]
            applied = 0
            for uid in user_ids:
                target = session_db.get(User, uid)
                if not target or int(getattr(target, "role", 0) or 0) == 10:
                    continue  # nunca tocar a dirección
                grants = {g.resource_key: g for g in session_db.query(UserAccessGrant).filter(UserAccessGrant.user_id == uid).all()}
                for lk in leaf_keys:
                    resource = res_map.get(lk)
                    if not resource:
                        continue
                    grant = grants.get(lk)
                    if not grant:
                        grant = UserAccessGrant(user_id=uid, resource_key=lk)
                        session_db.add(grant)
                    grant.can_view_basic, grant.can_view_econ, grant.can_edit = _coherent_grant_values(
                        resource, view=target_view, econ=target_econ, edit=target_edit
                    )
                applied += 1
            session_db.commit()
            flash(f"Accesos aplicados a {applied} trabajador(es).", "success")
            return redirect(url_for("personnel_bulk_access"))

        rows = (
            session_db.query(User, UserProfile, UserSecurity)
            .outerjoin(UserProfile, UserProfile.user_id == User.id)
            .outerjoin(UserSecurity, UserSecurity.user_id == User.id)
            .all()
        )
        users = [
            (u, p, s) for (u, p, s) in rows
            if not (s and getattr(s, "is_deleted", False)) and int(getattr(u, "role", 0) or 0) != 10
        ]
        users.sort(key=lambda t: ((t[1].nick if t[1] and t[1].nick else t[0].email) or "").lower())
        access_rows = _build_personnel_access_rows()
        return render_template("personnel_bulk.html", users=users, access_rows=access_rows)
    finally:
        session_db.close()


