def _safe_uuid(value):
    try:
        return to_uuid(value)
    except Exception:
        return None


def _safe_int(value, default: int = 0) -> int:
    try:
        return int(str(value or "").strip() or default)
    except Exception:
        return default


def _json_dict(value) -> dict:
    if isinstance(value, dict):
        return dict(value)
    if isinstance(value, str) and value.strip():
        try:
            parsed = json.loads(value)
            return parsed if isinstance(parsed, dict) else {}
        except Exception:
            return {}
    return {}


def _json_list(value) -> list:
    if isinstance(value, list):
        return list(value)
    if isinstance(value, str) and value.strip():
        try:
            parsed = json.loads(value)
            return parsed if isinstance(parsed, list) else []
        except Exception:
            return []
    return []


APP33_ENTITY_LINK_TYPES = {
    "promoter": {"label": "Tercero", "icon": "fa-user-tie"},
    "artist": {"label": "Artista", "icon": "fa-microphone-lines"},
    "media": {"label": "Medio", "icon": "fa-bullhorn"},
    "venue": {"label": "Recinto", "icon": "fa-location-dot"},
    "ticketer": {"label": "Ticketera", "icon": "fa-ticket"},
    "publishing": {"label": "Editorial", "icon": "fa-pen-nib"},
}
APP33_ENTITY_LINK_ALIASES = {
    "third_party": "promoter", "tercero": "promoter", "promotor": "promoter",
    "artista": "artist",
    "medio": "media", "recinto": "venue", "ticketera": "ticketer", "editorial": "publishing",
    "publishing_company": "publishing",
}

def _entity_link_type(raw: str | None) -> str:
    value = (raw or "").strip().lower()
    value = APP33_ENTITY_LINK_ALIASES.get(value, value)
    return value if value in APP33_ENTITY_LINK_TYPES else ""


def _entity_link_label(entity_type: str | None) -> str:
    return APP33_ENTITY_LINK_TYPES.get(_entity_link_type(entity_type), {}).get("label", "Vinculación")


def _entity_placeholder_url() -> str:
    try:
        return url_for("static", filename="img/placeholder_photo.png")
    except Exception:
        return ""


def _entity_link_payload(session_db, entity_type: str | None, entity_id) -> dict | None:
    etype = _entity_link_type(entity_type)
    eid = _safe_uuid(entity_id)
    if not etype or not eid:
        return None
    row = None
    label = ""
    subtitle = ""
    logo_url = ""
    href = ""
    if etype == "promoter":
        row = session_db.get(Promoter, eid)
        if row:
            label = _promoter_display_name(row) or row.nick or "Tercero"
            subtitle = " · ".join([x for x in [(row.contact_email or "").strip(), (row.contact_phone or "").strip()] if x])
            logo_url = row.logo_url or ""
            href = url_for("promoter_detail_view", pid=row.id)
    elif etype == "artist":
        row = session_db.get(Artist, eid)
        if row:
            label = row.name or "Artista"
            subtitle = (getattr(row, "genre", "") or "").strip()
            logo_url = getattr(row, "photo_url", "") or ""
            href = url_for("artist_detail_view", artist_id=row.id)
    elif etype == "media":
        row = session_db.get(MediaOutlet, eid)
        if row:
            label = row.name or "Medio"
            subtitle = (row.media_type or "").replace("_", " ").title()
            logo_url = row.logo_url or ""
            href = url_for("media_outlet_detail_view", media_id=row.id)
    elif etype == "venue":
        row = session_db.get(Venue, eid)
        if row:
            label = row.name or "Recinto"
            subtitle = " · ".join([x for x in [(row.municipality or "").strip(), (row.province or "").strip()] if x])
            logo_url = row.photo_url or ""
            href = url_for("venue_detail_view", vid=row.id)
    elif etype == "ticketer":
        row = session_db.get(Ticketer, eid)
        if row:
            label = row.name or "Ticketera"
            subtitle = row.link_url or ""
            logo_url = row.logo_url or ""
            href = url_for("ticketer_detail_view", tid=row.id)
    elif etype == "publishing":
        row = session_db.get(PublishingCompany, eid)
        if row:
            label = row.name or "Editorial"
            subtitle = "Editorial"
            logo_url = row.logo_url or ""
            href = url_for("publishing_company_detail_view", pcid=row.id)
    if not row:
        return None
    return {
        "type": etype,
        "type_label": _entity_link_label(etype),
        "icon": APP33_ENTITY_LINK_TYPES.get(etype, {}).get("icon", "fa-link"),
        "id": str(eid),
        "label": label,
        "subtitle": subtitle,
        "logo_url": logo_url or _entity_placeholder_url(),
        "href": href,
    }


def _entity_link_rows(session_db, entity_type: str | None, entity_id, active_only: bool = True) -> list[dict]:
    etype = _entity_link_type(entity_type)
    eid = _safe_uuid(entity_id)
    if not etype or not eid:
        return []
    q = session_db.query(ThirdPartyLink).filter(
        or_(
            and_(ThirdPartyLink.source_type == etype, ThirdPartyLink.source_id == eid),
            and_(ThirdPartyLink.target_type == etype, ThirdPartyLink.target_id == eid),
        )
    )
    if active_only:
        q = q.filter(ThirdPartyLink.is_active.is_(True))
    rows = q.order_by(ThirdPartyLink.created_at.desc()).all()
    out = []
    for link in rows:
        if link.source_type == etype and str(link.source_id) == str(eid):
            other = _entity_link_payload(session_db, link.target_type, link.target_id)
            source = _entity_link_payload(session_db, link.source_type, link.source_id)
        else:
            other = _entity_link_payload(session_db, link.source_type, link.source_id)
            source = _entity_link_payload(session_db, link.target_type, link.target_id)
        if not other:
            continue
        out.append({
            "id": str(link.id),
            "relation_title": link.relation_title or "",
            "note": link.note or "",
            "is_active": bool(link.is_active),
            "created_at_label": _invitation_display_datetime(link.created_at) if "_invitation_display_datetime" in globals() else "",
            "source": source,
            "linked": other,
        })
    return out


def _promoter_link_summary(session_db, promoter: Promoter | None) -> dict:
    if not promoter:
        return {}
    rows = _entity_link_rows(session_db, "promoter", promoter.id, active_only=True)
    if not rows:
        pub = getattr(promoter, "publishing_company", None)
        if pub:
            return {"label": pub.name, "type_label": "Editorial", "logo_url": pub.logo_url or _entity_placeholder_url(), "items": []}
        return {}
    first = rows[0].get("linked") or {}
    label = first.get("label") or ""
    type_label = first.get("type_label") or ""
    return {
        "label": label,
        "type_label": type_label,
        "relation_title": rows[0].get("relation_title") or "",
        "icon": first.get("icon") or "fa-link",
        "logo_url": first.get("logo_url") or _entity_placeholder_url(),
        "items": [{
            "label": (r.get("linked") or {}).get("label", ""),
            "type_label": (r.get("linked") or {}).get("type_label", ""),
            "relation_title": r.get("relation_title", ""),
            "icon": (r.get("linked") or {}).get("icon", "fa-link"),
            "logo_url": (r.get("linked") or {}).get("logo_url", ""),
        } for r in rows[:3]],
    }


def _promoter_link_summary_text(summary: dict | None) -> str:
    """Texto corto y legible del vínculo principal, con la relación por delante.
    Ej.: "director · Radio X" o, si no hay relación, "Medio · Radio X"."""
    if not summary:
        return ""
    lead = (summary.get("relation_title") or "").strip() or (summary.get("type_label") or "")
    parts = [lead, summary.get("label") or ""]
    return " · ".join([x for x in parts if x])


def _invitation_token() -> str:
    return _uuid.uuid4().hex + _uuid.uuid4().hex[:8]


def _invitation_display_date(value) -> str:
    if not value:
        return "Sin fecha"
    try:
        return value.strftime("%d/%m/%Y")
    except Exception:
        return str(value)


def _invitation_display_datetime(value) -> str:
    if not value:
        return ""
    try:
        return value.strftime("%d/%m/%Y %H:%M")
    except Exception:
        return str(value)


def _invitation_normalize_search(value: str | None) -> str:
    raw = str(value or "")
    raw = unicodedata.normalize("NFD", raw)
    raw = "".join(ch for ch in raw if unicodedata.category(ch) != "Mn")
    raw = re.sub(r"[^a-zA-Z0-9]+", " ", raw)
    return raw.casefold().strip()


def _concert_artist_ids(concert: Concert | None) -> list[str]:
    ids = []
    if not concert:
        return ids
    raw = getattr(concert, "artist_ids", None)
    if isinstance(raw, list):
        ids.extend([str(x) for x in raw if x])
    if getattr(concert, "artist_id", None):
        ids.append(str(concert.artist_id))
    out = []
    seen = set()
    for item in ids:
        if item and item not in seen:
            seen.add(item)
            out.append(item)
    return out


def _concert_artist_rows(session_db, concert: Concert | None) -> list[Artist]:
    ids = [_safe_uuid(x) for x in _concert_artist_ids(concert)]
    ids = [x for x in ids if x]
    if not ids:
        return []
    rows = session_db.query(Artist).filter(Artist.id.in_(ids)).order_by(Artist.name.asc()).all()
    order = {str(x): i for i, x in enumerate(ids)}
    return sorted(rows, key=lambda a: order.get(str(a.id), 9999))


def _artist_chip_payload(artist: Artist | None) -> dict:
    return {
        "id": str(getattr(artist, "id", "") or ""),
        "name": getattr(artist, "name", None) or "Artista",
        "photo_url": getattr(artist, "photo_url", None) or url_for("static", filename="img/placeholder_photo.png"),
    }


def _invitation_event_type_label(concert: Concert | None) -> str:
    raw = (getattr(concert, "activity_type", None) or getattr(concert, "sale_type", None) or "CONCIERTO").strip().upper()
    labels = {
        "CONCIERTO": "Concierto",
        "FESTIVAL": "Festival",
        "EVENTO_PROMOCIONAL": "Evento promocional",
        "PROGRAMA_TV": "Programa de TV",
        "TV": "Programa de TV",
        "MARCA": "Acción con marca",
        "OTROS": "Otros",
        "CADIZ": "Festival / ciclo",
    }
    return labels.get(raw, raw.replace("_", " ").title())


def _invitation_event_title(concert: Concert | None) -> str:
    if not concert:
        return "Evento"
    for field in ("festival_name", "manual_venue_name"):
        value = (getattr(concert, field, None) or "").strip()
        if value:
            return value
    venue = getattr(concert, "venue", None)
    if venue and getattr(venue, "name", None):
        return venue.name
    return _invitation_event_type_label(concert)


def _invitation_event_city(concert: Concert | None) -> str:
    if not concert:
        return ""
    return (getattr(concert, "manual_municipality", None) or (getattr(getattr(concert, "venue", None), "municipality", None) or "")).strip()


def _invitation_event_province(concert: Concert | None) -> str:
    if not concert:
        return ""
    return (getattr(concert, "manual_province", None) or (getattr(getattr(concert, "venue", None), "province", None) or "")).strip()


def _invitation_event_venue_name(concert: Concert | None) -> str:
    if not concert:
        return ""
    return (getattr(getattr(concert, "venue", None), "name", None) or getattr(concert, "manual_venue_name", None) or "").strip()


def _invitation_event_payload(session_db, concert: Concert, include_counts: bool = False) -> dict:
    artists = [_artist_chip_payload(a) for a in _concert_artist_rows(session_db, concert)]
    payload = {
        "id": str(concert.id),
        "type_label": _invitation_event_type_label(concert),
        "title": _invitation_event_title(concert),
        "date": concert.date.isoformat() if getattr(concert, "date", None) else "",
        "date_label": _invitation_display_date(getattr(concert, "date", None)),
        "city": _invitation_event_city(concert),
        "province": _invitation_event_province(concert),
        "venue": _invitation_event_venue_name(concert),
        "show_time": getattr(concert, "show_time", None) or "",
        "artists": artists,
        "artist_names": ", ".join([a["name"] for a in artists]) or (getattr(getattr(concert, "artist", None), "name", None) or ""),
        "status": getattr(concert, "status", None) or "",
    }
    if include_counts:
        payload["counts"] = _invitation_event_counts(session_db, concert)
    return payload


def _invitation_category_legacy_rows(concert: Concert | None) -> list[dict]:
    rows: list[dict] = []
    seen = set()
    for raw in list(getattr(concert, "invitations_json", None) or []):
        if not isinstance(raw, dict):
            continue
        name = (raw.get("category") or raw.get("name") or "General").strip() or "General"
        key = name.casefold()
        if key in seen:
            continue
        seen.add(key)
        rows.append({
            "name": name,
            "qty_contract": _safe_int(raw.get("total_qty"), _safe_int(raw.get("artist_qty")) + _safe_int(raw.get("office_qty"))),
            "source": "CONTRATO",
        })
    ticketing = getattr(concert, "ticketing_payload", None) or {}
    if isinstance(ticketing, dict):
        for raw in list(ticketing.get("ticket_types") or []):
            if not isinstance(raw, dict):
                continue
            qty = _safe_int(raw.get("invites_total")) or _safe_int(raw.get("invites_artist"))
            if qty <= 0:
                continue
            name = (raw.get("name") or raw.get("category") or "General").strip() or "General"
            key = name.casefold()
            if key in seen:
                continue
            seen.add(key)
            rows.append({"name": name, "qty_contract": qty, "source": "TICKETING"})
    if not rows:
        rows.append({"name": "General", "qty_contract": 0, "source": "DEFAULT"})
    return rows


def _invitation_get_categories(session_db, concert: Concert, ensure_defaults: bool = False) -> list[InvitationCategory]:
    categories = (
        session_db.query(InvitationCategory)
        .filter(InvitationCategory.concert_id == concert.id)
        .order_by(InvitationCategory.sort_order.asc(), InvitationCategory.created_at.asc())
        .all()
    )
    if categories or not ensure_defaults:
        return categories
    created = []
    for idx, row in enumerate(_invitation_category_legacy_rows(concert)):
        cat = InvitationCategory(
            concert_id=concert.id,
            name=row["name"],
            source=row.get("source") or "DEFAULT",
            qty_contract=_safe_int(row.get("qty_contract")),
            sort_order=idx,
            created_by_user_id=_safe_uuid(session.get("user_id")),
            created_by_nick=_current_user_email(),
        )
        session_db.add(cat)
        created.append(cat)
    try:
        session_db.flush()
    except Exception:
        session_db.rollback()
        return (
            session_db.query(InvitationCategory)
            .filter(InvitationCategory.concert_id == concert.id)
            .order_by(InvitationCategory.sort_order.asc(), InvitationCategory.created_at.asc())
            .all()
        )
    return created


def _invitation_category_payload(cat: InvitationCategory, counts: dict | None = None) -> dict:
    qty_contract = _safe_int(getattr(cat, "qty_contract", 0))
    qty_extra = _safe_int(getattr(cat, "qty_extra", 0))
    uploaded = _safe_int((counts or {}).get("uploaded", 0))
    assigned = _safe_int((counts or {}).get("assigned", 0))
    total_configured = qty_contract + qty_extra
    return {
        "id": str(cat.id),
        "name": cat.name,
        "ticket_kind": cat.ticket_kind or "PDF_UNNUMBERED",
        "guest_list_mode": cat.guest_list_mode or "",
        "qty_contract": qty_contract,
        "qty_extra": qty_extra,
        "configured": total_configured,
        "uploaded": uploaded,
        "assigned": assigned,
        "available_configured": max(total_configured - assigned, 0),
        "source": cat.source or "MANUAL",
        "is_active": bool(cat.is_active),
    }


def _invitation_ticket_kind_label(value: str | None) -> str:
    key = (value or "PDF_UNNUMBERED").strip().upper()
    return dict(INVITATION_CATEGORY_TYPES).get(key, key.replace("_", " ").title())


def _invitation_ticket_status_label(value: str | None) -> str:
    labels = {
        "AVAILABLE": "Disponible",
        "ASSIGNED": "Asignada",
        "SENT": "Enviada",
        "DELIVERED": "Entregada",
        "PICKED_UP": "Recogida",
        "LOST": "Perdida",
    }
    return labels.get((value or "AVAILABLE").upper(), (value or "AVAILABLE").title())


def _invitation_ticket_status_class(value: str | None) -> str:
    key = (value or "AVAILABLE").strip().upper()
    if key == "AVAILABLE":
        return "available"
    if key == "ASSIGNED":
        return "assigned"
    if key in {"SENT", "DELIVERED", "PICKED_UP"}:
        return "sent"
    if key == "LOST":
        return "lost"
    return key.lower()


def _invitation_ticket_payload(t: InvitationTicket, name_map: dict[str, str] | None = None) -> dict:
    sector = (getattr(t, "sector", None) or "").strip()
    row_label = (getattr(t, "row_label", None) or "").strip()
    seat = (getattr(t, "seat_number", None) or "").strip()
    location = " ".join([x for x in [sector, row_label, seat] if x]) or ("Numerada" if getattr(t, "is_numbered", False) else "Sin numerar")
    return {
        "id": str(t.id),
        "category_id": str(t.category_id),
        "category_name": (name_map or {}).get(str(t.category_id), "Categoría"),
        "status": t.status or "AVAILABLE",
        "status_label": _invitation_ticket_status_label(t.status),
        "status_class": _invitation_ticket_status_class(t.status),
        "code": t.ticket_code or t.pdf_name or "—",
        "pdf_url": t.pdf_url,
        "pdf_name": t.pdf_name or "",
        "sector": sector or "General",
        "row_label": row_label or "Sin fila",
        "seat_number": seat,
        "is_numbered": bool(getattr(t, "is_numbered", False)),
        "location": location,
        "assigned_label": t.assigned_label or "",
        "assigned_request_id": str(t.assigned_request_id) if getattr(t, "assigned_request_id", None) else "",
        "assigned_commitment_id": str(t.assigned_commitment_id) if getattr(t, "assigned_commitment_id", None) else "",
        "warning": t.previous_assignment_warning or "",
    }


def _invitation_ticket_groups(ticket_payloads: list[dict]) -> list[dict]:
    grouped: dict[str, dict[str, list[dict]]] = defaultdict(lambda: defaultdict(list))
    for item in ticket_payloads:
        grouped[item.get("sector") or "General"][item.get("row_label") or "Sin fila"].append(item)
    out = []
    for sector in sorted(grouped.keys(), key=lambda x: str(x).casefold()):
        rows = []
        for row_label in sorted(grouped[sector].keys(), key=lambda x: str(x).casefold()):
            seats = sorted(grouped[sector][row_label], key=lambda x: _safe_int(x.get("seat_number")) if str(x.get("seat_number") or "").isdigit() else 999999)
            numbered = [(_safe_int(s.get("seat_number")), s) for s in seats if str(s.get("seat_number") or "").isdigit()]
            non_numbered = [s for s in seats if not str(s.get("seat_number") or "").isdigit()]
            # Detección automática del patrón: si todas las butacas de la fila son de la misma
            # paridad (todas pares o todas impares) se numeran de 2 en 2 (pares/impares); si no,
            # correlativas. Así el plano muestra "butacas seguidas" sin inventar huecos de la
            # paridad contraria.
            step = 2 if (len(numbered) >= 2 and len({n % 2 for n, _ in numbered}) == 1 and (numbered[-1][0] - numbered[0][0]) >= 2) else 1
            visual = []
            last_num = None
            for num, seat in numbered:
                if last_num is not None:
                    diff = num - last_num
                    missing_slots = (diff // step) - 1 if (step and diff % step == 0) else 0
                    if missing_slots > 4:
                        visual.append({"type": "gap-large", "count": missing_slots})
                    elif missing_slots > 0:
                        m = last_num + step
                        while m < num:
                            visual.append({"type": "missing", "seat": m})
                            m += step
                visual.append({"type": "seat", "seat": seat})
                last_num = num
            for seat in non_numbered:
                visual.append({"type": "seat", "seat": seat})
            rows.append({"row_label": row_label, "seats": seats, "visual": visual, "step": step})
        out.append({"sector": sector, "rows": rows})
    return out


def _invitation_availability_breakdown(ticket_payloads: list[dict]) -> dict:
    """Disponibles de UNA categoría numerada agrupadas por sector y fila, con rangos de butacas
    seguidas (respetando el paso: pares/impares o correlativo)."""
    avail = [t for t in (ticket_payloads or []) if (t.get('status') or '') == 'AVAILABLE']
    by_sector: dict = defaultdict(lambda: defaultdict(list))
    for t in avail:
        by_sector[t.get('sector') or 'General'][t.get('row_label') or 'Sin fila'].append(t)
    sectors = []
    total = 0
    for sector in sorted(by_sector.keys(), key=lambda x: str(x).casefold()):
        rows = []
        sector_count = 0
        for row_label in sorted(by_sector[sector].keys(), key=lambda x: str(x).casefold()):
            seats = by_sector[sector][row_label]
            sector_count += len(seats)
            nums = sorted([_safe_int(t.get('seat_number')) for t in seats if str(t.get('seat_number') or '').isdigit()])
            step = 2 if (len(nums) >= 2 and len({n % 2 for n in nums}) == 1 and (nums[-1] - nums[0]) >= 2) else 1
            runs = []
            i = 0
            while i < len(nums):
                j = i
                while j + 1 < len(nums) and nums[j + 1] - nums[j] == step:
                    j += 1
                runs.append(str(nums[i]) if nums[i] == nums[j] else f'{nums[i]}-{nums[j]}')
                i = j + 1
            rows.append({'row_label': row_label, 'available': len(seats), 'runs': runs})
        sectors.append({'sector': sector, 'available': sector_count, 'rows': rows})
        total += sector_count
    return {'sectors': sectors, 'available_total': total}


def _invitation_split_pdf_pages(data: bytes) -> list[bytes]:
    """Divide un PDF en una lista de PDFs de una sola página (bytes), una entrada por página.

    Si pypdf no está disponible, el PDF tiene una sola página o no se puede leer/dividir, devuelve
    `[data]` (se trata como una única entrada, comportamiento previo)."""
    if not data:
        return []
    if not PYPDF_AVAILABLE or PdfReader is None or PdfWriter is None:
        return [data]
    try:
        reader = PdfReader(BytesIO(data))
        pages = list(reader.pages)
        if len(pages) <= 1:
            return [data]
        blobs = []
        for page in pages:
            writer = PdfWriter()
            writer.add_page(page)
            buf = BytesIO()
            writer.write(buf)
            blobs.append(buf.getvalue())
        return blobs
    except Exception:
        return [data]


def _invitation_extract_pdf_text_from_bytes(data: bytes) -> str:
    if not data or not PYPDF_AVAILABLE or PdfReader is None:
        return ""
    try:
        reader = PdfReader(BytesIO(data))
        parts = []
        for page in list(reader.pages)[:3]:
            try:
                parts.append(page.extract_text() or "")
            except Exception:
                continue
        return "\n".join(parts)
    except Exception:
        return ""


def _invitation_extract_ticket_metadata(data: bytes, filename: str | None = None) -> dict:
    text_value = _invitation_extract_pdf_text_from_bytes(data)
    haystack = "\n".join([filename or "", text_value or ""])
    compact = re.sub(r"[ \t]+", " ", haystack, flags=re.M)

    # Acota la detección de sector/fila/asiento a la zona de DATOS de la entrada (desde la primera
    # etiqueta tipo "Nombre:/Asiento:/Butaca:/Localidad:") para evitar el largo texto legal de
    # condiciones, que contiene palabras como "Lounge" o "filmar" que ensuciaban la detección.
    m_data = re.search(r"\b(?:nombre|asiento|butaca|localidad)\s*:", compact, flags=re.I)
    data_region = compact[m_data.start():] if m_data else compact

    def pick(patterns, text=None):
        src = compact if text is None else text
        for pattern in patterns:
            m = re.search(pattern, src, flags=re.I | re.M)
            if m:
                return (m.group(1) or "").strip(" :-#\t\r\n")
        return ""

    sector = pick([
        # Zonas con nombre propio ("Platea General", "Tribuna Alta"...): habitual cuando la etiqueta
        # y el valor quedan descolocados al extraer el texto. Las palabras extra se limitan a la misma
        # línea para no arrastrar texto contiguo.
        r"\b((?:platea|tribuna|grada|grader[ií]o|anfiteatro|palco|pista|lounge|patio|preferente)(?:[^\S\n]+(?:general|alta|baja|central|lateral|vip|[A-Z0-9][\wÁÉÍÓÚÜÑ]*)){0,2})\b",
        r"(?:sector|secci[oó]n|zona|bloque|block|grada|tribuna|platea|anfiteatro|palco|puerta|acceso|gate)\s*[:#\.\-]?\s*([A-Za-z0-9ÁÉÍÓÚÜÑ][\wÁÉÍÓÚÜÑ./-]{0,18})",
    ], data_region)
    row_label = pick([
        r"(?:\bfila\b|\brow\b|\bfil\.)\s*[:#\.\-]?\s*([A-Za-z0-9ÁÉÍÓÚÜÑ][\wÁÉÍÓÚÜÑ./-]{0,10})",
        # Valor ANTES de la etiqueta ("...20:00 14Fila:" -> 14).
        r"([0-9]{1,3}[A-Za-zÁÉÍÓÚÜÑ]?)\s*Fila\b",
    ], data_region)
    seat = pick([
        r"(?:asiento|butaca|seat)\s*[:#\.\-]?\s*([0-9]{1,5}[A-Za-z]?)",
        r"n[ºo°]?\.?\s*(?:asiento|butaca)\s*[:#\.\-]?\s*([0-9]{1,5}[A-Za-z]?)",
        # Número de asiento aislado en su línea antes de "Apertura de puertas" (valor descolocado).
        r"\n[ ]*([0-9]{1,4})[ ]*\n[ ]*Apertura",
    ], data_region)
    # Código de barras numérico (12-20 dígitos): es lo único realmente ÚNICO por entrada/butaca.
    barcode = pick([r"\b(\d{12,20})\b"])
    # "Localizador"/"Código" etiquetado: puede venir COMPARTIDO por todo el pedido (mismo en todas las
    # entradas), así que NO es fiable para deduplicar; solo se usa si no hay código de barras numérico.
    labeled_code = pick([
        r"(?:c[oó]digo(?:\s*de\s*barras)?|c[oó]d\.?|code|barcode|localizador|locator|n[ºo°]?\.?\s*entrada|ticket)\s*[:#\.\-]?\s*([A-Z0-9][A-Z0-9._/-]{4,64})",
    ])
    code = barcode or labeled_code or pick([r"\b([A-Z0-9]{10,})\b"])
    code_reliable = bool(barcode)
    if not code:
        code = (Path(filename or "").stem or hashlib.sha256(data or b"").hexdigest()[:16]).strip()
    return {
        "sector": sector[:80] or None,
        "row_label": row_label[:40] or None,
        "seat_number": seat[:20] or None,
        "ticket_code": code[:120] or None,
        "code_reliable": code_reliable,
        "raw_text": text_value[:4000] if text_value else "",
    }


def _invitation_assigned_qty_for_source(session_db, category_id, source_type: str, source_id) -> int:
    q = session_db.query(func.count(InvitationTicket.id)).filter(InvitationTicket.category_id == category_id)
    if source_type == "commitment":
        q = q.filter(InvitationTicket.assigned_commitment_id == source_id)
    else:
        q = q.filter(InvitationTicket.assigned_request_id == source_id)
    return int(q.scalar() or 0)


def _invitation_pending_assignment_payloads(session_db, concert: Concert, categories: list[InvitationCategory]) -> dict[str, list[dict]]:
    name_map = _invitation_category_name_map(categories)
    payload: dict[str, list[dict]] = {str(c.id): [] for c in categories}
    for commitment in session_db.query(InvitationCommitment).filter(InvitationCommitment.concert_id == concert.id).order_by(InvitationCommitment.created_at.asc()).all():
        quantities = _json_dict(commitment.quantities_json)
        for cid, qty in quantities.items():
            cat = next((c for c in categories if str(c.id) == str(cid)), None)
            if not cat:
                continue
            assigned = _invitation_assigned_qty_for_source(session_db, cat.id, "commitment", commitment.id)
            pending = max(_safe_int(qty) - assigned, 0)
            if pending <= 0:
                continue
            payload[str(cat.id)].append({
                "source_type": "commitment",
                "source_id": str(commitment.id),
                "name": commitment.name,
                "company": commitment.reason or "Compromiso",
                "photo_url": url_for("static", filename="img/placeholder_photo.png"),
                "requester": commitment.created_by_nick or "",
                "date_label": _invitation_display_datetime(commitment.created_at),
                "qty": pending,
                "qty_total": _safe_int(qty),
                "assigned": assigned,
                "category_id": str(cat.id),
                "category_name": name_map.get(str(cat.id), "Categoría"),
            })
    approved_statuses = {"APROBADAS", "ASIGNADAS"}
    for row in session_db.query(InvitationRequest).filter(InvitationRequest.concert_id == concert.id, InvitationRequest.status.in_(approved_statuses)).order_by(InvitationRequest.created_at.asc()).all():
        quantities = _json_dict(row.quantities_json)
        for cid, qty in quantities.items():
            cat = next((c for c in categories if str(c.id) == str(cid)), None)
            if not cat:
                continue
            assigned = _invitation_assigned_qty_for_source(session_db, cat.id, "request", row.id)
            pending = max(_safe_int(qty) - assigned, 0)
            if pending <= 0:
                continue
            payload[str(cat.id)].append({
                "source_type": "request",
                "source_id": str(row.id),
                "name": row.guest_name,
                "company": row.guest_company or "Petición aprobada",
                "photo_url": row.requester_photo_url or url_for("static", filename="img/placeholder_photo.png"),
                "requester": row.requester_nick or row.requester_email or "",
                "date_label": _invitation_display_datetime(row.created_at),
                "qty": pending,
                "qty_total": _safe_int(qty),
                "assigned": assigned,
                "category_id": str(cat.id),
                "category_name": name_map.get(str(cat.id), "Categoría"),
            })
    return payload


def _invitation_request_uses_only_guest_list(session_db, row: InvitationRequest) -> bool:
    quantities = _json_dict(row.quantities_json)
    if not quantities:
        return False
    categories = _invitation_get_categories(session_db, row.concert or session_db.get(Concert, row.concert_id), ensure_defaults=False) if row.concert_id else []
    cat_map = {str(c.id): c for c in categories}
    matched = False
    for cid, qty in quantities.items():
        if _safe_int(qty) <= 0:
            continue
        cat = cat_map.get(str(cid))
        if not cat or (cat.ticket_kind or "").upper() != "GUEST_LIST":
            return False
        matched = True
    return matched


def _invitation_quantities_from_form(form, categories: list[InvitationCategory] | None = None, prefix: str = "qty") -> dict:
    quantities: dict[str, int] = {}
    category_ids = [str(c.id) for c in (categories or [])]
    if category_ids:
        for cid in category_ids:
            val = _safe_int(form.get(f"{prefix}_{cid}"))
            if val > 0:
                quantities[cid] = val
    raw = form.get("quantities_json")
    if raw:
        for k, v in _json_dict(raw).items():
            val = _safe_int(v)
            if val > 0:
                quantities[str(k)] = val
    total = _safe_int(form.get(f"{prefix}_total") or form.get("qty_total"))
    if not quantities and total > 0:
        quantities["TOTAL"] = total
    return quantities


def _invitation_total_qty(quantities: dict | None) -> int:
    return sum(_safe_int(v) for v in (quantities or {}).values())


def _invitation_category_name_map(categories: list[InvitationCategory]) -> dict[str, str]:
    return {str(c.id): c.name for c in categories}


def _invitation_quantities_label(quantities: dict | None, name_map: dict[str, str] | None = None) -> str:
    q = quantities or {}
    if not q:
        return "0"
    pieces = []
    for cid, qty in q.items():
        qty = _safe_int(qty)
        if qty <= 0:
            continue
        name = (name_map or {}).get(str(cid)) or ("Total" if str(cid) == "TOTAL" else "Categoría")
        pieces.append(f"{name}: {qty}")
    return " · ".join(pieces) or "0"


def _invitation_status_badge(status: str | None) -> str:
    s = (status or "SOLICITADAS").upper()
    if s in {"APROBADAS", "ASIGNADAS", "ENVIADAS", "ENTREGADAS_MANO", "DISPONIBLES_TAQUILLA", "RECOGIDAS_TAQUILLA"}:
        return "success"
    if s in {"SOLICITADAS", "COMPROMETIDAS"}:
        return "warning text-dark"
    if s in {"RECHAZADAS", "ANULADAS"}:
        return "danger"
    return "secondary"


def _invitation_request_payload(row: InvitationRequest, categories: list[InvitationCategory] | None = None) -> dict:
    name_map = _invitation_category_name_map(categories or [])
    quantities = _json_dict(row.quantities_json)
    link_summary = _json_dict(getattr(row, "guest_link_summary", None))
    if not link_summary:
        try:
            link_summary = _promoter_link_summary(row._sa_instance_state.session, row.guest_promoter) if getattr(row, "guest_promoter", None) else {}
        except Exception:
            link_summary = {}
    return {
        "id": str(row.id),
        "guest_name": row.guest_name,
        "guest_company": row.guest_company or "",
        "guest_title": getattr(row, "guest_title", None) or row.guest_company or "",
        "guest_email": row.guest_email or "",
        "guest_phone": row.guest_phone or "",
        "requester_nick": row.requester_nick or row.requester_email or "—",
        "requester_photo_url": row.requester_photo_url or url_for("static", filename="img/placeholder_photo.png"),
        "receiver_mode": row.receiver_mode or "GUEST",
        "receiver_payload": _json_dict(row.receiver_payload),
        "quantities": quantities,
        "qty_total": _invitation_total_qty(quantities),
        "quantities_label": _invitation_quantities_label(quantities, name_map),
        "status": row.status or "SOLICITADAS",
        "status_label": INVITATION_STATUS_LABELS.get(row.status or "", row.status or "Solicitadas"),
        "status_badge": _invitation_status_badge(row.status),
        "link_summary": link_summary,
        "link_summary_text": _promoter_link_summary_text(link_summary),
        "note": row.note or "",
        "created_at_label": _invitation_display_datetime(row.created_at),
        "downloaded_at_label": _invitation_display_datetime(row.downloaded_at),
        "downloaded_count": _safe_int(row.downloaded_count),
        "can_edit_public": (row.status or "") in {"SOLICITADAS", "APROBADAS"},
        "download_url": url_for("invitation_request_download", token=row.delivery_token) if row.delivery_token else "",
        "download_url_abs": url_for("invitation_request_download", token=row.delivery_token, _external=True) if row.delivery_token else "",
        "created_by_nick": getattr(row, "created_by_nick", None) or "",
        "registered_by_other": bool(getattr(row, "created_by_user_id", None)) and str(getattr(row, "created_by_user_id", "") or "") != str(getattr(row, "requester_user_id", "") or ""),
    }


def _invitation_ficha_overview(session_db, concert, categories) -> list[dict]:
    """Compromisos y peticiones del evento agrupados por categoría para la ficha del concierto.

    Cada petición/compromiso aparece bajo cada categoría en la que tenga cantidad > 0; los que no
    encajan en ninguna van a un grupo 'Sin categoría'. Incluye foto y vínculo del invitado."""
    cat_objs = list(categories or [])
    cat_order = [str(c.id) for c in cat_objs]
    cat_name = {str(c.id): c.name for c in cat_objs}
    cat_kind = {str(c.id): (c.ticket_kind or 'PDF_UNNUMBERED') for c in cat_objs}
    groups = {cid: {"category_id": cid, "category_name": cat_name[cid], "ticket_kind": cat_kind[cid], "commitments": [], "requests": []} for cid in cat_order}
    sin = {"category_id": "", "category_name": "Sin categoría", "ticket_kind": "", "commitments": [], "requests": []}

    reqs = (
        session_db.query(InvitationRequest)
        .filter(InvitationRequest.concert_id == concert.id)
        .filter(InvitationRequest.status.notin_(['RECHAZADAS', 'ANULADAS']))
        .order_by(InvitationRequest.created_at.asc())
        .all()
    )
    for row in reqs:
        payload = _invitation_request_payload(row, cat_objs)
        quantities = payload.get("quantities") or {}
        placed = False
        for cid in cat_order:
            qty = _safe_int(quantities.get(cid))
            if qty > 0:
                item = dict(payload)
                item["qty"] = qty
                groups[cid]["requests"].append(item)
                placed = True
        if not placed:
            item = dict(payload)
            item["qty"] = payload.get("qty_total") or 0
            sin["requests"].append(item)

    for row in (
        session_db.query(InvitationCommitment)
        .filter(InvitationCommitment.concert_id == concert.id)
        .filter(InvitationCommitment.status != 'ANULADAS')
        .order_by(InvitationCommitment.created_at.asc())
        .all()
    ):
        quantities = _json_dict(row.quantities_json)
        base = {
            "id": str(row.id),
            "name": row.name,
            "reason": row.reason or "",
            "photo_url": (getattr(row.promoter, "logo_url", None) if getattr(row, "promoter", None) else None) or url_for("static", filename="img/placeholder_photo.png"),
        }
        placed = False
        for cid in cat_order:
            qty = _safe_int(quantities.get(cid))
            if qty > 0:
                item = dict(base)
                item["qty"] = qty
                groups[cid]["commitments"].append(item)
                placed = True
        if not placed:
            item = dict(base)
            item["qty"] = _invitation_total_qty(quantities)
            sin["commitments"].append(item)

    out = [groups[cid] for cid in cat_order]
    if sin["requests"] or sin["commitments"]:
        out.append(sin)
    return [g for g in out if g["requests"] or g["commitments"]]


def _invitation_event_cutoff_datetime(concert: Concert | None):
    """Devuelve el corte operativo de invitaciones: 05:00 del día posterior al evento.

    Las invitaciones deben seguir disponibles durante la madrugada posterior al concierto
    para permitir gestión en puerta/taquilla, pero no deben aparecer ni poder solicitarse
    cuando ya han pasado 5 horas desde el cierre del día del evento.
    """
    event_date = getattr(concert, "date", None)
    if not event_date:
        return None
    try:
        if isinstance(event_date, datetime):
            event_date = event_date.date()
        return datetime.combine(event_date + timedelta(days=1), datetime.min.time(), tzinfo=TZ_MADRID).replace(hour=5, minute=0, second=0, microsecond=0)
    except Exception:
        return None


def _invitation_event_is_active_for_requests(concert: Concert | None, *, now_value=None) -> bool:
    """Indica si un evento puede aparecer en Pedir/Gestionar invitaciones.

    Regla de negocio: desaparece 5 horas después del día del concierto/evento.
    """
    cutoff = _invitation_event_cutoff_datetime(concert)
    if not cutoff:
        return True
    now_value = now_value or _now_madrid()
    try:
        if getattr(now_value, "tzinfo", None) is None:
            now_value = now_value.replace(tzinfo=TZ_MADRID)
        return now_value < cutoff
    except Exception:
        return True


def _invitation_event_query_start_date() -> date:
    """Fecha mínima SQL amplia para no perder eventos de ayer antes de las 05:00."""
    now_value = _now_madrid()
    return now_value.date() - timedelta(days=1 if now_value.hour < 5 else 0)


def _invitation_concert_visible_for_user(concert: Concert | None) -> bool:
    """Oculta solicitudes personales 5h después del día del concierto/evento."""
    return _invitation_event_is_active_for_requests(concert)


def _user_is_ticketing(state: dict | None = None) -> bool:
    """True si el usuario actual pertenece al departamento de Ticketing."""
    state = state or _current_user_state()
    return any(str(d).strip().lower() == "ticketing" for d in (state.get("departments") or []))


def _concert_is_group_promoted(session_db, concert) -> bool:
    """True si una empresa del grupo participa como promotora (group_company_id) o como
    socio (ConcertCompanyShare) en el concierto/actividad."""
    if not concert:
        return False
    if getattr(concert, "group_company_id", None):
        return True
    cid = getattr(concert, "id", None)
    if not cid:
        return False
    try:
        return session_db.query(ConcertCompanyShare.id).filter(ConcertCompanyShare.concert_id == cid).first() is not None
    except Exception:
        return False


def _filter_manageable_concerts(session_db, concerts, state: dict | None = None) -> list:
    """Devuelve solo los conciertos que el usuario actual puede GESTIONAR en invitaciones.

    Criterio de negocio:
      - Rol 10 (dirección): todos.
      - Requiere acceso a 'invitaciones.gestionar'.
      - Producción (artistas asignados): conciertos de esos artistas cuyo promotor NO sea una
        empresa del grupo (sin group_company_id ni participación del grupo).
      - Ticketing: solo conciertos cuyo promotor SÍ sea una empresa del grupo (group_company_id
        o participación vía ConcertCompanyShare).
      - Además, los añadidos manualmente vía 'Gestionar otros' (opt-in), sin filtrar por grupo.
    """
    concerts = [c for c in (concerts or []) if c is not None]
    if not concerts:
        return []
    state = state or _current_user_state()
    if int(state.get("role") or 0) == 10:
        return list(concerts)
    if not _state_has_access(state, "invitaciones.gestionar", include_descendants=True):
        return []
    uid = _safe_uuid(state.get("user_id"))
    assigned = {str(x) for x in (state.get("assigned_artist_ids") or []) if x}
    is_ticketing = _user_is_ticketing(state)
    concert_ids = [c.id for c in concerts if getattr(c, "id", None)]
    opt_in_ids: set[str] = set()
    group_share_ids: set[str] = set()
    if uid and concert_ids:
        for (cid,) in (
            session_db.query(InvitationManagerOptIn.concert_id)
            .filter(InvitationManagerOptIn.user_id == uid, InvitationManagerOptIn.concert_id.in_(concert_ids))
            .all()
        ):
            opt_in_ids.add(str(cid))
    # Conciertos con participación de una empresa del grupo (socio). Junto con group_company_id
    # define "el promotor es una empresa del grupo". Se carga SIEMPRE: producción los excluye y
    # ticketing los incluye.
    if concert_ids:
        for (cid,) in (
            session_db.query(ConcertCompanyShare.concert_id)
            .filter(ConcertCompanyShare.concert_id.in_(concert_ids))
            .distinct()
            .all()
        ):
            group_share_ids.add(str(cid))
    out = []
    for c in concerts:
        cid = str(getattr(c, "id", "") or "")
        if cid and cid in opt_in_ids:
            out.append(c)
            continue
        is_group = bool(getattr(c, "group_company_id", None)) or (cid in group_share_ids)
        # Producción: conciertos de sus artistas asignados con promotor externo (no del grupo).
        if assigned and not is_group and (assigned & set(_concert_artist_ids(c))):
            out.append(c)
            continue
        # Ticketing: solo conciertos cuyo promotor es una empresa del grupo.
        if is_ticketing and is_group:
            out.append(c)
            continue
    return out


def _user_can_manage_invitations(concert, *, state: dict | None = None, session_db=None) -> bool:
    """Indica si el usuario actual puede gestionar las invitaciones de un concierto concreto."""
    if not concert:
        return False
    own = False
    if session_db is None:
        session_db = db()
        own = True
    try:
        return bool(_filter_manageable_concerts(session_db, [concert], state=state))
    finally:
        if own:
            session_db.close()


def _ensure_can_manage_invitations(session_db, concert):
    """Aborta con 403 si el usuario actual no puede gestionar las invitaciones del concierto.
    Refuerza server-side la restricción que la UI ya aplica (artistas asignados / Ticketing /
    'Gestionar otros' / dirección)."""
    if not concert or not _user_can_manage_invitations(concert, session_db=session_db):
        abort(403)


def _invitation_request_visible_for_user(row: InvitationRequest | None) -> bool:
    if not row or (row.status or "") in {"RECHAZADAS", "ANULADAS"}:
        return False
    return _invitation_concert_visible_for_user(getattr(row, "concert", None))


def _invitation_request_kind_flags(session_db, row: InvitationRequest, categories: list[InvitationCategory]) -> dict:
    quantities = _json_dict(getattr(row, "quantities_json", None))
    cat_map = {str(c.id): c for c in (categories or [])}
    kinds = []
    for cid, qty in quantities.items():
        if _safe_int(qty) <= 0:
            continue
        cat = cat_map.get(str(cid))
        if cat:
            kinds.append((cat.ticket_kind or "PDF_UNNUMBERED").upper())
    uses_guest_list = bool(kinds) and all(k == "GUEST_LIST" for k in kinds)
    requires_numbered_assignment = any(k == "PDF_NUMBERED" for k in kinds)
    assigned_or_sent = (getattr(row, "status", None) or "") in {"ASIGNADAS", "ENVIADAS", "ENTREGADAS_MANO", "DISPONIBLES_TAQUILLA", "RECOGIDAS_TAQUILLA"}
    return {
        "uses_guest_list": uses_guest_list,
        "requires_numbered_assignment": requires_numbered_assignment,
        "can_send": uses_guest_list or assigned_or_sent,
        "can_download_pdf": assigned_or_sent and not uses_guest_list,
        "can_auto_assign": not requires_numbered_assignment and (getattr(row, "status", None) or "") in {"SOLICITADAS", "APROBADAS"},
    }


def _invitation_parse_ticket_kind_and_guest_mode(raw_kind: str | None, fallback_kind: str | None = None, fallback_guest_mode: str | None = None) -> tuple[str, str | None]:
    value = (raw_kind or fallback_kind or "PDF_UNNUMBERED").strip().upper()
    if value in {"GUEST_LIST_BOX_OFFICE", "GUEST_LIST_TAQUILLA", "LIST_BOX_OFFICE"}:
        return "GUEST_LIST", "BOX_OFFICE"
    if value in {"GUEST_LIST_DOOR", "LIST_DOOR", "GUEST_LIST_ACCESS"}:
        return "GUEST_LIST", "DOOR"
    if value == "GUEST_LIST":
        mode = (fallback_guest_mode or "BOX_OFFICE").strip().upper()
        return "GUEST_LIST", mode if mode in {"BOX_OFFICE", "DOOR"} else "BOX_OFFICE"
    if value not in {"PDF_UNNUMBERED", "PDF_NUMBERED"}:
        value = "PDF_UNNUMBERED"
    return value, None


def _invitation_event_counts(session_db, concert: Concert) -> dict:
    categories = _invitation_get_categories(session_db, concert, ensure_defaults=False)
    category_total = sum(_safe_int(c.qty_contract) + _safe_int(c.qty_extra) for c in categories)
    if not categories:
        for row in _invitation_category_legacy_rows(concert):
            category_total += _safe_int(row.get("qty_contract"))
    commitments = session_db.query(InvitationCommitment).filter(InvitationCommitment.concert_id == concert.id).filter(InvitationCommitment.status != "ANULADAS").all()
    requests = session_db.query(InvitationRequest).filter(InvitationRequest.concert_id == concert.id).all()
    committed = sum(_invitation_total_qty(_json_dict(x.quantities_json)) for x in commitments)
    requested = sum(_invitation_total_qty(_json_dict(x.quantities_json)) for x in requests if (x.status or "") in INVITATION_PENDING_COUNT_STATUSES)
    assigned = sum(_invitation_total_qty(_json_dict(x.quantities_json)) for x in requests if (x.status or "") in {"ASIGNADAS", "ENVIADAS", "ENTREGADAS_MANO", "DISPONIBLES_TAQUILLA", "RECOGIDAS_TAQUILLA"})
    return {
        "configured": category_total,
        "committed": committed,
        "requested": requested,
        "assigned": assigned,
        "result": category_total - committed - requested - assigned,
    }


def _invitation_configured_concert_query(session_db):
    query_start = _invitation_event_query_start_date()
    return (
        session_db.query(Concert)
        .options(joinedload(Concert.artist), joinedload(Concert.venue))
        .filter(or_(Concert.date == None, Concert.date >= query_start))  # noqa: E711
        .order_by(Concert.date.asc().nullslast(), Concert.created_at.desc())
    )


def _invitation_event_has_config(session_db, concert: Concert) -> bool:
    if session_db.query(InvitationCategory.id).filter(InvitationCategory.concert_id == concert.id).first():
        return True
    if _invitation_category_legacy_rows(concert):
        rows = _invitation_category_legacy_rows(concert)
        return any(_safe_int(r.get("qty_contract")) > 0 for r in rows)
    return False


def _invitation_delivery_recipients(row: InvitationRequest) -> list[str]:
    payload = _json_dict(row.receiver_payload)
    values = []
    mode = (row.receiver_mode or "GUEST").upper()
    if mode == "GUEST":
        values.extend([row.guest_email])
    elif mode == "ME":
        values.extend([row.requester_email])
    elif mode == "OTHER":
        values.extend([payload.get("email")])
    elif mode in {"BOX_OFFICE", "DOOR"}:
        values.extend([row.guest_email, row.requester_email])
    return _dedupe_valid_email_addresses(values)


def _invitation_receiver_text(row: InvitationRequest) -> str:
    payload = _json_dict(row.receiver_payload)
    mode = (row.receiver_mode or "GUEST").upper()
    labels = {
        "GUEST": "Enviar al invitado",
        "BOX_OFFICE": "Dejar en taquilla",
        "ME": "Enviar a mí",
        "OTHER": "Enviar a otro",
        "DOOR": "Acceso por puerta",
    }
    base = labels.get(mode, mode)
    if mode == "OTHER":
        target = " · ".join([x for x in [payload.get("name"), payload.get("email"), payload.get("phone")] if x])
        return f"{base}: {target}" if target else base
    return base


def _invitation_parse_deadline(value: str | None):
    raw = (value or "").strip()
    if not raw:
        return None
    try:
        if "T" in raw:
            return datetime.fromisoformat(raw)
        return datetime.strptime(raw, "%Y-%m-%d %H:%M")
    except Exception:
        try:
            return datetime.strptime(raw, "%Y-%m-%d")
        except Exception:
            return None


def _invitation_link_state(link: InvitationPublicLink) -> tuple[str, str]:
    if (link.status or "").upper() == "CANCELLED":
        return "cancelled", "Este enlace ha sido anulado y ya no está disponible. Por favor contacte con quien se lo ha enviado."
    try:
        concert = getattr(link, "concert", None)
        if concert is not None and not _invitation_event_is_active_for_requests(concert):
            return "expired", "Lo sentimos, este concierto o evento ya ha pasado y no admite nuevas peticiones de invitaciones."
    except Exception:
        pass
    if link.deadline_at:
        try:
            deadline = link.deadline_at
            if getattr(deadline, "tzinfo", None) is None:
                deadline = deadline.replace(tzinfo=TZ_MADRID)
            if deadline < _now_madrid():
                return "expired", "Lo sentimos, el plazo para realizar peticiones ya ha finalizado."
        except Exception:
            pass
    return "active", ""


def _invitation_public_limits(link: InvitationPublicLink, categories: list[InvitationCategory], requests: list[InvitationRequest] | None = None) -> dict:
    category_limits = _json_dict(link.category_limits_json)
    enabled = set(str(x) for x in _json_list(link.categories_enabled_json))
    used_total = 0
    used_by_category = defaultdict(int)
    for row in requests or []:
        if (row.status or "") in INVITATION_FINAL_STATUSES:
            continue
        q = _json_dict(row.quantities_json)
        used_total += _invitation_total_qty(q)
        for cid, qty in q.items():
            used_by_category[str(cid)] += _safe_int(qty)
    rows = []
    for cat in categories:
        cid = str(cat.id)
        if link.limit_mode == "CATEGORIES" and cid not in category_limits:
            continue
        if link.limit_mode == "NONE" and enabled and cid not in enabled:
            continue
        limit = _safe_int(category_limits.get(cid), None) if link.limit_mode == "CATEGORIES" else None
        if limit is not None and limit <= 0:
            continue
        rows.append({
            "id": cid,
            "name": cat.name,
            "limit": limit,
            "used": used_by_category.get(cid, 0),
            "available": None if limit is None else max(limit - used_by_category.get(cid, 0), 0),
        })
    total_limit = _safe_int(link.total_limit) if link.limit_mode == "TOTAL" else None
    return {"categories": rows, "total_limit": total_limit, "used_total": used_total, "available_total": None if total_limit is None else max(total_limit - used_total, 0)}


def _invitation_upsert_category_rows_from_request(session_db, concert: Concert, form) -> list[InvitationCategory]:
    categories = _invitation_get_categories(session_db, concert, ensure_defaults=True)
    return categories


def _invitation_artist_options(session_db) -> list[dict]:
    rows = session_db.query(Artist).order_by(Artist.name.asc()).all()
    return [_artist_chip_payload(a) for a in rows]


def _invitation_event_artist_options(session_db) -> list[dict]:
    """Artistas con al menos un concierto/festival/evento vigente para solicitudes de
    invitaciones (de hoy en adelante, o aún sin fecha asignada).

    Se usa en el paso "Selecciona artista" de Pedir invitaciones (alta interna y enlace),
    para no ofrecer artistas cuyas actividades ya pasaron ni los que no tienen ninguna.
    Mismo criterio de vigencia que el listado de eventos del módulo: actividad sin fecha
    asignada (TBD) o con fecha >= hoy (vía `_invitation_event_query_start_date`), más la
    regla de las 5 h (`_invitation_event_is_active_for_requests`). Solo selecciona las
    columnas necesarias para no cargar los payloads JSONB pesados del concierto.
    """
    query_start = _invitation_event_query_start_date()
    now_value = _now_madrid()
    wanted_ids = set()
    for row in (
        session_db.query(Concert.id, Concert.date, Concert.artist_id, Concert.artist_ids)
        .filter(or_(Concert.date == None, Concert.date >= query_start))  # noqa: E711
        .all()
    ):
        if not _invitation_event_is_active_for_requests(row, now_value=now_value):
            continue
        for aid in _concert_artist_ids(row):
            if aid:
                wanted_ids.add(aid)
    if not wanted_ids:
        return []
    uuids = [u for u in (_safe_uuid(a) for a in wanted_ids) if u]
    if not uuids:
        return []
    rows = session_db.query(Artist).filter(Artist.id.in_(uuids)).order_by(Artist.name.asc()).all()
    return [_artist_chip_payload(a) for a in rows]


def _invitation_personnel_options(session_db) -> list[dict]:
    rows = (
        session_db.query(User, UserProfile)
        .outerjoin(UserProfile, UserProfile.user_id == User.id)
        .order_by(User.email.asc())
        .all()
    )
    out = []
    for user, profile in rows:
        name = _profile_full_name(profile) if profile else ""
        nick = getattr(profile, "nick", None) if profile else None
        out.append({
            "id": str(user.id),
            "name": name or nick or user.email,
            "email": user.email,
            "photo_url": (getattr(profile, "photo_url", None) if profile else None) or url_for("static", filename="img/placeholder_photo.png"),
        })
    return out


def _invitation_promoter_payload(promoter: Promoter | None) -> dict:
    return {
        "id": str(getattr(promoter, "id", "") or ""),
        "name": _promoter_display_name(promoter) if promoter else "",
        "email": getattr(promoter, "contact_email", None) or "",
        "phone": getattr(promoter, "contact_phone", None) or "",
        "photo_url": getattr(promoter, "logo_url", None) or url_for("static", filename="img/placeholder_photo.png"),
    }


def _invitation_public_link_url(link: InvitationPublicLink) -> str:
    return _external_url_for("public_invitation_request_link", token=link.token)


def _invitation_request_download_url(row: InvitationRequest) -> str:
    if not row.delivery_token:
        row.delivery_token = _invitation_token()
    return _external_url_for("invitation_request_download", token=row.delivery_token)


def _build_invitation_request_pdf(session_db, row: InvitationRequest) -> bytes:
    concert = row.concert or session_db.get(Concert, row.concert_id)
    categories = _invitation_get_categories(session_db, concert, ensure_defaults=False) if concert else []
    name_map = _invitation_category_name_map(categories)
    buffer = BytesIO()
    if not REPORTLAB_AVAILABLE:
        text_body = f"Invitaciones\n\n{row.guest_name}\n{_invitation_quantities_label(_json_dict(row.quantities_json), name_map)}"
        return text_body.encode("utf-8")
    doc = SimpleDocTemplate(buffer, pagesize=A4, rightMargin=36, leftMargin=36, topMargin=36, bottomMargin=36)
    styles = getSampleStyleSheet()
    title_style = ParagraphStyle("InvitationTitle", parent=styles["Title"], alignment=TA_CENTER, fontSize=20, spaceAfter=14)
    normal = styles["BodyText"]
    story = []
    story.append(Paragraph("Invitaciones", title_style))
    if concert:
        event = _invitation_event_payload(session_db, concert)
        info = [
            ["Evento", html.escape(event["type_label"] + " · " + (event["title"] or ""))],
            ["Artista", html.escape(event["artist_names"] or "—")],
            ["Fecha", html.escape(event["date_label"] or "—")],
            ["Hora", html.escape(event.get("show_time") or "—")],
            ["Recinto", html.escape(event.get("venue") or "—")],
            ["Ciudad", html.escape(" · ".join([x for x in [event.get("city"), event.get("province")] if x]) or "—")],
        ]
        tbl = Table(info, colWidths=[90, 360])
        tbl.setStyle(TableStyle([
            ("BACKGROUND", (0, 0), (0, -1), colors.whitesmoke),
            ("BOX", (0, 0), (-1, -1), 0.5, colors.lightgrey),
            ("INNERGRID", (0, 0), (-1, -1), 0.25, colors.lightgrey),
            ("VALIGN", (0, 0), (-1, -1), "TOP"),
        ]))
        story.append(tbl)
        story.append(Spacer(1, 14))
    quantities = _json_dict(row.quantities_json)
    story.append(Paragraph(f"Buenas, te adjunto {row.guest_name and html.escape(row.guest_name) or 'las invitaciones'}.", normal))
    story.append(Spacer(1, 8))
    story.append(Paragraph(f"<b>Invitaciones:</b> {html.escape(_invitation_quantities_label(quantities, name_map))}", normal))
    story.append(Paragraph(f"<b>Estado:</b> {html.escape(INVITATION_STATUS_LABELS.get(row.status or '', row.status or ''))}", normal))
    receiver = _invitation_receiver_text(row)
    if receiver:
        story.append(Paragraph(f"<b>Entrega:</b> {html.escape(receiver)}", normal))
    assigned = (
        session_db.query(InvitationTicket)
        .filter(InvitationTicket.assigned_request_id == row.id)
        .order_by(InvitationTicket.sector.asc().nullslast(), InvitationTicket.row_label.asc().nullslast(), InvitationTicket.seat_number.asc().nullslast())
        .all()
    )
    if assigned:
        story.append(Spacer(1, 12))
        story.append(Paragraph("<b>Entradas asignadas</b>", normal))
        data = [["Categoría", "Localización", "Código"]]
        cat_map = {str(c.id): c.name for c in categories}
        for t in assigned:
            loc = " ".join([x for x in [t.sector, t.row_label, t.seat_number] if x]) or "Sin numerar"
            code = t.ticket_code or t.pdf_name or "—"
            data.append([cat_map.get(str(t.category_id), "Categoría"), loc, code])
        table = Table(data, colWidths=[140, 160, 190])
        table.setStyle(TableStyle([
            ("BACKGROUND", (0, 0), (-1, 0), colors.whitesmoke),
            ("GRID", (0, 0), (-1, -1), 0.25, colors.lightgrey),
            ("VALIGN", (0, 0), (-1, -1), "TOP"),
        ]))
        story.append(table)
    story.append(Spacer(1, 18))
    story.append(Paragraph("Importante: todas las invitaciones quedan sujetas a las indicaciones de organización, taquilla o puerta.", normal))
    doc.build(story)
    return buffer.getvalue()


def _invitation_email_body(session_db, row: InvitationRequest, download_url: str | None = None) -> tuple[str, str, str]:
    concert = row.concert or session_db.get(Concert, row.concert_id)
    event = _invitation_event_payload(session_db, concert) if concert else {}
    qty = _invitation_total_qty(_json_dict(row.quantities_json))
    inv_text = "la invitación" if qty == 1 else f"{qty} invitaciones"
    event_desc = " · ".join([x for x in [event.get("type_label"), event.get("artist_names"), event.get("date_label"), event.get("city"), event.get("venue")] if x])
    subject = f"Invitaciones {event_desc}".strip()
    logo = url_for("static", filename="img/logo.png", _external=True)
    is_guest_list = _invitation_request_uses_only_guest_list(session_db, row)
    if is_guest_list:
        mode = "en taquilla" if (row.receiver_mode or '').upper() == 'BOX_OFFICE' else "en puerta"
        body_main = f"Se han confirmado {html.escape(inv_text)} para {html.escape(row.guest_name or 'el invitado')}. Podrá recogerlas {mode} o acceder indicando su nombre en lista, según la configuración del evento."
        html_body = f"""
        <div style="font-family:Arial,sans-serif;color:#111;line-height:1.45;max-width:720px;margin:0 auto">
          <div style="text-align:right;margin-bottom:18px"><img src="{logo}" style="max-height:58px;max-width:180px" alt="Logo"></div>
          <h2 style="text-align:center;margin:0 0 18px">Invitaciones</h2>
          <p>Buenas{(' ' + html.escape(row.guest_name)) if row.guest_name else ''},</p>
          <p>{body_main}</p>
          <p><b>Evento:</b> {html.escape(event_desc)}</p>
          <p style="font-size:13px;color:#555">Gestionado por: {html.escape(row.requester_nick or row.requester_email or '')}</p>
        </div>
        """
        text_body = f"Buenas {row.guest_name or ''}, se han confirmado {inv_text} para {event_desc}. Podrá recogerlas {mode} o acceder indicando su nombre en lista. Gestionado por: {row.requester_nick or row.requester_email or ''}"
        return subject, html_body, text_body

    download_url = download_url or _invitation_request_download_url(row)
    html_body = f"""
    <div style="font-family:Arial,sans-serif;color:#111;line-height:1.45;max-width:720px;margin:0 auto">
      <div style="text-align:right;margin-bottom:18px"><img src="{logo}" style="max-height:58px;max-width:180px" alt="Logo"></div>
      <h2 style="text-align:center;margin:0 0 18px">Invitaciones</h2>
      <p>Buenas{(' ' + html.escape(row.guest_name)) if row.guest_name else ''},</p>
      <p>Te adjunto {html.escape(inv_text)} para {html.escape(event.get('type_label') or 'el evento')} de <b>{html.escape(event.get('artist_names') or '')}</b>{(' el ' + html.escape(event.get('date_label') or '')) if event.get('date_label') else ''}{(' a las ' + html.escape(event.get('show_time') or '')) if event.get('show_time') else ''}{(' en ' + html.escape(event.get('venue') or '')) if event.get('venue') else ''}{(' en ' + html.escape(event.get('city') or '')) if event.get('city') else ''}.</p>
      <p style="text-align:center;margin:26px 0"><a href="{html.escape(download_url)}" style="background:#e83b4b;color:#fff;text-decoration:none;padding:13px 22px;border-radius:12px;font-weight:700;display:inline-block">Descargar invitaciones</a></p>
      <p style="font-size:13px;color:#555">Gestionado por: {html.escape(row.requester_nick or row.requester_email or '')}</p>
    </div>
    """
    text_body = f"Buenas {row.guest_name or ''}, te adjunto invitaciones para {event_desc}. Descargar invitaciones: {download_url}\nGestionado por: {row.requester_nick or row.requester_email or ''}"
    return subject, html_body, text_body



def _invitation_event_logo_url(session_db, concert: Concert | None, external: bool = True) -> str:
    if concert:
        for company in (getattr(concert, "billing_company", None), getattr(concert, "group_company", None)):
            logo = (getattr(company, "logo_url", None) or "").strip()
            if logo:
                return logo
    return (_treinta_y_tres_logo_url(session_db) if "_treinta_y_tres_logo_url" in globals() else "") or url_for("static", filename="img/logo.png", _external=external)


def _invitation_list_type_label(value: str | None) -> str:
    key = (value or "COMPLETE").strip().upper()
    return {"COMPLETE": "Listado completo", "DOOR": "Listado de puerta", "BOX_OFFICE": "Listado de taquilla"}.get(key, "Listado completo")


def _invitation_request_list_kind(session_db, row: InvitationRequest, categories: list[InvitationCategory]) -> set[str]:
    modes = set()
    quantities = _json_dict(row.quantities_json)
    cat_map = {str(c.id): c for c in categories}
    for cid, qty in quantities.items():
        if _safe_int(qty) <= 0:
            continue
        cat = cat_map.get(str(cid))
        if cat and (cat.ticket_kind or '').upper() == 'GUEST_LIST':
            modes.add((cat.guest_list_mode or 'BOX_OFFICE').upper())
    rm = (row.receiver_mode or '').upper()
    if rm in {'BOX_OFFICE', 'DOOR'}:
        modes.add('DOOR' if rm == 'DOOR' else 'BOX_OFFICE')
    if (row.status or '') in {'DISPONIBLES_TAQUILLA', 'RECOGIDAS_TAQUILLA'}:
        modes.add('BOX_OFFICE')
    if not modes:
        modes.add('COMPLETE')
    return modes


def _invitation_guest_list_rows(session_db, concert: Concert, list_type: str | None = 'COMPLETE') -> list[dict]:
    list_type = (list_type or 'COMPLETE').strip().upper()
    categories = _invitation_get_categories(session_db, concert, ensure_defaults=False)
    rows = []
    valid_statuses = {'APROBADAS', 'ASIGNADAS', 'ENVIADAS', 'ENTREGADAS_MANO', 'DISPONIBLES_TAQUILLA', 'RECOGIDAS_TAQUILLA'}
    query = (session_db.query(InvitationRequest)
             .options(joinedload(InvitationRequest.guest_promoter))
             .filter(InvitationRequest.concert_id == concert.id, InvitationRequest.status.in_(valid_statuses))
             .order_by(InvitationRequest.guest_name.asc().nullslast(), InvitationRequest.created_at.asc()))
    for row in query.all():
        modes = _invitation_request_list_kind(session_db, row, categories)
        if list_type == 'DOOR' and 'DOOR' not in modes:
            continue
        if list_type == 'BOX_OFFICE' and 'BOX_OFFICE' not in modes:
            continue
        payload = _invitation_request_payload(row, categories)
        flags = _invitation_request_kind_flags(session_db, row, categories)
        payload.update(flags)
        payload['list_modes'] = list(modes)
        payload['list_type'] = 'DOOR' if 'DOOR' in modes else ('BOX_OFFICE' if 'BOX_OFFICE' in modes else 'COMPLETE')
        payload['list_type_label'] = _invitation_list_type_label(payload['list_type'])
        payload['show_check'] = list_type in {'DOOR', 'BOX_OFFICE'} or payload['list_type'] in {'DOOR', 'BOX_OFFICE'}
        payload['download_url'] = _invitation_request_download_url(row) if flags.get('can_download_pdf') else payload.get('download_url')
        rows.append(payload)
    rows.sort(key=lambda x: _invitation_normalize_search(x.get('guest_name') or ''))
    return rows


def _build_invitation_guest_list_pdf(session_db, concert: Concert, list_type: str | None = 'COMPLETE') -> bytes:
    rows = _invitation_guest_list_rows(session_db, concert, list_type)
    event = _invitation_event_payload(session_db, concert)
    if not REPORTLAB_AVAILABLE:
        lines = ["Invitados", _invitation_list_type_label(list_type), " · ".join([x for x in [event.get('artist_names'), event.get('date_label'), event.get('venue'), event.get('city')] if x]), ""]
        for r in rows:
            lines.append(f"{r.get('guest_name','')} | {r.get('link_summary_text','')} | {r.get('guest_title','')} | {r.get('quantities_label','')} | {r.get('status_label','')}")
        return "\n".join(lines).encode('utf-8')
    buf = BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4, leftMargin=34, rightMargin=34, topMargin=34, bottomMargin=34)
    styles = getSampleStyleSheet()
    title_style = ParagraphStyle('InvGuestTitle', parent=styles['Title'], alignment=TA_CENTER, fontSize=18, leading=22)
    small = ParagraphStyle('InvGuestSmall', parent=styles['Normal'], fontSize=8, leading=10)
    normal = ParagraphStyle('InvGuestNormal', parent=styles['Normal'], fontSize=9, leading=11)
    story = []
    logo_cell = ''
    logo_url = _invitation_event_logo_url(session_db, concert)
    if logo_url:
        try:
            logo_cell = _rl_image_flowable_from_url(logo_url, 3.1, 1.25) or ''
        except Exception:
            logo_cell = ''
    header_text = '<br/>'.join([html.escape(x) for x in [event.get('artist_names'), event.get('type_label'), event.get('date_label'), event.get('venue'), event.get('city')] if x])
    header = Table([[Paragraph(header_text or 'Evento', normal), logo_cell]], colWidths=[360, 120])
    header.setStyle(TableStyle([('VALIGN',(0,0),(-1,-1),'TOP'), ('ALIGN',(1,0),(1,0),'RIGHT')]))
    story.extend([header, Spacer(1, 10), Paragraph('Invitados', title_style), Paragraph(html.escape(_invitation_list_type_label(list_type)), ParagraphStyle('InvGuestSub', parent=small, alignment=TA_CENTER)), Spacer(1, 12)])
    data = [[Paragraph('<b>Invitado</b>', small), Paragraph('<b>Vinculación</b>', small), Paragraph('<b>Título</b>', small), Paragraph('<b>Categoría / nº</b>', small), Paragraph('<b>Estado</b>', small), Paragraph('<b>Check</b>', small)]]
    for r in rows:
        check = '☐' if (list_type or '').upper() in {'DOOR','BOX_OFFICE'} or r.get('show_check') else ''
        status = '' if (r.get('status') == 'APROBADAS') else (r.get('status_label') or '')
        data.append([
            Paragraph(html.escape(r.get('guest_name') or ''), normal),
            Paragraph(html.escape(r.get('link_summary_text') or ''), normal),
            Paragraph(html.escape(r.get('guest_title') or ''), normal),
            Paragraph(html.escape(r.get('quantities_label') or ''), normal),
            Paragraph(html.escape(status), normal),
            Paragraph(check, normal),
        ])
    table = Table(data, colWidths=[105, 90, 85, 105, 70, 30], repeatRows=1)
    table.setStyle(TableStyle([('GRID',(0,0),(-1,-1),0.25,colors.HexColor('#d9dee6')),('BACKGROUND',(0,0),(-1,0),colors.HexColor('#f3f4f6')),('VALIGN',(0,0),(-1,-1),'TOP'),('ROWBACKGROUNDS',(0,1),(-1,-1),[colors.white, colors.HexColor('#fbfcfd')])]))
    story.append(table)
    doc.build(story)
    return buf.getvalue()

def _invitation_rejection_email_body(session_db, row: InvitationRequest, reason: str | None = None) -> tuple[str, str, str]:
    concert = row.concert or session_db.get(Concert, row.concert_id)
    event = _invitation_event_payload(session_db, concert) if concert else {}
    subject = f"Solicitud de invitaciones rechazada · {event.get('artist_names') or event.get('title') or ''}".strip(" ·")
    html_body = f"""
    <div style="font-family:Arial,sans-serif;line-height:1.45;color:#111">
      <h2>Solicitud de invitaciones rechazada</h2>
      <p>La solicitud de invitaciones para <b>{html.escape(row.guest_name or '')}</b> ha sido rechazada.</p>
      <p><b>Evento:</b> {html.escape(' · '.join([x for x in [event.get('type_label'), event.get('artist_names'), event.get('date_label'), event.get('city'), event.get('venue')] if x]))}</p>
      {f'<p><b>Motivo:</b> {html.escape(reason)}</p>' if reason else ''}
    </div>
    """
    text_body = f"La solicitud de invitaciones para {row.guest_name or ''} ha sido rechazada. {reason or ''}"
    return subject, html_body, text_body


@app.get('/invitaciones', endpoint='invitations_view')
@admin_required
def invitations_view():
    tab = (request.args.get('tab') or 'pedir').strip().lower()
    if tab == 'mis':
        tab = 'pedir'
    if tab not in {'pedir', 'gestionar'}:
        tab = 'pedir'
    session_db = db()
    try:
        artists = _invitation_artist_options(session_db)
        event_artists = _invitation_event_artist_options(session_db)
        personnel = _invitation_personnel_options(session_db)
        query_start = _invitation_event_query_start_date()
        query = (
            session_db.query(Concert)
            .options(joinedload(Concert.artist), joinedload(Concert.venue))
            .filter(or_(Concert.date == None, Concert.date >= query_start))  # noqa: E711
            .order_by(Concert.date.asc().nullslast(), Concert.created_at.desc())
            .limit(160)
        )
        now_value = _now_madrid()
        candidates = []
        for concert in query.all():
            if not _invitation_event_is_active_for_requests(concert, now_value=now_value):
                continue
            # Se incluyen TODOS los conciertos activos (tengan o no invitaciones configuradas o
            # solicitudes); en "Gestionar" el filtrado por perfil (artistas asignados no-grupo /
            # ticketing con empresa del grupo) lo hace _filter_manageable_concerts más abajo.
            candidates.append(concert)
        # En "Gestionar" cada usuario solo ve lo que le corresponde (artistas asignados; Ticketing ->
        # empresas del grupo; opt-ins de "Gestionar otros"). Dirección (rol 10) ve todo.
        if tab == 'gestionar':
            candidates = _filter_manageable_concerts(session_db, candidates, state=_current_user_state())
        events = [_invitation_event_payload(session_db, c, include_counts=True) for c in candidates]
        # Agrupado por artista para la pestaña Gestionar: un grupo por artista, en orden de aparición
        # (el del evento más próximo primero, porque `events` ya viene cronológico) y eventos
        # cronológicos dentro de cada grupo.
        events_by_artist = []
        if tab == 'gestionar':
            _agroups = {}
            for ev in events:
                arts = ev.get('artists') or [{'id': '', 'name': 'Sin artista', 'photo_url': None}]
                for a in arts:
                    akey = str(a.get('id') or a.get('name') or '')
                    grp = _agroups.get(akey)
                    if grp is None:
                        grp = {'artist': a, 'events': []}
                        _agroups[akey] = grp
                        events_by_artist.append(grp)
                    grp['events'].append(ev)
        current_user_id = _safe_uuid(session.get('user_id'))
        my_requests = []
        my_denied_count = 0
        show_denied = _truthy(request.args.get('show_denied'))
        if current_user_id:
            base_q = (
                session_db.query(InvitationRequest)
                .options(joinedload(InvitationRequest.concert))
                .filter(InvitationRequest.requester_user_id == current_user_id)
                .order_by(InvitationRequest.created_at.desc())
                .limit(180)
            )
            rows = base_q.all()
            for row in rows:
                if not _invitation_concert_visible_for_user(row.concert):
                    continue
                is_denied = (row.status or '') in {'RECHAZADAS', 'ANULADAS'}
                if is_denied:
                    my_denied_count += 1
                    if not show_denied:
                        continue
                concert = row.concert
                cats = _invitation_get_categories(session_db, concert, ensure_defaults=False) if concert else []
                item = _invitation_request_payload(row, cats)
                item['event'] = _invitation_event_payload(session_db, concert) if concert else {}
                item['is_denied'] = is_denied
                my_requests.append(item)
                if len(my_requests) >= 120:
                    break
        return render_template(
            'invitaciones.html',
            tab=tab,
            artists=artists,
            event_artists=event_artists,
            personnel=personnel,
            events=events,
            events_by_artist=events_by_artist,
            my_requests=my_requests,
            my_denied_count=my_denied_count,
            show_denied=show_denied,
            category_types=INVITATION_CATEGORY_TYPES,
            guest_list_modes=INVITATION_GUEST_LIST_MODES,
            status_labels=INVITATION_STATUS_LABELS,
        )
    finally:
        session_db.close()


@app.get('/api/invitaciones/gestionar-otros/artistas', endpoint='api_invitation_manage_others_artists')
@admin_required
def api_invitation_manage_others_artists():
    """Artistas con actividades futuras que el usuario NO gestiona todavía ('Gestionar otros')."""
    state = _current_user_state()
    session_db = db()
    try:
        if int(state.get('role') or 0) != 10 and not _state_has_access(state, 'invitaciones.gestionar', include_descendants=True):
            return jsonify({'ok': False, 'artists': []}), 403
        query_start = _invitation_event_query_start_date()
        now_value = _now_madrid()
        concerts = (
            session_db.query(Concert)
            .options(joinedload(Concert.artist))
            .filter(or_(Concert.date == None, Concert.date >= query_start))  # noqa: E711
            .order_by(Concert.date.asc().nullslast(), Concert.created_at.desc())
            .limit(400)
            .all()
        )
        active = [c for c in concerts if _invitation_event_is_active_for_requests(c, now_value=now_value)]
        managed_ids = {str(c.id) for c in _filter_manageable_concerts(session_db, active, state=state)}
        not_managed = [c for c in active if str(c.id) not in managed_ids]
        counts: dict[str, int] = {}
        for c in not_managed:
            for aid in _concert_artist_ids(c):
                if aid:
                    counts[aid] = counts.get(aid, 0) + 1
        if not counts:
            return jsonify({'ok': True, 'artists': []})
        uuids = [u for u in (_safe_uuid(a) for a in counts.keys()) if u]
        rows = session_db.query(Artist).filter(Artist.id.in_(uuids)).all() if uuids else []
        artists = []
        for a in rows:
            payload = _artist_chip_payload(a)
            payload['activity_count'] = counts.get(str(a.id), 0)
            artists.append(payload)
        artists.sort(key=lambda x: (-x['activity_count'], (x.get('name') or '').lower()))
        return jsonify({'ok': True, 'artists': artists})
    finally:
        session_db.close()


@app.get('/api/invitaciones/gestionar-otros/artista/<artist_id>/actividades', endpoint='api_invitation_manage_others_activities')
@admin_required
def api_invitation_manage_others_activities(artist_id):
    """Actividades futuras de un artista que el usuario aún no gestiona."""
    state = _current_user_state()
    aid = _safe_uuid(artist_id)
    session_db = db()
    try:
        if not aid:
            return jsonify({'ok': False, 'events': []}), 400
        query_start = _invitation_event_query_start_date()
        now_value = _now_madrid()
        concerts = (
            session_db.query(Concert)
            .options(joinedload(Concert.artist), joinedload(Concert.venue))
            .filter(or_(Concert.date == None, Concert.date >= query_start))  # noqa: E711
            .order_by(Concert.date.asc().nullslast(), Concert.created_at.desc())
            .limit(400)
            .all()
        )
        active = [c for c in concerts if _invitation_event_is_active_for_requests(c, now_value=now_value)]
        managed_ids = {str(c.id) for c in _filter_manageable_concerts(session_db, active, state=state)}
        target = [c for c in active if str(aid) in set(_concert_artist_ids(c)) and str(c.id) not in managed_ids]
        events = [_invitation_event_payload(session_db, c, include_counts=True) for c in target]
        return jsonify({'ok': True, 'events': events})
    finally:
        session_db.close()


@app.post('/invitaciones/gestionar-otros/anadir', endpoint='invitation_manage_others_add')
@admin_required
def invitation_manage_others_add():
    """Añade una actividad a la lista de gestión del usuario ('Gestionar otros')."""
    state = _current_user_state()
    uid = _safe_uuid(state.get('user_id'))
    data = request.get_json(silent=True) or {}
    concert_id = _safe_uuid(request.form.get('concert_id') or data.get('concert_id'))
    if not uid or not concert_id:
        return jsonify({'ok': False, 'error': 'Datos incompletos'}), 400
    session_db = db()
    try:
        concert = session_db.get(Concert, concert_id)
        if not concert:
            return jsonify({'ok': False, 'error': 'Actividad no encontrada'}), 404
        existing = session_db.query(InvitationManagerOptIn).filter_by(user_id=uid, concert_id=concert_id).first()
        if not existing:
            session_db.add(InvitationManagerOptIn(user_id=uid, concert_id=concert_id))
            session_db.commit()
        return jsonify({'ok': True, 'concert_id': str(concert_id)})
    except Exception as exc:
        session_db.rollback()
        return jsonify({'ok': False, 'error': str(exc)}), 500
    finally:
        session_db.close()


@app.get('/api/invitaciones/eventos', endpoint='api_invitation_events')
@admin_required
def api_invitation_events():
    artist_id = (request.args.get('artist_id') or '').strip()
    include_all = _truthy(request.args.get('all'))
    session_db = db()
    try:
        aid = str(_safe_uuid(artist_id) or '')
        query_start = _invitation_event_query_start_date()
        q = (
            session_db.query(Concert)
            .options(joinedload(Concert.artist), joinedload(Concert.venue))
            .filter(or_(Concert.date == None, Concert.date >= query_start))  # noqa: E711
            .order_by(Concert.date.asc().nullslast(), Concert.created_at.desc())
            .limit(220)
        )
        rows = []
        now_value = _now_madrid()
        for c in q.all():
            if not _invitation_event_is_active_for_requests(c, now_value=now_value):
                continue
            if aid and aid not in _concert_artist_ids(c):
                continue
            if (not include_all) and (not _invitation_event_has_config(session_db, c)):
                continue
            rows.append(_invitation_event_payload(session_db, c, include_counts=True))
        return jsonify({"ok": True, "events": rows})
    finally:
        session_db.close()


@app.get('/api/invitaciones/eventos/<concert_id>/categorias', endpoint='api_invitation_event_categories')
@admin_required
def api_invitation_event_categories(concert_id):
    session_db = db()
    try:
        concert = session_db.get(Concert, to_uuid(concert_id))
        if not concert:
            abort(404)
        if not _invitation_event_is_active_for_requests(concert):
            return jsonify({'ok': False, 'message': 'Este concierto o evento ya no admite solicitudes de invitaciones.'}), 410
        categories = _invitation_get_categories(session_db, concert, ensure_defaults=True)
        session_db.commit()
        counts = _invitation_event_counts(session_db, concert)
        return jsonify({
            'ok': True,
            'event': _invitation_event_payload(session_db, concert, include_counts=True),
            'categories': [_invitation_category_payload(c) for c in categories],
            'counts': counts,
        })
    finally:
        session_db.close()


@app.get('/invitaciones/evento/<concert_id>', endpoint='invitation_event_detail')
@admin_required
def invitation_event_detail(concert_id):
    session_db = db()
    try:
        concert = session_db.get(Concert, to_uuid(concert_id))
        if not concert:
            abort(404)
        _ensure_can_manage_invitations(session_db, concert)
        if not _invitation_event_is_active_for_requests(concert):
            flash('Este concierto o evento ya no aparece en gestión de invitaciones porque han pasado más de 5 horas desde el día del evento.', 'warning')
            return redirect(url_for('invitations_view', tab='gestionar'))
        # Origen para el botón "Volver": si se entra desde la ficha de la actividad (?from=ficha) se
        # recuerda en sesión por concierto, así sobrevive a las acciones internas (subir/asignar/enviar
        # recargan o redirigen aquí sin querystring). Desde la lista/inicio (?from=gestionar) se limpia.
        _back_origin = (request.args.get('from') or '').strip().lower()
        _back_map = session.get('inv_event_origin') or {}
        if _back_origin == 'ficha':
            _back_map[str(concert.id)] = 'ficha'
            session['inv_event_origin'] = _back_map
        elif _back_origin in ('gestionar', 'lista', 'inicio') and str(concert.id) in _back_map:
            _back_map.pop(str(concert.id), None)
            session['inv_event_origin'] = _back_map
        back_to_ficha = (session.get('inv_event_origin') or {}).get(str(concert.id)) == 'ficha'
        categories = _invitation_get_categories(session_db, concert, ensure_defaults=True)
        session_db.commit()
        # Releer tras crear defaults para contar bien.
        categories = _invitation_get_categories(session_db, concert, ensure_defaults=False)
        ticket_counts = defaultdict(lambda: {"uploaded": 0, "assigned": 0})
        for cid, status, count in (
            session_db.query(InvitationTicket.category_id, InvitationTicket.status, func.count(InvitationTicket.id))
            .filter(InvitationTicket.concert_id == concert.id)
            .group_by(InvitationTicket.category_id, InvitationTicket.status)
            .all()
        ):
            ticket_counts[str(cid)]["uploaded"] += int(count or 0)
            if status != 'AVAILABLE':
                ticket_counts[str(cid)]["assigned"] += int(count or 0)
        cat_payloads = [_invitation_category_payload(c, ticket_counts.get(str(c.id))) for c in categories]
        name_map = _invitation_category_name_map(categories)
        commitments = []
        for row in session_db.query(InvitationCommitment).filter(InvitationCommitment.concert_id == concert.id).order_by(InvitationCommitment.created_at.asc()).all():
            q = _json_dict(row.quantities_json)
            commitments.append({
                "id": str(row.id),
                "name": row.name,
                "reason": row.reason or "",
                "quantities": q,
                "quantities_label": _invitation_quantities_label(q, name_map),
                "status": row.status,
                "status_label": INVITATION_STATUS_LABELS.get(row.status or '', row.status or ''),
                "note": row.note or "",
            })
        requests = []
        denied_count = 0
        show_denied = _truthy(request.args.get('show_denied'))
        for row in session_db.query(InvitationRequest).filter(InvitationRequest.concert_id == concert.id).order_by(InvitationRequest.created_at.desc()).all():
            is_denied = (row.status or '') in {'RECHAZADAS', 'ANULADAS'}
            if is_denied:
                denied_count += 1
                if not show_denied:
                    continue
            item = _invitation_request_payload(row, categories)
            item.update(_invitation_request_kind_flags(session_db, row, categories))
            item['is_denied'] = is_denied
            requests.append(item)
        guest_list_rows_complete = _invitation_guest_list_rows(session_db, concert, 'COMPLETE')
        guest_list_rows_door = _invitation_guest_list_rows(session_db, concert, 'DOOR')
        guest_list_rows_box_office = _invitation_guest_list_rows(session_db, concert, 'BOX_OFFICE')
        guest_list_links = []
        for glink in session_db.query(InvitationGuestListLink).filter(InvitationGuestListLink.concert_id == concert.id).order_by(InvitationGuestListLink.created_at.desc()).limit(20).all():
            guest_list_links.append({
                'id': str(glink.id),
                'token': glink.token,
                'url': _external_url_for('public_invitation_guest_list', token=glink.token),
                'list_type': glink.list_type or 'COMPLETE',
                'list_type_label': _invitation_list_type_label(glink.list_type),
                'status': glink.status or 'ACTIVE',
                'created_at_label': _invitation_display_datetime(glink.created_at),
                'created_by': glink.created_by_nick or '',
            })
        links = []
        for link in session_db.query(InvitationPublicLink).filter(InvitationPublicLink.concert_id == concert.id).order_by(InvitationPublicLink.created_at.desc()).all():
            state, msg = _invitation_link_state(link)
            limits = _invitation_public_limits(link, categories, [])
            links.append({
                "id": str(link.id),
                "token": link.token,
                "url": _invitation_public_link_url(link),
                "target_name": link.target_name or (link.target_promoter.nick if link.target_promoter else '') or '—',
                "target_email": link.target_email or '',
                "requested_by": link.requested_by_nick or link.requested_by_email or '—',
                "deadline_label": _invitation_display_datetime(link.deadline_at),
                "state": state,
                "state_label": "Activo" if state == 'active' else ("Vencido" if state == 'expired' else "Anulado"),
                "state_badge": "success" if state == 'active' else "danger",
                "limit_summary": _invitation_limits_summary(link, categories),
                "message": msg,
                "limits": limits,
            })
        ticket_rows = (
            session_db.query(InvitationTicket)
            .filter(InvitationTicket.concert_id == concert.id)
            .order_by(InvitationTicket.sector.asc().nullslast(), InvitationTicket.row_label.asc().nullslast(), InvitationTicket.seat_number.asc().nullslast(), InvitationTicket.uploaded_at.asc())
            .limit(1000)
            .all()
        )
        tickets = [_invitation_ticket_payload(t, name_map) for t in ticket_rows]
        tickets_by_category = {str(c.id): [] for c in categories}
        for item in tickets:
            tickets_by_category.setdefault(str(item['category_id']), []).append(item)
        uncategorized_tickets = tickets_by_category.get('None', [])
        ticket_groups_by_category = {
            cid: _invitation_ticket_groups(rows)
            for cid, rows in tickets_by_category.items()
        }
        availability_by_category = {
            cid: _invitation_availability_breakdown(rows)
            for cid, rows in tickets_by_category.items()
        }
        pending_assignments = _invitation_pending_assignment_payloads(session_db, concert, categories)
        current_state = _current_user_state()
        return render_template(
            'invitaciones.html',
            tab='evento',
            back_to_ficha=back_to_ficha,
            event=_invitation_event_payload(session_db, concert, include_counts=True),
            concert=concert,
            categories=cat_payloads,
            commitments=commitments,
            requests=requests,
            denied_count=denied_count,
            show_denied=show_denied,
            guest_list_rows_complete=guest_list_rows_complete,
            guest_list_rows_door=guest_list_rows_door,
            guest_list_rows_box_office=guest_list_rows_box_office,
            guest_list_links=guest_list_links,
            links=links,
            tickets=tickets,
            tickets_by_category=tickets_by_category,
            uncategorized_tickets=uncategorized_tickets,
            ticket_groups_by_category=ticket_groups_by_category,
            availability_by_category=availability_by_category,
            pending_assignments=pending_assignments,
            current_user_invitation={
                'name': current_state.get('nick') or current_state.get('email') or '',
                'email': current_state.get('email') or '',
                'phone': current_state.get('phone') or '',
                'photo_url': current_state.get('photo_url') or url_for('static', filename='img/placeholder_photo.png'),
            },
            artists=_invitation_artist_options(session_db),
            event_artists=_invitation_event_artist_options(session_db),
            personnel=_invitation_personnel_options(session_db),
            category_types=INVITATION_CATEGORY_TYPES,
            guest_list_modes=INVITATION_GUEST_LIST_MODES,
            status_labels=INVITATION_STATUS_LABELS,
        )
    finally:
        session_db.close()


def _invitation_limits_summary(link: InvitationPublicLink, categories: list[InvitationCategory]) -> str:
    if (link.limit_mode or 'NONE') == 'TOTAL':
        return f"Límite total: {_safe_int(link.total_limit)}"
    if (link.limit_mode or '') == 'CATEGORIES':
        limits = _json_dict(link.category_limits_json)
        name_map = _invitation_category_name_map(categories)
        pieces = [f"{name_map.get(cid, 'Categoría')}: {_safe_int(qty)}" for cid, qty in limits.items() if _safe_int(qty) > 0]
        return ' · '.join(pieces) or 'Sin límite por categoría'
    if link.categorize_requests:
        enabled = set(str(x) for x in _json_list(link.categories_enabled_json))
        if enabled:
            name_map = _invitation_category_name_map(categories)
            return 'Categorías: ' + ' · '.join([name_map.get(cid, 'Categoría') for cid in enabled])
        return 'Sin límite, con categorías'
    return 'Sin límite y sin categorías'


@app.post('/invitaciones/evento/<concert_id>/categorias', endpoint='invitation_category_save')
@admin_required
def invitation_category_save(concert_id):
    session_db = db()
    next_url = (request.form.get('next') or '').strip()
    if not next_url.startswith('/'):
        next_url = ''
    fallback_url = url_for('invitation_event_detail', concert_id=concert_id) + '#inv-tab-tickets'
    try:
        concert = session_db.get(Concert, to_uuid(concert_id))
        if not concert:
            abort(404)
        _ensure_can_manage_invitations(session_db, concert)

        # Modo tabla: permite configurar de una vez todas las categorías con contrato/adicionales.
        row_names = request.form.getlist('category_name[]')
        if row_names:
            row_ids = request.form.getlist('category_id[]')
            contract_qtys = request.form.getlist('qty_contract[]')
            extra_qtys = request.form.getlist('qty_extra[]')
            kinds = request.form.getlist('ticket_kind[]')
            guest_modes = request.form.getlist('guest_list_mode[]')
            for idx, name_raw in enumerate(row_names):
                name = (name_raw or '').strip()
                if not name:
                    continue
                category_id = _safe_uuid(row_ids[idx] if idx < len(row_ids) else None)
                row = session_db.get(InvitationCategory, category_id) if category_id else None
                if row and row.concert_id != concert.id:
                    continue
                if not row:
                    row = InvitationCategory(concert_id=concert.id, created_by_user_id=_safe_uuid(session.get('user_id')), created_by_nick=_current_user_email(), sort_order=idx)
                    session_db.add(row)
                raw_kind = kinds[idx] if idx < len(kinds) else ''
                raw_guest = guest_modes[idx] if idx < len(guest_modes) else ''
                ticket_kind, guest_mode = _invitation_parse_ticket_kind_and_guest_mode(raw_kind, getattr(row, 'ticket_kind', None), raw_guest or getattr(row, 'guest_list_mode', None))
                row.name = name
                row.qty_contract = _safe_int(contract_qtys[idx] if idx < len(contract_qtys) else 0)
                row.qty_extra = _safe_int(extra_qtys[idx] if idx < len(extra_qtys) else 0)
                row.ticket_kind = ticket_kind
                row.guest_list_mode = guest_mode
                row.is_active = True
                row.sort_order = idx
                row.updated_at = _now_madrid()
            session_db.commit()
            flash('Invitaciones disponibles actualizadas.', 'success')
            return redirect(next_url or fallback_url)

        category_id = _safe_uuid(request.form.get('category_id'))
        row = session_db.get(InvitationCategory, category_id) if category_id else None
        if row and row.concert_id != concert.id:
            abort(403)
        if not row:
            row = InvitationCategory(concert_id=concert.id, created_by_user_id=_safe_uuid(session.get('user_id')), created_by_nick=_current_user_email())
            session_db.add(row)
        ticket_kind, guest_mode = _invitation_parse_ticket_kind_and_guest_mode(request.form.get('ticket_kind'), getattr(row, 'ticket_kind', None), request.form.get('guest_list_mode') or getattr(row, 'guest_list_mode', None))
        row.name = (request.form.get('name') or 'General').strip() or 'General'
        row.ticket_kind = ticket_kind
        row.guest_list_mode = guest_mode
        row.qty_contract = _safe_int(request.form.get('qty_contract'))
        row.qty_extra = _safe_int(request.form.get('qty_extra'))
        row.is_active = not _truthy(request.form.get('inactive'))
        row.updated_at = _now_madrid()
        session_db.commit()
        flash('Categoría de invitaciones guardada.', 'success')
    except Exception as exc:
        session_db.rollback()
        flash(f'No se pudo guardar la categoría: {exc}', 'danger')
    finally:
        session_db.close()
    return redirect(next_url or fallback_url)


@app.post('/invitaciones/solicitudes', endpoint='invitation_request_create')
@admin_required
def invitation_request_create():
    session_db = db()
    try:
        concert = session_db.get(Concert, to_uuid(request.form.get('concert_id')))
        if not concert:
            abort(404)
        if not _invitation_event_is_active_for_requests(concert):
            raise ValueError('Este concierto o evento ya no admite solicitudes de invitaciones.')
        categories = _invitation_get_categories(session_db, concert, ensure_defaults=True)
        quantities = _invitation_quantities_from_form(request.form, categories)
        if _invitation_total_qty(quantities) <= 0:
            raise ValueError('Indica al menos una invitación.')
        # Las solicitudes (peticiones) NO se limitan por el cupo del evento: el concierto puede no
        # tener invitaciones configuradas todavía, o tenerlas completas y ampliarse después. El
        # control de cupo se ejerce al ACEPTAR/asignar la solicitud (por eso existe el flujo de
        # aprobación), no al pedirla.
        state = _current_user_state()
        # Por defecto la petición se atribuye a quien la registra. Si se pide para otra persona de la
        # oficina (guest_type EMPLOYEE), más abajo se reasigna a esa persona para que figure como suya.
        requester_info = {
            'user_id': session.get('user_id'),
            'nick': state.get('nick') or _email_to_nick(state.get('email') or ''),
            'email': state.get('email'),
            'photo_url': state.get('photo_url'),
            'phone': state.get('phone') or '',
        }
        guest_type = (request.form.get('guest_type') or 'THIRD_PARTY').strip().upper()
        guest_name = (request.form.get('guest_name') or '').strip()
        guest_email = (request.form.get('guest_email') or '').strip()
        guest_phone = (request.form.get('guest_phone') or '').strip()
        guest_company = (request.form.get('guest_company') or '').strip()
        guest_title = (request.form.get('guest_title') or guest_company or '').strip()
        guest_link_summary = {}
        guest_promoter_id = _safe_uuid(request.form.get('guest_promoter_id'))
        guest_artist_id = _safe_uuid(request.form.get('guest_artist_id'))
        guest_user_id = _safe_uuid(request.form.get('guest_user_id'))
        if guest_type == 'SELF':
            guest_name = state.get('nick') or state.get('email') or 'Solicitante'
            guest_email = state.get('email') or guest_email
        elif guest_type == 'EMPLOYEE' and guest_user_id:
            user = session_db.get(User, guest_user_id)
            profile = session_db.get(UserProfile, guest_user_id)
            if user:
                guest_name = _profile_full_name(profile) or getattr(profile, 'nick', None) or user.email
                guest_email = user.email
                # Pedir "para alguien de la empresa" hace que la petición figure como suya: el
                # solicitante pasa a ser esa persona (aparece en SUS invitaciones solicitadas).
                _emp_phones = list(getattr(profile, 'mobile_phones', None) or [])
                requester_info = {
                    'user_id': str(user.id),
                    'nick': getattr(profile, 'nick', None) or _profile_full_name(profile) or _email_to_nick(user.email or ''),
                    'email': user.email,
                    'photo_url': getattr(profile, 'photo_url', None),
                    'phone': (_emp_phones[0] if _emp_phones else ''),
                }
        elif guest_type == 'ARTIST' and guest_artist_id:
            artist = session_db.get(Artist, guest_artist_id)
            if artist:
                guest_name = artist.name
                guest_email = artist.email or guest_email
        elif guest_promoter_id:
            promoter = session_db.get(Promoter, guest_promoter_id)
            if promoter:
                guest_name = _promoter_display_name(promoter) or promoter.nick
                guest_email = promoter.contact_email or guest_email
                guest_phone = promoter.contact_phone or guest_phone
                guest_link_summary = _promoter_link_summary(session_db, promoter)
        if not guest_name:
            guest_name = 'Invitado'
        # Correo añadido a mano en el paso de entrega (cuando el invitado no lo tiene en su ficha).
        if not guest_email:
            guest_email = (request.form.get('guest_fallback_email') or '').strip()
        receiver_mode = (request.form.get('receiver_mode') or 'GUEST').strip().upper()
        receiver_payload = {
            'name': (request.form.get('receiver_name') or '').strip(),
            'email': (request.form.get('receiver_email') or '').strip(),
            'phone': (request.form.get('receiver_phone') or '').strip(),
        }
        no_guest_contact = False
        if receiver_mode == 'GUEST':
            receiver_payload['name'] = receiver_payload.get('name') or guest_name
            receiver_payload['email'] = receiver_payload.get('email') or guest_email
            receiver_payload['phone'] = receiver_payload.get('phone') or guest_phone
            if not receiver_payload.get('email') and not receiver_payload.get('phone'):
                # El invitado no tiene correo ni teléfono: en vez de fallar, la petición se completa
                # y las invitaciones se envían a quien las solicita (puede añadir un correo después).
                no_guest_contact = True
                receiver_mode = 'ME'
                receiver_payload = {
                    'name': requester_info.get('nick') or requester_info.get('email') or 'Solicitante',
                    'email': requester_info.get('email') or '',
                    'phone': requester_info.get('phone') or '',
                    'fallback_from_guest': True,
                }
        elif receiver_mode == 'ME':
            receiver_payload = {
                'name': requester_info.get('nick') or requester_info.get('email') or 'Solicitante',
                'email': requester_info.get('email') or '',
                'phone': requester_info.get('phone') or '',
            }
        elif receiver_mode == 'OTHER':
            receiver_promoter_id = _safe_uuid(request.form.get('receiver_promoter_id'))
            if receiver_promoter_id:
                receiver_promoter = session_db.get(Promoter, receiver_promoter_id)
                if receiver_promoter:
                    receiver_payload['promoter_id'] = str(receiver_promoter.id)
                    receiver_payload['name'] = receiver_payload.get('name') or _promoter_display_name(receiver_promoter) or receiver_promoter.nick
                    receiver_payload['email'] = receiver_payload.get('email') or receiver_promoter.contact_email or ''
                    receiver_payload['phone'] = receiver_payload.get('phone') or receiver_promoter.contact_phone or ''
            if not receiver_payload.get('name'):
                receiver_payload['name'] = 'Otro receptor'
            if not receiver_payload.get('email') and not receiver_payload.get('phone'):
                raise ValueError('Para enviar a otro receptor selecciona un tercero con email/teléfono o indica al menos email o teléfono.')
        elif receiver_mode == 'BOX_OFFICE':
            receiver_payload = {}
        row = InvitationRequest(
            concert_id=concert.id,
            request_source='INTERNAL',
            requester_type='USER',
            requester_user_id=_safe_uuid(requester_info.get('user_id')),
            requester_nick=requester_info.get('nick'),
            requester_email=requester_info.get('email'),
            requester_photo_url=requester_info.get('photo_url'),
            created_by_user_id=_safe_uuid(session.get('user_id')),
            created_by_nick=state.get('nick') or _email_to_nick(state.get('email') or ''),
            guest_type=guest_type,
            guest_promoter_id=guest_promoter_id,
            guest_artist_id=guest_artist_id,
            guest_user_id=guest_user_id,
            guest_name=guest_name,
            guest_company=guest_company,
            guest_title=guest_title,
            guest_link_summary=guest_link_summary,
            guest_email=guest_email,
            guest_phone=guest_phone,
            guest_note=(request.form.get('guest_note') or '').strip(),
            receiver_mode=receiver_mode,
            receiver_payload=receiver_payload,
            quantities_json=quantities,
            status='SOLICITADAS',
            note=(request.form.get('note') or '').strip(),
            delivery_token=_invitation_token(),
        )
        session_db.add(row)
        session_db.commit()
        if no_guest_contact:
            flash('El invitado no tenía correo configurado: la solicitud se completó y las invitaciones te llegarán a ti (quien las pide). Puedes añadir un correo a su ficha para enviárselas directamente.', 'warning')
        else:
            flash('Solicitud de invitaciones guardada como solicitada.', 'success')
        # Volvemos a la vista de invitaciones (pestaña "pedir", con "Mis solicitudes"), que el
        # solicitante siempre puede ver. La ficha del evento exige permiso de gestión, así que
        # redirigir allí daría 403 a quien solo tiene habilitado "pedir".
        return redirect(url_for('invitations_view', tab='pedir'))
    except Exception as exc:
        session_db.rollback()
        flash(f'No se pudo crear la solicitud: {exc}', 'danger')
        return redirect(url_for('invitations_view', tab='pedir'))
    finally:
        session_db.close()


@app.post('/invitaciones/enlaces', endpoint='invitation_public_link_create')
@admin_required
def invitation_public_link_create():
    session_db = db()
    try:
        concert = session_db.get(Concert, to_uuid(request.form.get('concert_id')))
        if not concert:
            abort(404)
        _ensure_can_manage_invitations(session_db, concert)
        if not _invitation_event_is_active_for_requests(concert):
            raise ValueError('Este concierto o evento ya no admite enlaces de peticiones de invitaciones.')
        categories = _invitation_get_categories(session_db, concert, ensure_defaults=True)
        state = _current_user_state()
        target_promoter_id = _safe_uuid(request.form.get('target_promoter_id'))
        target = session_db.get(Promoter, target_promoter_id) if target_promoter_id else None
        limit_mode = (request.form.get('limit_mode') or 'NONE').strip().upper()
        category_limits = {}
        categories_enabled = []
        for cat in categories:
            cid = str(cat.id)
            max_qty = _safe_int(request.form.get(f'link_limit_{cid}'))
            enabled = _truthy(request.form.get(f'link_enabled_{cid}')) or max_qty > 0
            if max_qty > 0:
                category_limits[cid] = max_qty
            if enabled:
                categories_enabled.append(cid)
        if limit_mode == 'CATEGORIES' and not category_limits:
            limit_mode = 'NONE'
        if limit_mode == 'TOTAL' and _safe_int(request.form.get('total_limit')) <= 0:
            limit_mode = 'NONE'
        link = InvitationPublicLink(
            concert_id=concert.id,
            token=_invitation_token(),
            target_promoter_id=target_promoter_id,
            target_name=(request.form.get('target_name') or (target.nick if target else '') or '').strip(),
            target_email=(request.form.get('target_email') or (target.contact_email if target else '') or '').strip(),
            target_phone=(request.form.get('target_phone') or (target.contact_phone if target else '') or '').strip(),
            requested_by_user_id=_safe_uuid(session.get('user_id')),
            requested_by_nick=state.get('nick') or _email_to_nick(state.get('email') or ''),
            requested_by_email=state.get('email'),
            requested_by_photo_url=state.get('photo_url'),
            limit_mode=limit_mode,
            total_limit=_safe_int(request.form.get('total_limit')) if limit_mode == 'TOTAL' else None,
            category_limits_json=category_limits,
            categories_enabled_json=categories_enabled,
            categorize_requests=_truthy(request.form.get('categorize_requests')) if request.form.get('categorize_requests') is not None else True,
            deadline_at=_invitation_parse_deadline(request.form.get('deadline_at')),
            status='ACTIVE',
        )
        session_db.add(link)
        session_db.commit()
        share_url = _invitation_public_link_url(link)
        flash('Enlace de peticiones generado. Copia el enlace desde la pestaña de enlaces generados.', 'success')
        return redirect(url_for('invitation_event_detail', concert_id=concert.id, generated_link=share_url))
    except Exception as exc:
        session_db.rollback()
        flash(f'No se pudo generar el enlace: {exc}', 'danger')
        return redirect(url_for('invitations_view', tab='pedir'))
    finally:
        session_db.close()


