@app.post('/invitaciones/compromisos/<commitment_id>/entregar', endpoint='invitation_commitment_deliver')
@admin_required
def invitation_commitment_deliver(commitment_id):
    """Entrega las entradas ya asignadas a un compromiso: por email (la dirección se pide en el
    momento) o marcándolas para recogida en taquilla. Si no tiene entradas asignadas, avisa."""
    session_db = db()
    try:
        row = session_db.get(InvitationCommitment, to_uuid(commitment_id))
        if not row:
            abort(404)
        _ensure_can_manage_invitations(session_db, row.concert)
        cid = row.concert_id
        mode = (request.form.get('mode') or 'email').strip().lower()
        tickets = session_db.query(InvitationTicket).filter(InvitationTicket.assigned_commitment_id == row.id).all()
        if not tickets:
            flash('Este compromiso aún no tiene entradas asignadas. Asígnaselas antes de entregarlas.', 'warning')
            return redirect(url_for('invitation_event_detail', concert_id=cid))
        now = _now_madrid()
        if mode in ('box_office', 'taquilla'):
            for t in tickets:
                t.status = 'DISPONIBLES_TAQUILLA'
                t.updated_at = now
            session_db.commit()
            flash(f'{len(tickets)} entrada(s) de «{row.name}» quedan para recogida en taquilla.', 'success')
            return redirect(url_for('invitation_event_detail', concert_id=cid))
        recipients = _dedupe_valid_email_addresses(request.form.getlist('recipients') + [(request.form.get('email') or '')])
        if not recipients:
            flash('Indica un email de destino o elige la recogida en taquilla.', 'warning')
            return redirect(url_for('invitation_event_detail', concert_id=cid))
        links = ''.join(f'<li><a href="{t.pdf_url}">{(t.ticket_code or t.pdf_name or "Entrada")}</a></li>' for t in tickets if t.pdf_url)
        html_body = f'<p>Hola,</p><p>Aquí tienes tus invitaciones ({len(tickets)}):</p><ul>{links}</ul>'
        text_body = 'Tus invitaciones:\n' + '\n'.join((t.pdf_url or '') for t in tickets if t.pdf_url)
        ok, err = _send_optional_email(recipients, 'Tus invitaciones', html_body, text_body=text_body, reply_to=_current_user_email())
        if ok:
            for t in tickets:
                t.status = 'SENT'
                t.sent_at = now
                t.updated_at = now
            session_db.commit()
            flash(f'Invitaciones de «{row.name}» enviadas por email.', 'success')
        else:
            session_db.rollback()
            flash(f'No se pudo enviar el email: {err or "SMTP no configurado"}', 'warning')
        return redirect(url_for('invitation_event_detail', concert_id=cid))
    except Exception as exc:
        session_db.rollback()
        flash(f'No se pudo entregar: {exc}', 'danger')
        return redirect(url_for('invitations_view', tab='gestionar'))
    finally:
        session_db.close()


@app.post('/invitaciones/solicitudes/<request_id>/estado', endpoint='invitation_request_status')
@admin_required
def invitation_request_status(request_id):
    session_db = db()
    try:
        row = session_db.get(InvitationRequest, to_uuid(request_id))
        if not row:
            abort(404)
        action = (request.form.get('action') or '').strip().upper()
        _state = _current_user_state()
        _is_owner = str(getattr(row, 'requester_user_id', '') or '') == str(_state.get('user_id') or '')
        # El peticionario puede anular SU propia solicitud; el resto de acciones exigen gestión.
        if not (action == 'CANCEL' and _is_owner):
            _ensure_can_manage_invitations(session_db, row.concert)
        old_status = row.status
        if action == 'APPROVE':
            row.status = 'APROBADAS'
            row.approved_at = _now_madrid()
            flash('Solicitud aprobada.', 'success')
        elif action == 'REJECT':
            reason = (request.form.get('reason') or '').strip()
            row.status = 'RECHAZADAS'
            row.rejected_at = _now_madrid()
            row.rejection_reason = reason
            subject, html_body, text_body = _invitation_rejection_email_body(session_db, row, reason)
            recipients = _dedupe_valid_email_addresses([row.requester_email, row.guest_email])
            if recipients:
                _send_optional_email(recipients, subject, html_body, text_body=text_body)
            flash('Solicitud rechazada.', 'warning')
        elif action == 'CANCEL':
            row.status = 'ANULADAS'
            row.cancelled_at = _now_madrid()
            row.cancelled_by_label = _current_user_email()
            assigned = session_db.query(InvitationTicket).filter(InvitationTicket.assigned_request_id == row.id).all()
            for t in assigned:
                t.previous_assignment_warning = f"Ya había sido asignada/enviada a {row.guest_name}."
                t.assigned_request_id = None
                t.assigned_label = None
                t.status = 'AVAILABLE'
            flash('Solicitud anulada y entradas liberadas con advertencia.', 'success')
        elif action == 'DELIVER_HAND':
            row.status = 'ENTREGADAS_MANO'
            row.delivered_at = _now_madrid()
            flash('Marcadas como entregadas en mano.', 'success')
        elif action == 'BOX_OFFICE':
            row.status = 'DISPONIBLES_TAQUILLA'
            flash('Marcadas como disponibles en taquilla.', 'success')
        elif action == 'PICKED_UP':
            row.status = 'RECOGIDAS_TAQUILLA'
            row.delivered_at = _now_madrid()
            flash('Marcadas como recogidas en taquilla.', 'success')
        else:
            flash('Acción no reconocida.', 'warning')
        row.updated_at = _now_madrid()
        session_db.commit()
        return redirect(url_for('invitation_event_detail', concert_id=row.concert_id))
    except Exception as exc:
        session_db.rollback()
        flash(f'No se pudo actualizar la solicitud: {exc}', 'danger')
        return redirect(url_for('invitations_view', tab='gestionar'))
    finally:
        session_db.close()


@app.post('/invitaciones/solicitudes/<request_id>/editar', endpoint='invitation_request_update')
@admin_required
def invitation_request_update(request_id):
    """Edita los datos de una solicitud propia (o gestionable) desde "Mis solicitudes".

    Solo mientras no tenga invitaciones asignadas/enviadas (SOLICITADAS/APROBADAS); después hay que
    anularla y crear una nueva, porque cambiar invitado/cantidades rompería la asignación."""
    session_db = db()
    try:
        row = session_db.get(InvitationRequest, to_uuid(request_id))
        if not row:
            abort(404)
        _state = _current_user_state()
        _is_owner = str(getattr(row, 'requester_user_id', '') or '') == str(_state.get('user_id') or '')
        if not _is_owner:
            _ensure_can_manage_invitations(session_db, row.concert)
        # Los datos del invitado y la nota se pueden corregir siempre; las cantidades solo antes de
        # asignar entradas (después cambiarlas descuadraría la asignación: anula y crea otra).
        guest_name = (request.form.get('guest_name') or '').strip()
        if guest_name:
            row.guest_name = guest_name
        row.guest_email = (request.form.get('guest_email') or '').strip()
        row.guest_phone = (request.form.get('guest_phone') or '').strip()
        guest_title = (request.form.get('guest_title') or '').strip()
        row.guest_title = guest_title
        row.guest_company = guest_title or row.guest_company
        row.note = (request.form.get('note') or '').strip()
        new_total = _safe_int(request.form.get('qty_total'))
        if new_total > 0 and (row.status or '') in {'SOLICITADAS', 'APROBADAS'}:
            quantities = _json_dict(row.quantities_json)
            positive = {k: _safe_int(v) for k, v in quantities.items() if _safe_int(v) > 0}
            if len(positive) == 1:
                quantities[next(iter(positive))] = new_total
                row.quantities_json = quantities
            elif not positive:
                row.quantities_json = {'TOTAL': new_total}
        row.updated_at = _now_madrid()
        session_db.commit()
        flash('Solicitud actualizada.', 'success')
        return redirect(url_for('invitations_view', tab='pedir'))
    except Exception as exc:
        session_db.rollback()
        flash(f'No se pudo actualizar la solicitud: {exc}', 'danger')
        return redirect(url_for('invitations_view', tab='pedir'))
    finally:
        session_db.close()


@app.post('/invitaciones/solicitudes/<request_id>/eliminar', endpoint='invitation_request_delete')
@admin_required
def invitation_request_delete(request_id):
    """Elimina una solicitud propia (o gestionable), gestionando sus entradas asignadas:

    - Sin entradas o con entradas asignadas pero NO enviadas → se liberan (vuelven a disponibles) y
      se borra la solicitud directamente.
    - Con entradas YA enviadas → requiere una decisión explícita (`mode`), porque el invitado pudo
      recibirlas o descargarlas. Sin `mode` válido devolvemos `needs_confirm` para que el front
      muestre la advertencia con las opciones:
        · `recover` → recuperar/cancelar envío: las entradas vuelven a estar disponibles (con aviso).
        · `lost`    → darlas por perdidas: las entradas quedan en estado LOST y NO vuelven al pool.
    """
    _ajax = _truthy(request.form.get('ajax'))
    fallback = request.referrer if (request.referrer or '').startswith(request.host_url) else None
    session_db = db()
    try:
        row = session_db.get(InvitationRequest, to_uuid(request_id))
        if not row:
            abort(404)
        _state = _current_user_state()
        _is_owner = str(getattr(row, 'requester_user_id', '') or '') == str(_state.get('user_id') or '')
        if not _is_owner:
            _ensure_can_manage_invitations(session_db, row.concert)
        tickets = session_db.query(InvitationTicket).filter(InvitationTicket.assigned_request_id == row.id).all()
        sent_statuses = {'ENVIADAS', 'ENTREGADAS_MANO', 'DISPONIBLES_TAQUILLA', 'RECOGIDAS_TAQUILLA'}
        was_sent = bool(row.sent_at) or (row.status or '') in sent_statuses or any((t.status or '') in {'SENT', 'DELIVERED', 'PICKED_UP'} for t in tickets)
        was_downloaded = bool(row.downloaded_at) or _safe_int(row.downloaded_count) > 0
        mode = (request.form.get('mode') or '').strip().lower()

        # Entradas enviadas sin decisión → no borrar a ciegas: pedir confirmación.
        if tickets and was_sent and mode not in {'recover', 'lost'}:
            info = {
                'ok': False, 'needs_confirm': True, 'sent': True,
                'downloaded': bool(was_downloaded), 'ticket_count': len(tickets),
                'guest_name': row.guest_name or '',
            }
            if _ajax:
                return jsonify(info)
            flash('Estas invitaciones ya fueron enviadas. Usa el menú para recuperarlas o darlas por perdidas antes de eliminar.', 'warning')
            return redirect(fallback or (url_for('invitation_event_detail', concert_id=row.concert_id) if not _is_owner else url_for('invitations_view', tab='pedir')))

        give_up = bool(tickets) and was_sent and was_downloaded and mode == 'lost'
        for t in tickets:
            if give_up:
                t.previous_assignment_warning = f"Entregada y descargada por {row.guest_name}; dada por perdida."
                t.status = 'LOST'
            else:
                if was_downloaded:
                    t.previous_assignment_warning = f"Ya había sido enviada y descargada por {row.guest_name}."
                elif was_sent:
                    t.previous_assignment_warning = f"Ya había sido enviada a {row.guest_name}."
                elif t.assigned_label:
                    t.previous_assignment_warning = f"Ya había sido asignada a {t.assigned_label}."
                t.status = 'AVAILABLE'
            t.assigned_request_id = None
            t.assigned_commitment_id = None
            t.assigned_label = None
            t.sent_at = None
            t.updated_at = _now_madrid()
        session_db.delete(row)
        session_db.commit()
        if give_up:
            msg = f'Solicitud eliminada. {len(tickets)} entrada(s) dadas por perdidas (no vuelven a estar disponibles).'
        elif tickets:
            msg = f'Solicitud eliminada. {len(tickets)} entrada(s) vuelven a estar disponibles.'
        else:
            msg = 'Solicitud eliminada.'
        if _ajax:
            return jsonify({'ok': True, 'message': msg})
        flash(msg, 'success')
        return redirect(fallback or url_for('invitations_view', tab='pedir'))
    except Exception as exc:
        session_db.rollback()
        if _ajax:
            return jsonify({'ok': False, 'error': str(exc)}), 400
        flash(f'No se pudo eliminar la solicitud: {exc}', 'danger')
        return redirect(fallback or url_for('invitations_view', tab='pedir'))
    finally:
        session_db.close()


@app.post('/invitaciones/solicitudes/<request_id>/asignar-auto', endpoint='invitation_request_auto_assign')
@admin_required
def invitation_request_auto_assign(request_id):
    session_db = db()
    try:
        row = session_db.get(InvitationRequest, to_uuid(request_id))
        if not row:
            abort(404)
        _ensure_can_manage_invitations(session_db, row.concert)
        concert = row.concert or session_db.get(Concert, row.concert_id)
        categories = _invitation_get_categories(session_db, concert, ensure_defaults=True)
        cat_map = {str(c.id): c for c in categories}
        quantities = _json_dict(row.quantities_json)
        assigned_count = 0
        for cid, qty in quantities.items():
            qty = _safe_int(qty)
            if qty <= 0 or cid == 'TOTAL':
                continue
            cat = cat_map.get(str(cid))
            if not cat:
                continue
            if (cat.ticket_kind or '').upper() == 'GUEST_LIST':
                assigned_count += qty
                continue
            available = (
                session_db.query(InvitationTicket)
                .filter(InvitationTicket.category_id == cat.id)
                .filter(InvitationTicket.status == 'AVAILABLE')
                .order_by(InvitationTicket.sector.asc().nullslast(), InvitationTicket.row_label.asc().nullslast(), InvitationTicket.seat_number.asc().nullslast(), InvitationTicket.uploaded_at.asc())
                .limit(qty)
                .all()
            )
            if len(available) < qty:
                raise ValueError(f'No hay invitaciones suficientes en {cat.name}: faltan {qty - len(available)}.')
            for ticket in available:
                if ticket.previous_assignment_warning and not _truthy(request.form.get('accept_warnings')):
                    raise ValueError(f'La entrada {ticket.ticket_code or ticket.pdf_name} ya había sido enviada/asignada antes. Acepta la advertencia para reasignarla.')
                ticket.assigned_request_id = row.id
                ticket.assigned_label = row.guest_name
                ticket.status = 'ASSIGNED'
                ticket.assigned_at = _now_madrid()
                assigned_count += 1
        if assigned_count > 0:
            row.status = 'ASIGNADAS'
            row.assigned_at = _now_madrid()
        session_db.commit()
        flash('Invitaciones asignadas.', 'success')
        return redirect(url_for('invitation_event_detail', concert_id=row.concert_id))
    except Exception as exc:
        session_db.rollback()
        flash(f'No se pudieron asignar automáticamente: {exc}', 'danger')
        return redirect(url_for('invitations_view', tab='gestionar'))
    finally:
        session_db.close()


@app.post('/invitaciones/solicitudes/<request_id>/enviar', endpoint='invitation_request_send')
@admin_required
def invitation_request_send(request_id):
    session_db = db()
    try:
        row = session_db.get(InvitationRequest, to_uuid(request_id))
        if not row:
            abort(404)
        _ensure_can_manage_invitations(session_db, row.concert)
        channel = (request.form.get('channel') or 'email').strip().lower()
        categories = _invitation_get_categories(session_db, row.concert or session_db.get(Concert, row.concert_id), ensure_defaults=False) if row.concert_id else []
        flags = _invitation_request_kind_flags(session_db, row, categories)
        if not flags.get('can_send'):
            raise ValueError('Solo se pueden enviar invitaciones cuando ya tienen entradas asignadas o cuando son de tipo listado.')
        download_url = _invitation_request_download_url(row)
        subject, html_body, text_body = _invitation_email_body(session_db, row, download_url)
        row.delivery_token = row.delivery_token or _invitation_token()
        if channel == 'email':
            recipients = _dedupe_valid_email_addresses(request.form.getlist('recipients') + request.form.getlist('extra_emails') + _invitation_delivery_recipients(row))
            ok, err = _send_optional_email(recipients, subject, html_body, text_body=text_body, reply_to=_current_user_email())
            if ok:
                row.status = 'ENVIADAS'
                row.sent_at = _now_madrid()
                for ticket in session_db.query(InvitationTicket).filter(InvitationTicket.assigned_request_id == row.id).all():
                    ticket.status = 'SENT'
                    ticket.sent_at = row.sent_at
                    ticket.updated_at = row.sent_at
                flash('Invitaciones enviadas por email.', 'success')
            else:
                flash(f'No se pudo enviar el email: {err or "SMTP no configurado"}', 'warning')
        else:
            row.status = 'ENVIADAS'
            row.sent_at = _now_madrid()
            for ticket in session_db.query(InvitationTicket).filter(InvitationTicket.assigned_request_id == row.id).all():
                ticket.status = 'SENT'
                ticket.sent_at = row.sent_at
                ticket.updated_at = row.sent_at
            session_db.commit()
            msg = text_body.replace('\n', ' ')
            if channel == 'whatsapp':
                return redirect('https://wa.me/?text=' + quote_plus(msg))
            if channel == 'sms':
                return redirect('sms:?&body=' + quote_plus(msg))
            flash('Enlace listo para copiar.', 'success')
        session_db.commit()
        return redirect(url_for('invitation_event_detail', concert_id=row.concert_id))
    except Exception as exc:
        session_db.rollback()
        flash(f'No se pudo enviar: {exc}', 'danger')
        return redirect(url_for('invitations_view', tab='gestionar'))
    finally:
        session_db.close()


@app.post('/invitaciones/evento/<concert_id>/enviar-asignadas', endpoint='invitation_event_send_all')
@admin_required
def invitation_event_send_all(concert_id):
    """Envía por email, de una vez, todas las peticiones del evento que tienen entradas asignadas
    (estado ASIGNADAS). Las de recogida en taquilla (receiver_mode=BOX_OFFICE) NO se envían."""
    session_db = db()
    try:
        concert = session_db.get(Concert, to_uuid(concert_id))
        if not concert:
            abort(404)
        _ensure_can_manage_invitations(session_db, concert)
        categories = _invitation_get_categories(session_db, concert, ensure_defaults=False)
        rows = (
            session_db.query(InvitationRequest)
            .filter(InvitationRequest.concert_id == concert.id, InvitationRequest.status == 'ASIGNADAS')
            .all()
        )
        sent = 0
        skipped_box = 0
        no_email = 0
        failed = 0
        for row in rows:
            if (row.receiver_mode or '').strip().upper() == 'BOX_OFFICE':
                skipped_box += 1
                continue
            flags = _invitation_request_kind_flags(session_db, row, categories)
            if not flags.get('can_send'):
                continue
            row.delivery_token = row.delivery_token or _invitation_token()
            download_url = _invitation_request_download_url(row)
            subject, html_body, text_body = _invitation_email_body(session_db, row, download_url)
            recipients = _dedupe_valid_email_addresses(_invitation_delivery_recipients(row))
            if not recipients:
                no_email += 1
                continue
            ok, err = _send_optional_email(recipients, subject, html_body, text_body=text_body, reply_to=_current_user_email())
            if ok:
                row.status = 'ENVIADAS'
                row.sent_at = _now_madrid()
                for ticket in session_db.query(InvitationTicket).filter(InvitationTicket.assigned_request_id == row.id).all():
                    ticket.status = 'SENT'
                    ticket.sent_at = row.sent_at
                    ticket.updated_at = row.sent_at
                sent += 1
            else:
                failed += 1
        session_db.commit()
        parts = []
        if sent:
            parts.append(f'{sent} enviadas')
        if skipped_box:
            parts.append(f'{skipped_box} de taquilla (no se envían)')
        if no_email:
            parts.append(f'{no_email} sin email')
        if failed:
            parts.append(f'{failed} con error de envío')
        if sent:
            flash('Envío masivo: ' + ', '.join(parts) + '.', 'success')
        elif parts:
            flash('No se envió ninguna invitación: ' + ', '.join(parts) + '.', 'warning')
        else:
            flash('No hay invitaciones asignadas pendientes de enviar.', 'info')
        return redirect(url_for('invitation_event_detail', concert_id=concert_id) + '#inv-tab-guests')
    except Exception as exc:
        session_db.rollback()
        flash(f'No se pudo completar el envío masivo: {exc}', 'danger')
        return redirect(url_for('invitation_event_detail', concert_id=concert_id))
    finally:
        session_db.close()


