@app.post('/invitaciones/evento/<concert_id>/tickets/upload', endpoint='invitation_tickets_upload')
@admin_required
def invitation_tickets_upload(concert_id):
    session_db = db()
    try:
        concert = session_db.get(Concert, to_uuid(concert_id))
        if not concert:
            abort(404)
        _ensure_can_manage_invitations(session_db, concert)
        cat_id_raw = (request.form.get('category_id') or '').strip()
        category = session_db.get(InvitationCategory, to_uuid(cat_id_raw)) if cat_id_raw else None
        if cat_id_raw and (not category or category.concert_id != concert.id):
            raise ValueError('Categoría no válida.')
        if category is not None:
            ticket_kind, guest_mode = _invitation_parse_ticket_kind_and_guest_mode(
                request.form.get('ticket_kind'),
                category.ticket_kind or 'PDF_UNNUMBERED',
                request.form.get('guest_list_mode') or category.guest_list_mode or 'BOX_OFFICE',
            )
            category.ticket_kind = ticket_kind
            category.guest_list_mode = guest_mode
            if ticket_kind == 'GUEST_LIST':
                session_db.commit()
                flash('Categoría configurada como listado de invitados.', 'success')
                return redirect(url_for('invitation_event_detail', concert_id=concert_id) + '#inv-tab-tickets')
        else:
            # Subida "sin clasificar": entra sin categoría y luego se mueve a una concreta.
            ticket_kind, _gm = _invitation_parse_ticket_kind_and_guest_mode(request.form.get('ticket_kind'), 'PDF_UNNUMBERED', None)
            if ticket_kind == 'GUEST_LIST':
                ticket_kind = 'PDF_UNNUMBERED'
        is_numbered = ticket_kind == 'PDF_NUMBERED' or _truthy(request.form.get('is_numbered'))
        files = request.files.getlist('tickets[]') or request.files.getlist('files[]')
        if not files:
            raise ValueError('No se han seleccionado PDFs.')
        errors = []
        duplicates = []      # entradas que no se suben por estar ya repetidas
        created = 0
        seen_codes = set()   # códigos ya usados en este lote (para garantizar unicidad)
        seen_shas = set()    # páginas idénticas ya vistas en este lote
        seen_butacas = set() # butacas (sector+fila+asiento) ya vistas en este lote (numeradas)
        folder = f'invitaciones/{concert.id}/{category.id if category else "sin-categoria"}'

        def _code_taken(value):
            if value in seen_codes:
                return True
            return session_db.query(InvitationTicket.id).filter(
                InvitationTicket.concert_id == concert.id, InvitationTicket.ticket_code == value).first() is not None
        for idx, file in enumerate(files):
            if not file or not getattr(file, 'filename', ''):
                continue
            fname = (file.filename or f'invitacion_{idx+1}.pdf').strip()
            if not fname.lower().endswith('.pdf'):
                errors.append(f'{fname}: solo se admiten PDFs')
                continue
            raw = file.read()
            try:
                file.stream.seek(0)
            except Exception:
                pass
            stem = Path(fname).stem or f'invitacion_{idx+1}'
            # Un PDF puede traer varias entradas: lo dividimos en una entrada por página.
            page_blobs = _invitation_split_pdf_pages(raw)
            multi = len(page_blobs) > 1
            form_code_single = (request.form.get(f'ticket_code_{idx}') or '').strip()
            for pidx, page_bytes in enumerate(page_blobs):
                page_sha = hashlib.sha256(page_bytes).hexdigest()
                page_label = f'{stem} (pág. {pidx + 1})' if multi else stem
                # Duplicado real = misma página (SHA): se salta e informa; el resto del lote sí se sube.
                if page_sha in seen_shas or session_db.query(InvitationTicket.id).filter(
                        InvitationTicket.concert_id == concert.id, InvitationTicket.pdf_sha256 == page_sha).first():
                    duplicates.append(page_label)
                    continue
                meta = _invitation_extract_ticket_metadata(page_bytes, f'{stem}-p{pidx + 1}.pdf')
                reliable_code = bool(meta.get('code_reliable'))
                if not multi and form_code_single:
                    code = form_code_single
                    reliable_code = True
                else:
                    code = (meta.get('ticket_code') or f'{stem}-p{pidx + 1}').strip()
                code = (code or page_sha[:16])[:120]
                # Solo se deduplica por CÓDIGO si es fiable (etiquetado en el PDF o escrito a mano);
                # si no, se garantiza un código único (sufijo) para no perder PDFs distintos.
                if _code_taken(code):
                    if reliable_code:
                        duplicates.append(f'{page_label} · {code}')
                        continue
                    base = code[:110]
                    suffix = 2
                    while _code_taken(code) and suffix < 9999:
                        code = f'{base}-{suffix}'
                        suffix += 1
                try:
                    url = upload_pdf_bytes(page_bytes, folder)
                except Exception as up_exc:
                    errors.append(f'{page_label}: no se pudo subir ({up_exc})')
                    continue
                seen_codes.add(code)
                seen_shas.add(page_sha)
                meta_sector = meta.get('sector') if is_numbered else None
                meta_row = meta.get('row_label') if is_numbered else None
                meta_seat = meta.get('seat_number') if is_numbered else None
                if multi:
                    sector_val = (request.form.get('sector') or meta_sector or '').strip() or None
                    row_val = (request.form.get('row_label') or meta_row or '').strip() or None
                    seat_val = (meta_seat or '').strip() or None
                else:
                    sector_val = (request.form.get(f'sector_{idx}') or request.form.get('sector') or meta_sector or '').strip() or None
                    row_val = (request.form.get(f'row_{idx}') or request.form.get('row_label') or meta_row or '').strip() or None
                    seat_val = (request.form.get(f'seat_{idx}') or meta_seat or '').strip() or None
                # Si en una subida NUMERADA una entrada no trae sector/fila/asiento (se coló una sin
                # numerar), se separa en un sector propio "Sin numerar" para no mezclarla con las numeradas.
                if is_numbered and not sector_val and not row_val and not seat_val:
                    sector_val = 'Sin numerar'
                # Antiduplicados por BUTACA: no subir dos veces la misma localidad (sector+fila+asiento)
                # en el mismo concierto, aunque el PDF sea distinto (complementa la deduplicación por SHA).
                if is_numbered and seat_val and sector_val and sector_val != 'Sin numerar':
                    _bk = (str(sector_val).strip().lower(), str(row_val or '').strip().lower(), str(seat_val).strip().lower())
                    if _bk in seen_butacas or session_db.query(InvitationTicket.id).filter(
                            InvitationTicket.concert_id == concert.id,
                            func.lower(func.coalesce(InvitationTicket.sector, '')) == _bk[0],
                            func.lower(func.coalesce(InvitationTicket.row_label, '')) == _bk[1],
                            func.lower(func.coalesce(InvitationTicket.seat_number, '')) == _bk[2]).first():
                        duplicates.append(f'{page_label} · {sector_val} F{row_val or "-"} A{seat_val}')
                        continue
                    seen_butacas.add(_bk)
                ticket = InvitationTicket(
                    concert_id=concert.id,
                    category_id=(category.id if category else None),
                    ticket_code=code,
                    pdf_url=url,
                    pdf_name=(f'{stem}.pdf' if multi else fname),
                    pdf_sha256=page_sha,
                    is_numbered=is_numbered,
                    sector=sector_val,
                    row_label=row_val,
                    seat_number=seat_val,
                    uploaded_by_user_id=_safe_uuid(session.get('user_id')),
                    uploaded_by_nick=_current_user_email(),
                )
                session_db.add(ticket)
                created += 1
        if category is not None:
            category.updated_at = _now_madrid()
        session_db.commit()
        if created:
            flash(f'{created} invitaciones subidas.', 'success')
        if duplicates:
            extra = f' (+{len(duplicates) - 8} más)' if len(duplicates) > 8 else ''
            flash(f'⚠️ {len(duplicates)} invitación(es) duplicada(s): solo se mantiene una de cada. No subidas: ' + ' · '.join(duplicates[:8]) + extra, 'warning')
        if errors:
            flash('Algunas invitaciones no se pudieron subir: ' + ' · '.join(errors[:8]), 'warning')
    except Exception as exc:
        session_db.rollback()
        flash(f'No se pudieron subir las invitaciones: {exc}', 'danger')
    finally:
        session_db.close()
    return redirect(url_for('invitation_event_detail', concert_id=concert_id) + '#inv-tab-tickets')


@app.post('/invitaciones/tickets/<ticket_id>/liberar', endpoint='invitation_ticket_release')
@admin_required
def invitation_ticket_release(ticket_id):
    _ajax = _truthy(request.form.get('ajax'))
    session_db = db()
    try:
        ticket = session_db.get(InvitationTicket, to_uuid(ticket_id))
        if not ticket:
            abort(404)
        _ensure_can_manage_invitations(session_db, ticket.concert)
        cid = ticket.concert_id
        if ticket.assigned_label:
            ticket.previous_assignment_warning = f"Ya había sido asignada a {ticket.assigned_label}."
        ticket.status = 'AVAILABLE'
        ticket.assigned_request_id = None
        ticket.assigned_commitment_id = None
        ticket.assigned_label = None
        session_db.commit()
        if _ajax:
            return jsonify({'ok': True, 'ticket_id': str(ticket.id)})
        flash('Entrada liberada.', 'success')
        return redirect(url_for('invitation_event_detail', concert_id=cid) + '#inv-tab-tickets')
    except Exception as exc:
        session_db.rollback()
        if _ajax:
            return jsonify({'ok': False, 'error': str(exc)}), 400
        flash(f'No se pudo liberar la entrada: {exc}', 'danger')
        return redirect(url_for('invitations_view', tab='gestionar'))
    finally:
        session_db.close()


