def _home_registros_pending(limit: int = 20) -> list[dict]:
    """Canciones con entregas de masters pendientes de validar (materiales PENDING o datos sin consolidar)."""
    session_db = db()
    try:
        pending_ids = set()
        for (sid,) in (
            session_db.query(SongMaterial.song_id)
            .filter(func.upper(func.coalesce(SongMaterial.validation_status, "VALIDATED")) == "PENDING")
            .distinct().all()
        ):
            if sid:
                pending_ids.add(sid)
        for link in session_db.query(SongMasterDeliveryLink).filter(SongMasterDeliveryLink.status == "SUBMITTED").all():
            d = link.data or {}
            if d.get("production") or d.get("authoral") or (d.get("lyrics") or "").strip():
                pending_ids.add(link.song_id)
        if not pending_ids:
            return []
        songs = (
            session_db.query(Song)
            .options(joinedload(Song.artists))
            .filter(Song.id.in_(list(pending_ids)))
            .limit(limit).all()
        )
        rows = []
        for s in songs:
            mat_pending = (
                session_db.query(func.count(SongMaterial.id))
                .filter(SongMaterial.song_id == s.id)
                .filter(func.upper(func.coalesce(SongMaterial.validation_status, "VALIDATED")) == "PENDING")
                .scalar()
            ) or 0
            rows.append({
                "id": str(s.id),
                "title": s.title,
                "artist_names": ", ".join([a.name for a in (s.artists or []) if getattr(a, "name", None)]) or "—",
                "cover_url": (s.cover_url or "").strip(),
                "materials_pending": int(mat_pending),
                "detail_url": url_for("discografica_song_detail", song_id=s.id, tab="materiales"),
            })
        return rows
    except Exception:
        return []
    finally:
        session_db.close()


def _home_invitations_to_manage(limit: int = 24) -> list[dict]:
    """Conciertos/actividades futuros que el usuario actual puede GESTIONAR y que tienen
    solicitudes de invitaciones. Alimenta el módulo del inicio 'Invitaciones pendientes de
    gestionar': tarjeta con artista(s)+foto, datos del evento y nº de solicitudes pendientes.
    Si todo está enviado o en taquilla, se marca como 'ya gestionadas' (etiqueta verde)."""
    state = _current_user_state()
    if int(state.get("role") or 0) != 10 and not _state_has_access(state, "invitaciones.gestionar", include_descendants=True):
        return []
    session_db = db()
    try:
        query_start = _invitation_event_query_start_date()
        now_value = _now_madrid()
        concerts = (
            session_db.query(Concert)
            .options(joinedload(Concert.artist), joinedload(Concert.venue))
            .filter(or_(Concert.date == None, Concert.date >= query_start))  # noqa: E711
            .order_by(Concert.date.asc().nullslast(), Concert.created_at.desc())
            .limit(300)
            .all()
        )
        active = [c for c in concerts if _invitation_event_is_active_for_requests(c, now_value=now_value)]
        manageable = _filter_manageable_concerts(session_db, active, state=state)
        if not manageable:
            return []
        ids = [c.id for c in manageable]
        pending_statuses = {"SOLICITADAS", "APROBADAS", "ASIGNADAS"}
        handled_statuses = {"ENVIADAS", "ENTREGADAS_MANO", "DISPONIBLES_TAQUILLA", "RECOGIDAS_TAQUILLA"}
        pending_by_concert: dict[str, int] = {}
        handled_by_concert: dict[str, int] = {}
        for cid, status, cnt in (
            session_db.query(InvitationRequest.concert_id, InvitationRequest.status, func.count(InvitationRequest.id))
            .filter(InvitationRequest.concert_id.in_(ids))
            .group_by(InvitationRequest.concert_id, InvitationRequest.status)
            .all()
        ):
            key = str(cid)
            st = (status or "").upper()
            if st in pending_statuses:
                pending_by_concert[key] = pending_by_concert.get(key, 0) + int(cnt or 0)
            elif st in handled_statuses:
                handled_by_concert[key] = handled_by_concert.get(key, 0) + int(cnt or 0)
        # Compromisos configurados: el evento también está "pendiente de gestionar" mientras tenga
        # compromisos sin entregar (o, si son de listado, sin marcar como asignados). Cuenta cada
        # compromiso como 1 unidad pendiente/gestionada, igual que cada petición.
        commitments = session_db.query(InvitationCommitment).filter(InvitationCommitment.concert_id.in_(ids)).all()
        commit_ids = [c.id for c in commitments]
        ticket_by_commit: dict[str, tuple[int, int]] = {}
        if commit_ids:
            delivered_set = {"SENT", "DELIVERED", "PICKED_UP", "DISPONIBLES_TAQUILLA", "RECOGIDAS_TAQUILLA"}
            for ccid, tstatus, cnt in (
                session_db.query(InvitationTicket.assigned_commitment_id, InvitationTicket.status, func.count(InvitationTicket.id))
                .filter(InvitationTicket.assigned_commitment_id.in_(commit_ids))
                .group_by(InvitationTicket.assigned_commitment_id, InvitationTicket.status)
                .all()
            ):
                a, d = ticket_by_commit.get(str(ccid), (0, 0))
                a += int(cnt or 0)
                if (tstatus or "").upper() in delivered_set:
                    d += int(cnt or 0)
                ticket_by_commit[str(ccid)] = (a, d)
        for c in commitments:
            committed_qty = sum(_safe_int(v) for v in _json_dict(c.quantities_json).values())
            if committed_qty <= 0:
                continue
            assigned_count, delivered_count = ticket_by_commit.get(str(c.id), (0, 0))
            # Gestionado si está todo entregado (PDF) o si es de listado marcado como asignado (sin PDFs).
            handled = (delivered_count >= committed_qty) or ((c.status or "").upper() == "ASIGNADAS" and assigned_count == 0)
            key = str(c.concert_id)
            if handled:
                handled_by_concert[key] = handled_by_concert.get(key, 0) + 1
            else:
                pending_by_concert[key] = pending_by_concert.get(key, 0) + 1
        rows = []
        for c in manageable:
            key = str(c.id)
            pending = pending_by_concert.get(key, 0)
            handled = handled_by_concert.get(key, 0)
            if pending == 0 and handled == 0:
                continue  # sin solicitudes reales que gestionar (ignora rechazadas/anuladas)
            payload = _invitation_event_payload(session_db, c)
            payload["pending_count"] = pending
            payload["managed"] = (pending == 0 and handled > 0)
            payload["detail_url"] = url_for("invitation_event_detail", concert_id=c.id, **{"from": "gestionar"})
            rows.append(payload)
            if len(rows) >= limit:
                break
        return rows
    except Exception:
        return []
    finally:
        session_db.close()


def _home_invitation_requests_for_current_user(limit: int = 12) -> list[dict]:
    uid = _safe_uuid(session.get('user_id'))
    if not uid:
        return []
    session_db = db()
    try:
        rows = (
            session_db.query(InvitationRequest)
            .options(joinedload(InvitationRequest.concert))
            .filter(InvitationRequest.requester_user_id == uid)
            .filter(InvitationRequest.status.notin_(['RECHAZADAS', 'ANULADAS']))
            .order_by(InvitationRequest.created_at.desc())
            .limit(max(limit * 3, 30))
            .all()
        )
        out = []
        for row in rows:
            if not _invitation_request_visible_for_user(row):
                continue
            cats = _invitation_get_categories(session_db, row.concert, ensure_defaults=False) if row.concert else []
            item = _invitation_request_payload(row, cats)
            item['event'] = _invitation_event_payload(session_db, row.concert) if row.concert else {}
            out.append(item)
            if len(out) >= limit:
                break
        return out
    except Exception:
        return []
    finally:
        session_db.close()



