# ---------------------------------------------------------------------------
# Chartmetric — motor de refresco (Fase 1): resuelve el ID de Chartmetric de cada artista, trae
# métricas (oyentes/seguidores) y playlists y lo cachea en BD. Todo dormido si no hay token.
# ---------------------------------------------------------------------------
def _chartmetric_extract_spotify_artist_id(artist) -> str | None:
    """Busca un id de artista de Spotify en social_links (open.spotify.com/artist/<id>)."""
    links = getattr(artist, "social_links", None) or {}
    if isinstance(links, dict):
        values = list(links.values())
    elif isinstance(links, (list, tuple)):
        values = list(links)
    else:
        values = []
    for v in values:
        if isinstance(v, str):
            m = re.search(r"open\.spotify\.com/artist/([A-Za-z0-9]+)", v)
            if m:
                return m.group(1)
    return None


def _chartmetric_pick_cmid(payload):
    """Extrae el Chartmetric ID de la respuesta de get-ids (defensivo; CONFIRMAR forma exacta)."""
    if isinstance(payload, list) and payload:
        return _chartmetric_pick_cmid(payload[0])
    if isinstance(payload, dict):
        for key in ("chartmetric", "cm_artist", "chartmetric_id", "id"):
            v = payload.get(key)
            if isinstance(v, list) and v:
                v = v[0]
            if isinstance(v, dict):
                v = v.get("id") or v.get("cm_artist")
            if v:
                return v
    return None


def _chartmetric_norm_name(s: str) -> str:
    """Normaliza un nombre para comparar: minúsculas, sin acentos, sin espacios extra."""
    s = unicodedata.normalize("NFKD", s or "")
    s = "".join(c for c in s if not unicodedata.combining(c))
    return " ".join(s.lower().split())


def _chartmetric_norm_isrc(s) -> str:
    """Normaliza un ISRC para comparar: solo alfanumérico, en mayúsculas (ignora guiones/espacios)."""
    return "".join(ch for ch in (s or "") if ch.isalnum()).upper()


def _chartmetric_search_best(name: str):
    """Mejor artista en Chartmetric por nombre: coincidencia EXACTA normalizada, el de mayor score.
    Devuelve el dict {id, name, image_url, sp_monthly_listeners...} o None (así no vinculamos un
    artista equivocado en nombres ambiguos)."""
    import chartmetric_utils as cm
    if not (name or "").strip():
        return None
    try:
        results = cm.search_artists(name, limit=10) or []
    except Exception:
        return None
    target = _chartmetric_norm_name(name)
    matches = [
        a for a in results
        if isinstance(a, dict) and a.get("id") and _chartmetric_norm_name(a.get("name", "")) == target
    ]
    if not matches:
        return None
    matches.sort(key=lambda a: (a.get("cm_artist_score") or 0), reverse=True)
    return matches[0]


def _chartmetric_fetch_artist_meta(cmid):
    """Nombre e imagen del artista en Chartmetric por CMID (para validar un ID puesto a mano)."""
    import chartmetric_utils as cm
    try:
        data = cm.get_artist(cmid)
        a = data.get("obj", data) if isinstance(data, dict) else data
        if isinstance(a, dict):
            return (a.get("name"), a.get("image_url") or a.get("cover_url"))
    except Exception:
        pass
    return (None, None)


def _chartmetric_resolve_cmid(session_db, artist) -> str | None:
    """Resuelve y persiste el Chartmetric ID del artista (no toca lo ya vinculado)."""
    import chartmetric_utils as cm
    link = session_db.get(ChartmetricArtist, artist.id)
    if link and link.chartmetric_id:
        return link.chartmetric_id
    if not link:
        link = ChartmetricArtist(artist_id=artist.id)
        session_db.add(link)
    try:
        cmid = cm_name = cm_img = source = None
        spotify_id = _chartmetric_extract_spotify_artist_id(artist)
        if spotify_id:
            data = cm.get_chartmetric_id_from_spotify(spotify_id)
            payload = data.get("obj", data) if isinstance(data, dict) else data
            cmid = _chartmetric_pick_cmid(payload)
            if cmid:
                source = "spotify"
                first = payload[0] if isinstance(payload, list) and payload else (payload if isinstance(payload, dict) else {})
                cm_name = first.get("artist_name") if isinstance(first, dict) else None
        if not cmid:
            hit = _chartmetric_search_best(artist.name)
            if hit:
                cmid, cm_name, cm_img, source = hit.get("id"), hit.get("name"), hit.get("image_url"), "name"
        if cmid:
            link.chartmetric_id = str(cmid)
            link.chartmetric_name = cm_name
            link.chartmetric_image_url = cm_img
            link.match_source = source
            link.status = "LINKED"
            link.last_error = None
        else:
            link.status = "NOT_FOUND"
            link.last_error = "No se encontró en Chartmetric (ni por Spotify ni por nombre exacto)."
    except Exception as e:
        link.status = "ERROR"
        link.last_error = str(e)[:500]
    link.updated_at = _now_madrid()
    return link.chartmetric_id


def _chartmetric_review_rows(session_db):
    """Una fila por artista con el ID de Chartmetric elegido (para revisión y corrección manual)."""
    rows = (
        session_db.query(Artist, ChartmetricArtist)
        .outerjoin(ChartmetricArtist, ChartmetricArtist.artist_id == Artist.id)
        .order_by(Artist.name.asc())
        .all()
    )
    out = []
    for art, link in rows:
        out.append({
            "artist_id": str(art.id),
            "artist_name": art.name,
            "artist_photo": art.photo_url,
            "cmid": (link.chartmetric_id if link else None),
            "cm_name": (getattr(link, "chartmetric_name", None) if link else None),
            "cm_image": (getattr(link, "chartmetric_image_url", None) if link else None),
            "source": (getattr(link, "match_source", None) if link else None),
            "status": (link.status if link else None),
        })
    return out


def _chartmetric_clear_artist_cache(session_db, artist_id):
    """Borra métricas y playlists cacheadas de un artista (al corregir/desvincular su ID)."""
    session_db.query(ChartmetricMetricPoint).filter_by(artist_id=artist_id).delete()
    session_db.query(ChartmetricPlaylistEntry).filter_by(artist_id=artist_id).delete()


def _chartmetric_upsert_metric_points(session_db, artist_id, source, field, series, keep_days=120):
    for pt in (series or [])[-keep_days:]:
        if not isinstance(pt, dict):
            continue
        ts = (pt.get("timestp") or "")[:10]
        if not ts:
            continue
        try:
            d = date.fromisoformat(ts)
        except (ValueError, TypeError):
            continue
        existing = (
            session_db.query(ChartmetricMetricPoint)
            .filter_by(artist_id=artist_id, source=source, field=field, date=d)
            .first()
        )
        if existing:
            existing.value = pt.get("value")
            existing.fetched_at = _now_madrid()
        else:
            session_db.add(ChartmetricMetricPoint(
                artist_id=artist_id, source=source, field=field, date=d, value=pt.get("value"),
            ))


def _chartmetric_replace_current_playlists(session_db, artist_id, platform, items, track_map=None, song_by_isrc=None, song_by_title=None, status="current"):
    """Reemplaza las playlists del artista en esa plataforma y estado (current/past) con el snapshot.

    track_map: cm_track -> {name, isrc}. Las playlists de Apple/Amazon NO traen el nombre de la
    canción, así que lo sacamos de aquí; y casamos con nuestra Song por ISRC (normalizado) o, si no
    cuadra, por título normalizado, para enlazar la ficha de la canción.
    """
    track_map = track_map or {}
    song_by_isrc = song_by_isrc or {}
    song_by_title = song_by_title or {}
    session_db.query(ChartmetricPlaylistEntry).filter_by(
        artist_id=artist_id, platform=platform, status=status
    ).delete()
    seen = set()
    official_owners = {"spotify", "apple music", "apple", "applemusic", "amazon", "amazon music"}
    for it in (items or []):
        pl = it.get("playlist", it) if isinstance(it, dict) else None
        if not isinstance(pl, dict):
            continue
        playlist_id = str(pl.get("playlist_id") or pl.get("id") or "").strip()
        cm_track = str(pl.get("cm_track") or pl.get("track_id") or "").strip()
        if not playlist_id:
            continue
        key = (playlist_id, cm_track)
        if key in seen:
            continue
        seen.add(key)
        owner = pl.get("owner_name") or pl.get("curator_name")
        is_official = bool(pl.get("editorial")) or (str(owner or "").strip().lower() in official_owners)
        added_d = None
        added = (pl.get("added_at") or "")[:10]
        if added:
            try:
                added_d = date.fromisoformat(added)
            except (ValueError, TypeError):
                added_d = None
        track_name = pl.get("track")
        info = track_map.get(cm_track) or {}
        if not track_name:
            track_name = info.get("name")
        song_id = None
        isrc = info.get("isrc")
        if isrc:
            song_id = song_by_isrc.get(_chartmetric_norm_isrc(isrc))
        if not song_id and track_name:
            song_id = song_by_title.get(_chartmetric_norm_name(track_name))
        session_db.add(ChartmetricPlaylistEntry(
            artist_id=artist_id, platform=platform, status=status,
            cm_track=cm_track or None, track_name=track_name, song_id=song_id,
            playlist_id=playlist_id, playlist_name=pl.get("name"),
            owner_name=owner, is_official=is_official,
            position=pl.get("position"), peak_position=pl.get("peak_position"),
            days_in_list=pl.get("period"), added_at=added_d,
            followers=pl.get("followers"), image_url=pl.get("image_url") or pl.get("playlist_image_url"),
        ))


def _chartmetric_refresh_artist(session_db, artist) -> dict:
    """Refresca métricas + playlists de un artista. Dormant si no configurado. No lanza."""
    import chartmetric_utils as cm
    if not cm.chartmetric_configured():
        return {"ok": False, "message": "Chartmetric no configurado."}
    cmid = _chartmetric_resolve_cmid(session_db, artist)
    if not cmid:
        session_db.commit()
        return {"ok": False, "message": "Sin Chartmetric ID (no se pudo vincular el artista)."}
    link = session_db.get(ChartmetricArtist, artist.id)
    errors = []
    for source, fields in (("spotify", ["listeners", "followers"]), ("instagram", ["followers"]), ("tiktok", ["followers"])):
        try:
            data = cm.get_artist_stat(cmid, source)
            payload = data.get("obj", data) if isinstance(data, dict) else data
            for field in fields:
                _chartmetric_upsert_metric_points(session_db, artist.id, source, field, (payload or {}).get(field))
        except Exception as e:
            errors.append(f"stat:{source}:{str(e)[:80]}")
    # Mapa de tracks (cm_track -> nombre + ISRC) para nombrar canciones en TODAS las plataformas
    # (Apple/Amazon no lo traen) y enlazarlas con nuestra ficha por ISRC.
    track_map = {}
    try:
        for t in (cm.get_artist_tracks(cmid) or []):
            if isinstance(t, dict):
                cmt = str(t.get("cm_track") or t.get("id") or "").strip()
                if cmt:
                    track_map[cmt] = {"name": t.get("name"), "isrc": t.get("isrc")}
    except Exception as e:
        errors.append(f"tracks:{str(e)[:80]}")
    # Casar las canciones de las playlists con NUESTRAS Song: por ISRC (normalizado) y, de respaldo,
    # por título normalizado. Usamos las canciones del propio artista (más fiable que buscar por ISRC
    # global, y permite el respaldo por título cuando el ISRC no coincide o falta).
    song_by_isrc = {}
    song_by_title = {}
    try:
        for sg in (getattr(artist, "songs", None) or []):
            if getattr(sg, "isrc", None):
                song_by_isrc[_chartmetric_norm_isrc(sg.isrc)] = sg.id
            if getattr(sg, "title", None):
                song_by_title[_chartmetric_norm_name(sg.title)] = sg.id
    except Exception:
        pass
    for platform in ("spotify", "applemusic", "amazon"):
        for st in ("current", "past"):
            try:
                items = cm.get_artist_playlists(cmid, platform=platform, status=st)
                # Enriquecer el mapa de nombres con lo que traen los propios items (Spotify SÍ incluye
                # el nombre de la canción). Como Spotify se procesa primero, así Apple/Amazon pueden
                # nombrar la canción aunque el endpoint de tracks no la cubra o se quede sin créditos.
                for it in (items or []):
                    pl = it.get("playlist", it) if isinstance(it, dict) else None
                    if isinstance(pl, dict):
                        cmt = str(pl.get("cm_track") or pl.get("track_id") or "").strip()
                        nm = pl.get("track")
                        if cmt and nm and not (track_map.get(cmt) or {}).get("name"):
                            track_map.setdefault(cmt, {})["name"] = nm
                _chartmetric_replace_current_playlists(session_db, artist.id, platform, items, track_map, song_by_isrc, song_by_title, status=st)
            except Exception as e:
                errors.append(f"pl:{platform}:{st}:{str(e)[:80]}")
    link.last_refreshed_at = _now_madrid()
    link.last_error = "; ".join(errors)[:500] if errors else None
    link.status = "LINKED" if not errors else "ERROR"
    session_db.commit()
    return {"ok": not errors, "message": "Actualizado." if not errors else "; ".join(errors)[:200]}


def _social_url_for(artist, *needles):
    """Primera URL de social_links que contenga alguno de los 'needles' (dominio). None si no hay."""
    links = getattr(artist, "social_links", None) or {}
    if isinstance(links, dict):
        values = list(links.values())
    elif isinstance(links, (list, tuple)):
        values = list(links)
    else:
        values = []
    for v in values:
        if isinstance(v, str) and any(n in v.lower() for n in needles):
            return v
    return None


def _chartmetric_header_metrics(session_db, artist):
    """Métricas de cabecera (oyentes Spotify, seguidores IG/TikTok) con variación mensual.

    Lee SOLO de la caché (chartmetric_metric_point); devuelve [] si no hay datos (no llama a la API).
    Defensivo: ante cualquier error devuelve [] para no romper la ficha del artista.
    """
    plan = [
        ("spotify", "listeners", "Oyentes Spotify", "fa-brands fa-spotify", ("open.spotify.com", "spotify.com")),
        ("instagram", "followers", "Seguidores Instagram", "fa-brands fa-instagram", ("instagram.com",)),
        ("tiktok", "followers", "Seguidores TikTok", "fa-brands fa-tiktok", ("tiktok.com",)),
    ]
    out = []
    try:
        for source, field, label, icon, needles in plan:
            rows = (
                session_db.query(ChartmetricMetricPoint)
                .filter_by(artist_id=artist.id, source=source, field=field)
                .order_by(ChartmetricMetricPoint.date.desc())
                .limit(45)
                .all()
            )
            rows = [r for r in rows if r.value is not None]
            if not rows:
                continue
            cur = float(rows[0].value)
            target = rows[0].date - timedelta(days=30)
            prev = next((r for r in rows if r.date <= target), None)
            delta = (cur - float(prev.value)) if prev is not None else None
            out.append({
                "label": label,
                "icon": icon,
                "value_fmt": f"{int(cur):,}".replace(",", "."),
                "up": delta is not None and delta > 0,
                "down": delta is not None and delta < 0,
                "url": _social_url_for(artist, *needles),
            })
    except Exception:
        return []
    return out


@app.route("/integraciones", methods=["GET", "POST"], endpoint="integrations_view")
@admin_required
def integrations_view():
    # Solo dirección: gestiona credenciales sensibles de servicios externos.
    if not is_master():
        return forbid("Solo dirección puede acceder a las integraciones.")
    # Import perezoso: si por lo que sea un módulo de integración fallara, no afecta al arranque.
    import pleo_utils
    import chartmetric_utils
    if request.method == "POST":
        action = (request.form.get("action") or "").strip()
        if action == "ping_pleo":
            ok, msg = pleo_utils.pleo_ping()
            flash(f"Pleo: {msg}", "success" if ok else "danger")
        elif action == "ping_chartmetric":
            ok, msg = chartmetric_utils.chartmetric_ping()
            flash(f"Chartmetric: {msg}", "success" if ok else "danger")
        elif action == "refresh_chartmetric_test":
            s = db()
            try:
                results = []
                for a in s.query(Artist).order_by(Artist.created_at.desc()).limit(3).all():
                    r = _chartmetric_refresh_artist(s, a)
                    results.append(f"{a.name}: {r['message']}")
                flash("Prueba Chartmetric · " + (" | ".join(results) or "no hay artistas"), "info")
            except Exception as e:
                try:
                    s.rollback()
                except Exception:
                    pass
                flash(f"Error en la prueba de Chartmetric: {e}", "danger")
            finally:
                s.close()
        elif action == "resolve_all_chartmetric":
            s = db()
            try:
                linked = nf = 0
                for a in s.query(Artist).order_by(Artist.name.asc()).all():
                    existing = s.get(ChartmetricArtist, a.id)
                    if existing and existing.chartmetric_id:
                        continue  # ya vinculado (no re-resolver: no gastar ni pisar lo manual)
                    if _chartmetric_resolve_cmid(s, a):
                        linked += 1
                    else:
                        nf += 1
                s.commit()
                flash(f"Vinculación automática: {linked} vinculados, {nf} sin encontrar. Revisa la tabla y corrige a mano lo que haga falta.", "info")
            except Exception as e:
                try:
                    s.rollback()
                except Exception:
                    pass
                flash(f"Error al vincular: {e}", "danger")
            finally:
                s.close()
        elif action == "link_chartmetric":
            aid = (request.form.get("artist_id") or "").strip()
            new_cmid = (request.form.get("chartmetric_id") or "").strip()
            s = db()
            try:
                art = s.get(Artist, to_uuid(aid)) if aid else None
                if not art:
                    flash("Artista no encontrado.", "warning")
                elif not new_cmid.isdigit():
                    flash("El ID de Chartmetric debe ser numérico.", "warning")
                else:
                    name, image = _chartmetric_fetch_artist_meta(new_cmid)
                    link = s.get(ChartmetricArtist, art.id)
                    if not link:
                        link = ChartmetricArtist(artist_id=art.id)
                        s.add(link)
                    link.chartmetric_id = new_cmid
                    link.chartmetric_name = name
                    link.chartmetric_image_url = image
                    link.match_source = "manual"
                    link.status = "LINKED"
                    link.last_error = None
                    link.updated_at = _now_madrid()
                    _chartmetric_clear_artist_cache(s, art.id)  # fuera datos viejos; se recogen al refrescar
                    s.commit()
                    flash(f"{art.name} → Chartmetric ID {new_cmid}" + (f" ({name})" if name else "") + ". Datos antiguos limpiados.", "success")
            except Exception as e:
                try:
                    s.rollback()
                except Exception:
                    pass
                flash(f"Error al vincular: {e}", "danger")
            finally:
                s.close()
        elif action == "unlink_chartmetric":
            aid = (request.form.get("artist_id") or "").strip()
            s = db()
            try:
                art = s.get(Artist, to_uuid(aid)) if aid else None
                if art:
                    link = s.get(ChartmetricArtist, art.id)
                    if link:
                        s.delete(link)
                    _chartmetric_clear_artist_cache(s, art.id)
                    s.commit()
                    flash(f"{art.name} desvinculado y datos limpiados.", "info")
            except Exception as e:
                try:
                    s.rollback()
                except Exception:
                    pass
                flash(f"Error al desvincular: {e}", "danger")
            finally:
                s.close()
        elif action == "refresh_all_chartmetric":
            s = db()
            try:
                n = s.query(ChartmetricArtist).filter(ChartmetricArtist.chartmetric_id.isnot(None)).count()
            finally:
                s.close()
            threading.Thread(target=_chartmetric_refresh_all_bg, daemon=True).start()
            flash(f"Refresco de {n} artista(s) en marcha en segundo plano. Vuelve en unos minutos y recarga la página.", "info")
        return redirect(url_for("integrations_view"))
    # Resumen de la caché + tabla de revisión (artista -> ID de Chartmetric elegido).
    cm_linked = cm_points = cm_playlists = 0
    review_rows = []
    cm_last_refresh = None
    cm_credit_warning = False
    if chartmetric_utils.chartmetric_configured():
        s = db()
        try:
            cm_linked = s.query(ChartmetricArtist).filter(ChartmetricArtist.chartmetric_id.isnot(None)).count()
            cm_points = s.query(ChartmetricMetricPoint).count()
            cm_playlists = s.query(ChartmetricPlaylistEntry).filter_by(status="current").count()
            review_rows = _chartmetric_review_rows(s)
            cm_last_refresh = s.query(func.max(ChartmetricArtist.last_refreshed_at)).scalar()
            cm_credit_warning = bool(
                s.query(ChartmetricArtist.artist_id)
                .filter(
                    ChartmetricArtist.last_error.ilike("%crédit%")
                    | ChartmetricArtist.last_error.ilike("%credit%")
                    | ChartmetricArtist.last_error.ilike("%402%")
                )
                .first()
            )
        except Exception:
            pass
        finally:
            s.close()
    return render_template(
        "integraciones.html",
        title="Integraciones",
        pleo_configured=pleo_utils.pleo_configured(),
        chartmetric_configured=chartmetric_utils.chartmetric_configured(),
        cm_linked=cm_linked,
        cm_points=cm_points,
        cm_playlists=cm_playlists,
        review_rows=review_rows,
        cm_last_refresh=cm_last_refresh,
        cm_credit_warning=cm_credit_warning,
    )


def _chartmetric_refresh_all_bg():
    """Refresca métricas + playlists de TODOS los artistas vinculados (en segundo plano)."""
    s = db()
    try:
        arts = (
            s.query(Artist)
            .join(ChartmetricArtist, ChartmetricArtist.artist_id == Artist.id)
            .filter(ChartmetricArtist.chartmetric_id.isnot(None))
            .all()
        )
        for a in arts:
            try:
                _chartmetric_refresh_artist(s, a)
            except Exception:
                try:
                    s.rollback()
                except Exception:
                    pass
    except Exception:
        pass
    finally:
        s.close()


_chartmetric_daily_check_date = None


def _chartmetric_maybe_daily_refresh():
    """Refresco diario automático SIN configurar nada: una vez al día, el primer proceso que entra lo
    reclama de forma atómica en BD (chartmetric_meta) y lanza el refresco de todos en segundo plano.
    Se llama desde home(); barato (throttle en memoria por worker). No lanza."""
    global _chartmetric_daily_check_date
    try:
        import chartmetric_utils as cm
        if not cm.chartmetric_configured():
            return
        today = _now_madrid().date()
        if _chartmetric_daily_check_date == today:
            return  # este worker ya lo comprobó hoy (evita consultar la BD en cada visita)
        _chartmetric_daily_check_date = today
        claimed = False
        s = db()
        try:
            res = s.execute(text(
                "UPDATE chartmetric_meta SET last_auto_refresh = CURRENT_DATE "
                "WHERE id = 1 AND (last_auto_refresh IS NULL OR last_auto_refresh < CURRENT_DATE)"
            ))
            s.commit()
            claimed = (res.rowcount or 0) > 0
        except Exception:
            try:
                s.rollback()
            except Exception:
                pass
        finally:
            s.close()
        if claimed:
            threading.Thread(target=_chartmetric_refresh_all_bg, daemon=True).start()
    except Exception:
        pass


def _chartmetric_playlists_grouped(session_db, artist_id=None, cm_track=None, song_id=None, status="current", only_official=True):
    """Playlists agrupadas por plataforma (Spotify/Apple/Amazon), ordenadas por oyentes desc.
    Marca is_new si la canción entró en la lista en los últimos 7 días."""
    q = session_db.query(ChartmetricPlaylistEntry).filter(ChartmetricPlaylistEntry.status == status)
    if artist_id is not None:
        q = q.filter(ChartmetricPlaylistEntry.artist_id == artist_id)
    if song_id is not None:
        q = q.filter(ChartmetricPlaylistEntry.song_id == song_id)
    if cm_track:
        q = q.filter(ChartmetricPlaylistEntry.cm_track == str(cm_track))
    if only_official:
        q = q.filter(ChartmetricPlaylistEntry.is_official.is_(True))
    entries = q.all()
    # Portada principal y título de NUESTRAS canciones enlazadas (en bloque, sin N+1).
    song_ids = {e.song_id for e in entries if e.song_id}
    song_map = {}
    if song_ids:
        for sg in session_db.query(Song.id, Song.title, Song.cover_url).filter(Song.id.in_(song_ids)).all():
            song_map[sg.id] = {"title": sg.title, "cover_url": sg.cover_url}
    platform_logos = {"spotify": "spotify.png", "applemusic": "apple_music.png", "amazon": "amazon_music.png"}
    today = _now_madrid().date()
    groups = []
    for key, label in (("spotify", "Spotify"), ("applemusic", "Apple Music"), ("amazon", "Amazon Music")):
        items = [e for e in entries if e.platform == key]
        items.sort(key=lambda e: float(e.followers or 0), reverse=True)
        rows = []
        for e in items:
            sinfo = song_map.get(e.song_id) if e.song_id else None
            rows.append({
                "track_name": e.track_name,
                "song_id": (str(e.song_id) if e.song_id else None),
                "song_title": (sinfo or {}).get("title"),
                "song_cover": (sinfo or {}).get("cover_url"),
                "playlist_name": e.playlist_name,
                "position": e.position,
                "days": e.days_in_list,
                "added_at": e.added_at,
                "is_new": bool(e.added_at and (today - e.added_at).days <= 7),
                "followers": int(e.followers) if e.followers is not None else None,
                "image_url": e.image_url,
                "owner_name": e.owner_name,
            })
        if rows:
            groups.append({"key": key, "label": label, "logo": platform_logos.get(key), "count": len(rows), "rows": rows})
    return groups


def _chartmetric_playlist_counts(session_db, song_id):
    """Recuento de playlists oficiales por plataforma (actuales/anteriores/total) de una canción."""
    rows = (
        session_db.query(
            ChartmetricPlaylistEntry.platform,
            ChartmetricPlaylistEntry.status,
            func.count().label("n"),
        )
        .filter(ChartmetricPlaylistEntry.song_id == song_id)
        .filter(ChartmetricPlaylistEntry.is_official.is_(True))
        .group_by(ChartmetricPlaylistEntry.platform, ChartmetricPlaylistEntry.status)
        .all()
    )
    labels = {"spotify": "Spotify", "applemusic": "Apple Music", "amazon": "Amazon Music"}
    logos = {"spotify": "spotify.png", "applemusic": "apple_music.png", "amazon": "amazon_music.png"}
    by = {k: {"key": k, "label": v, "logo": logos.get(k), "current": 0, "past": 0, "total": 0} for k, v in labels.items()}
    for platform, status, n in rows:
        if platform not in by:
            continue
        if status == "past":
            by[platform]["past"] += int(n)
        else:
            by[platform]["current"] += int(n)
        by[platform]["total"] += int(n)
    out = [by[k] for k in ("spotify", "applemusic", "amazon") if by[k]["total"] > 0]
    totals = {
        "current": sum(x["current"] for x in out),
        "past": sum(x["past"] for x in out),
        "total": sum(x["total"] for x in out),
    }
    return {"platforms": out, "totals": totals}


def _chartmetric_playlisting_overview(session_db):
    """Sección Playlisting: artistas sincronizados con sus playlists oficiales ACTUALES, agrupadas.
    Marca has_past si el artista tiene además playlists anteriores (para el filtro 'con anteriores')."""
    arts = (
        session_db.query(Artist)
        .join(ChartmetricArtist, ChartmetricArtist.artist_id == Artist.id)
        .filter(ChartmetricArtist.chartmetric_id.isnot(None))
        .order_by(Artist.name.asc())
        .all()
    )
    past_ids = {
        r[0] for r in session_db.query(ChartmetricPlaylistEntry.artist_id)
        .filter(ChartmetricPlaylistEntry.status == "past")
        .filter(ChartmetricPlaylistEntry.is_official.is_(True))
        .distinct().all()
    }
    out = []
    for a in arts:
        groups = _chartmetric_playlists_grouped(session_db, artist_id=a.id)
        total = sum(g["count"] for g in groups)
        has_past = a.id in past_ids
        if total or has_past:
            out.append({
                "artist_id": str(a.id),
                "artist_name": a.name,
                "artist_photo": a.photo_url,
                "total": total,
                "has_past": has_past,
                "groups": groups,
            })
    return out


@app.get("/playlisting", endpoint="playlisting_view")
@admin_required
def playlisting_view():
    """Sección Playlisting: artistas y en qué playlists oficiales están sus canciones ahora mismo."""
    s = db()
    try:
        overview = _chartmetric_playlisting_overview(s)
    finally:
        s.close()
    return render_template("playlisting.html", title="Playlisting", overview=overview)


@app.get("/cron/chartmetric/refresh", endpoint="cron_chartmetric_refresh")
def cron_chartmetric_refresh():
    """Refresco diario automático de Chartmetric (lo llama una tarea programada de Render con ?key=).
    Protegido por CHARTMETRIC_CRON_KEY; no requiere sesión. Lanza el refresco en segundo plano."""
    expected = (os.getenv("CHARTMETRIC_CRON_KEY") or "").strip()
    key = (request.args.get("key") or "").strip()
    if not expected or key != expected:
        return ("forbidden", 403)
    import chartmetric_utils as cm
    if not cm.chartmetric_configured():
        return ("chartmetric no configurado", 200)
    threading.Thread(target=_chartmetric_refresh_all_bg, daemon=True).start()
    return ("refresco en marcha", 200)


